    69→          [
    70→            { text: t("cancel"), style: "cancel" },
    71→            { text: t("createNewSheet"), onPress: () => router.push("/create-sheet") },
    72→          ]
    73→        );
    74→      }
    75→    }, [activeSheet, state.expiredSheetPromptShownForSheetId, setState, router])
    76→  );
