    84→    return (activeSheet.incomeItems ?? []).reduce(
    85→      (a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts),
    86→      0
    87→    );
    88→  }, [activeSheet, base, rateCache, periodStart]);
    89→
    90→  const needsSetup =
    91→    state.members.length === 0 ||
    92→    !activeSheet ||
    93→    incomeTotal === 0 ||
    94→    (activeSheet.categories?.length ?? 0) === 0;
    95→
