    97→    return (
    98→      <View style={[styles.setupContainer, { backgroundColor: theme.background, paddingTop: insets.top }]}>
    99→        {/* Header - same as Home */}
   100→        <View style={[styles.headerRow, { paddingHorizontal: 18 }]}>
   101→          <View style={styles.menuButton} />
   102→          <Pressable
   103→            onPress={() => router.push("/settings")}
   104→            style={({ pressed }) => [
   105→              styles.menuButton,
   106→              styles.menuButtonRight,
   107→              { backgroundColor: theme.surface, opacity: pressed ? 0.7 : 1 },
   108→            ]}
   109→          >
   110→            <IconSymbol name="gearshape.fill" size={24} color={theme.text} />
   111→          </Pressable>
