   123→              ]}
   124→            >
   125→              <Text style={styles.btnText}>Open Setup</Text>
   126→            </Pressable>
   127→            <Pressable
   128→              onPress={() => router.push("/settings?openCloudSync=1")}
   129→              style={({ pressed }) => [
