     1→import { Dropdown } from "@/components/dropdown";
     2→import { GlassModalContainer } from "@/components/glass-modal-container";
     3→import { SUPPORTED_CURRENCIES } from "@/constants/currencies";
     4→import { sharedStyles } from "@/constants/sharedStyles";
     5→import { useAppTheme } from "@/hooks/use-app-theme";
     6→import { useColorScheme } from "@/hooks/use-color-scheme";
     7→import { useLanguage } from "@/hooks/use-language";
     8→import { useCloudSyncSetup } from "@/hooks/use-cloud-sync-setup";
     9→import { useDataExportImport } from "@/hooks/use-data-export-import";
    10→import { useTipPurchase } from "@/hooks/use-tip-purchase";
    11→import { saveState } from "@/src/storage";
    12→import { useStore } from "@/src/store";
    13→import { useLocalSearchParams } from "expo-router";
    14→import React, { useState, useEffect } from "react";
    15→import { Pressable, ScrollView, StyleSheet, Text, View } from "react-native";
    16→
    17→export default function SettingsScreen() {
    18→  const { state, setState, syncFromCloud, syncing, skipNextCloudPush } = useStore();
    19→  const colorScheme = useColorScheme();
    20→  const theme = useAppTheme();
    21→  const { t, isJa } = useLanguage();
    22→  const { openCloudSync } = useLocalSearchParams<{ openCloudSync?: string }>();
    23→
    24→  // Cloud sync setup hook
    25→  const cloudSync = useCloudSyncSetup({ state, setState, openCloudSync });
    26→
    27→  // Export/Import hook
    28→  const dataIO = useDataExportImport({ state, setState });
    29→
    30→  // Tip purchase hook
    31→  const tips = useTipPurchase();
    32→  const [showTipThankYou, setShowTipThankYou] = useState(false);
    33→
    34→  // Auto-hide thank you message after 3 seconds
    35→  const tipState = tips.state;
    36→  const tipResetState = tips.resetState;
    37→  useEffect(() => {
    38→    if (tipState === "success") {
    39→      setShowTipThankYou(true);
    40→      const timer = setTimeout(() => {
    41→        setShowTipThankYou(false);
    42→        tipResetState();
    43→      }, 3000);
    44→      return () => clearTimeout(timer);
    45→    }
    46→  }, [tipState, tipResetState]);
    47→
    48→  const handleTipPurchase = async (productId: string) => {
    49→    await tips.purchase(productId);
    50→  };
    51→
    52→  // Get emoji for tip product
    53→  const getTipEmoji = (productId: string) => {
    54→    switch (productId) {
    55→      case "tip_small":
    56→        return "\u2615"; // coffee
    57→      case "tip_medium":
    58→        return "\ud83c\udf71"; // bento
    59→      case "tip_large":
    60→        return "\ud83c\udf7b"; // drinks
    61→      default:
    62→        return "\ud83d\udc9d"; // heart
    63→    }
    64→  };
    65→
    66→  // Get localized tip name
    67→  const getTipName = (productId: string) => {
    68→    switch (productId) {
    69→      case "tip_small":
    70→        return t("tipCoffee");
    71→      case "tip_medium":
    72→        return t("tipLunch");
    73→      case "tip_large":
    74→        return t("tipDrinks");
    75→      default:
    76→        return productId;
    77→    }
    78→  };
    79→
    80→  const handleThemeChange = async (pref: "system" | "light" | "dark") => {
    81→    const updatedState = { ...state, themePreference: pref };
    82→    await saveState(updatedState);
    83→    setState(updatedState);
    84→  };
    85→
    86→  const handleBaseCurrencyChange = async (newBase: string) => {
    87→    const oldBase = state.baseCurrency;
    88→    if (newBase === oldBase) return;
    89→
    90→    const usedCurrencies = state.usedCurrencies ?? [];
    91→    const nextUsed = usedCurrencies.filter((c) => c !== newBase);
    92→
    93→    const updatedSheets = state.sheets.map((sheet) => ({
    94→      ...sheet,
    95→      incomeItems: sheet.incomeItems.map((it) => ({
    96→        ...it,
    97→        ...(it.inputCurrency != null ? {} : { inputCurrency: oldBase, rate: 1 }),
    98→      })),
    99→      fixedExpenses: (sheet.fixedExpenses ?? []).map((it) => ({
   100→        ...it,
   101→        ...(it.inputCurrency != null ? {} : { inputCurrency: oldBase, rate: 1 }),
   102→      })),
   103→      savingsItems: (sheet.savingsItems ?? []).map((it) => ({
   104→        ...it,
   105→        ...(it.inputCurrency != null ? {} : { inputCurrency: oldBase, rate: 1 }),
   106→      })),
   107→      expenses: sheet.expenses.map((e) => ({
   108→        ...e,
   109→        ...(e.inputCurrency != null ? {} : { inputCurrency: oldBase, rate: 1 }),
   110→      })),
   111→    }));
   112→
   113→    const updatedState = {
   114→      ...state,
   115→      baseCurrency: newBase,
   116→      usedCurrencies: nextUsed,
   117→      sheets: updatedSheets,
   118→    };
   119→    await saveState(updatedState);
   120→    skipNextCloudPush();
   121→    setState(updatedState);
   122→  };
   123→
   124→  const handleLanguageChange = (lang: "en" | "ja") => {
   125→    setState({ ...state, language: lang });
   126→  };
   127→
   128→  const usedCurrencies = state.usedCurrencies ?? [];
   129→  const addableCurrencies = SUPPORTED_CURRENCIES.filter(
   130→    (c) => c.code !== state.baseCurrency && !usedCurrencies.includes(c.code)
   131→  );
   132→  const [addCurrencyDraft, setAddCurrencyDraft] = useState<string>("");
   133→
   134→  const handleAddUsedCurrency = (code: string) => {
   135→    if (!code || usedCurrencies.includes(code) || code === state.baseCurrency) return;
   136→    setState({ ...state, usedCurrencies: [...usedCurrencies, code] });
   137→    setAddCurrencyDraft("");
   138→  };
   139→
   140→  const handleRemoveUsedCurrency = (code: string) => {
   141→    const next = (state.usedCurrencies ?? []).filter((c) => c !== code);
   142→    setState({ ...state, usedCurrencies: next });
   143→  };
   144→
   145→  const themeOptions: { value: "system" | "light" | "dark"; label: string }[] = [
   146→    { value: "system", label: t("standard") },
   147→    { value: "light", label: t("light") },
   148→    { value: "dark", label: t("dark") },
   149→  ];
   150→
   151→  const languageOptions: { value: "en" | "ja"; label: string }[] = [
   152→    { value: "en", label: t("languageEn") },
   153→    { value: "ja", label: t("languageJa") },
   154→  ];
   155→
   156→  return (
   157→    <GlassModalContainer>
   158→      <ScrollView
   159→        style={styles.scrollView}
   160→        contentInsetAdjustmentBehavior="automatic"
   161→        contentContainerStyle={{ paddingTop: 16, paddingBottom: 12 }}
   162→      >
   163→        <View style={{ gap: 12, paddingHorizontal: 18 }}>
   164→          {/* Main Currency */}
   165→          <View style={[styles.section, { backgroundColor: theme.surface }]}>
   166→            <Text style={[styles.sectionTitle, { color: theme.text }]}>{t("mainCurrency")}</Text>
   167→            <Dropdown
   168→              options={SUPPORTED_CURRENCIES.map((c) => ({
   169→                label: isJa ? `${c.code} ${c.nameJa}` : `${c.code} ${c.nameEn}`,
   170→                value: c.code,
   171→              }))}
   172→              selectedValue={state.baseCurrency}
   173→              onValueChange={handleBaseCurrencyChange}
   174→              theme={theme}
   175→              placeholder={t("mainCurrency")}
   176→            />
   177→          </View>
   178→
   179→          {/* Used Currencies */}
   180→          <View style={[styles.section, { backgroundColor: theme.surface }]}>
   181→            <Text style={[styles.sectionTitle, { color: theme.text }]}>{t("usedCurrencies")}</Text>
   182→            <Text style={[styles.sectionDescription, { color: theme.subText }]}>
   183→              {t("usedCurrenciesHelp")}
   184→            </Text>
   185→            {usedCurrencies.length > 0 && (
   186→              <View style={{ flexDirection: "row", flexWrap: "wrap", gap: 8, marginBottom: 8 }}>
   187→                {usedCurrencies.map((code) => {
   188→                  const info = SUPPORTED_CURRENCIES.find((c) => c.code === code);
   189→                  const label = info
   190→                    ? isJa
   191→                      ? `${code} ${info.nameJa}`
   192→                      : `${code} ${info.nameEn}`
   193→                    : code;
   194→                  return (
   195→                    <View
   196→                      key={code}
   197→                      style={[
   198→                        styles.usedCurrencyChip,
   199→                        { backgroundColor: theme.inputBg, borderColor: theme.border },
   200→                      ]}
   201→                    >
   202→                      <Text style={[styles.usedCurrencyChipText, { color: theme.text }]}>
   203→                        {label}
   204→                      </Text>
   205→                      <Pressable
   206→                        onPress={() => handleRemoveUsedCurrency(code)}
   207→                        hitSlop={8}
   208→                        style={{ paddingLeft: 6 }}
   209→                      >
   210→                        <Text style={{ color: theme.subText, fontSize: 14 }}>×</Text>
   211→                      </Pressable>
   212→                    </View>
   213→                  );
   214→                })}
   215→              </View>
   216→            )}
   217→            {addableCurrencies.length > 0 && (
   218→              <View style={{ flexDirection: "row", gap: 8, alignItems: "center" }}>
   219→                <View style={{ flex: 1 }}>
   220→                  <Dropdown
   221→                    options={[
   222→                      { label: t("selectCurrencyToAdd"), value: "" },
   223→                      ...addableCurrencies.map((c) => ({
   224→                        label: isJa ? `${c.code} ${c.nameJa}` : `${c.code} ${c.nameEn}`,
   225→                        value: c.code,
   226→                      })),
   227→                    ]}
   228→                    selectedValue={addCurrencyDraft || ""}
   229→                    onValueChange={(v) => setAddCurrencyDraft(v || "")}
   230→                    theme={theme}
   231→                    placeholder={t("selectCurrencyToAdd")}
   232→                  />
   233→                </View>
   234→                <Pressable
   235→                  onPress={() => {
   236→                    if (addCurrencyDraft) handleAddUsedCurrency(addCurrencyDraft);
   237→                    setAddCurrencyDraft("");
   238→                  }}
   239→                  disabled={!addCurrencyDraft}
   240→                  style={[
   241→                    styles.addCurrencyButton,
   242→                    { backgroundColor: theme.buttonDark },
   243→                    !addCurrencyDraft && { opacity: 0.5 },
   244→                  ]}
   245→                >
   246→                  <Text style={styles.addCurrencyButtonText}>{t("addCurrency")}</Text>
   247→                </Pressable>
   248→              </View>
   249→            )}
   250→          </View>
   251→
   252→          {/* Language */}
   253→          <View style={[styles.section, { backgroundColor: theme.surface }]}>
   254→            <Text style={[styles.sectionTitle, { color: theme.text }]}>{t("language")}</Text>
   255→            <ToggleSegments
   256→              options={languageOptions}
   257→              selectedValue={state.language}
   258→              onSelect={handleLanguageChange}
   259→              colorScheme={colorScheme}
   260→              theme={theme}
   261→            />
   262→          </View>
   263→
   264→          {/* Cloud Sync */}
   265→          <View style={[styles.section, { backgroundColor: theme.surface }]}>
   266→            <Text style={[styles.sectionTitle, { color: theme.text }]}>Cloud Storage Sync</Text>
   267→            <Text style={[styles.sectionDescription, { color: theme.subText }]}>
   268→              {state.cloudSyncFileUri
   269→                ? "Your data is automatically synced with cloud storage."
   270→                : "Set up cloud sync to keep your data synchronized across devices. Tap below to select a folder (e.g. iCloud, Google Drive, Dropbox, or device storage). If the folder already contains NOKORI data, you can load it."}
   271→            </Text>
   272→
   273→            {state.cloudSyncFileUri ? (
   274→              <>
   275→                <View style={[styles.syncStatus, { backgroundColor: theme.successBg }]}>
   276→                  <Text style={[styles.syncStatusText, { color: theme.successText }]}>
   277→                    ✓ Cloud Sync Active
   278→                  </Text>
   279→                  <Text style={[styles.syncFileText, { color: theme.subText }]} numberOfLines={1}>
   280→                    {state.cloudSyncFileUri.split("/").pop() || state.cloudSyncFileUri}
   281→                  </Text>
   282→                </View>
   283→                <Text style={[styles.subsectionTitle, { color: theme.text }]}>{t("syncMode")}</Text>
   284→                <ToggleSegments
   285→                  options={[
   286→                    { value: false, label: t("syncModeEdit") },
   287→                    { value: true, label: t("syncModeView") },
   288→                  ]}
   289→                  selectedValue={state.cloudSyncReadOnly ?? false}
   290→                  onSelect={cloudSync.handleSyncModeChange}
   291→                  colorScheme={colorScheme}
   292→                  theme={theme}
   293→                />
   294→                <Text style={[styles.themeCaption, { color: theme.subText }]}>
   295→                  {state.cloudSyncReadOnly ?? false ? t("syncModeViewDesc") : t("syncModeEditDesc")}
   296→                </Text>
   297→                {!(state.cloudSyncReadOnly ?? false) && (
   298→                  <Pressable
   299→                    onPress={() => syncFromCloud()}
   300→                    disabled={syncing}
   301→                    style={[
   302→                      styles.button,
   303→                      { backgroundColor: theme.buttonDark },
   304→                      syncing && styles.buttonDisabled,
   305→                    ]}
   306→                  >
   307→                    <Text style={styles.buttonText}>{syncing ? "…" : t("syncNow")}</Text>
   308→                  </Pressable>
   309→                )}
   310→                <Pressable
   311→                  onPress={cloudSync.handleSelectSyncFolder}
   312→                  disabled={cloudSync.isSettingSync}
   313→                  style={[
   314→                    styles.button,
   315→                    { backgroundColor: theme.buttonPrimary },
   316→                    cloudSync.isSettingSync && styles.buttonDisabled,
   317→                  ]}
   318→                >
   319→                  <Text style={styles.buttonText}>{cloudSync.isSettingSync ? "…" : "Reconnect Folder"}</Text>
   320→                </Pressable>
   321→                <Pressable
   322→                  onPress={cloudSync.handleDisableCloudSync}
   323→                  style={[
   324→                    styles.button,
   325→                    { backgroundColor: theme.buttonDanger },
   326→                    styles.disableSyncButton,
   327→                  ]}
   328→                >
   329→                  <Text style={styles.buttonText}>Disable Cloud Sync</Text>
   330→                </Pressable>
   331→              </>
   332→            ) : (
   333→              <View style={{ gap: 8 }}>
   334→                <Pressable
   335→                  onPress={cloudSync.handleSelectSyncFolder}
   336→                  disabled={cloudSync.isSettingSync}
   337→                  style={[
   338→                    styles.button,
   339→                    { backgroundColor: theme.buttonSuccess },
   340→                    cloudSync.isSettingSync && styles.buttonDisabled,
   341→                  ]}
   342→                >
   343→                  <Text style={styles.buttonText}>
   344→                    {cloudSync.isSettingSync ? "Setting up..." : "Set Up Cloud Sync"}
   345→                  </Text>
   346→                </Pressable>
   347→                {cloudSync.isSettingSync && (
   348→                  <Pressable
   349→                    onPress={cloudSync.cancelSetup}
   350→                    style={[styles.button, { backgroundColor: theme.buttonDark }]}
   351→                  >
   352→                    <Text style={styles.buttonText}>Cancel</Text>
   353→                  </Pressable>
   354→                )}
   355→              </View>
   356→            )}
   357→
   358→            <View style={[styles.divider, { backgroundColor: theme.border }]} />
   359→            <Text style={[styles.subsectionTitle, { color: theme.text }]}>Manual Export/Import</Text>
   360→            <Pressable
   361→              onPress={dataIO.handleExportData}
   362→              disabled={dataIO.isExporting || dataIO.isImporting}
   363→              style={[
   364→                styles.button,
   365→                { backgroundColor: theme.buttonDark },
   366→                (dataIO.isExporting || dataIO.isImporting) && styles.buttonDisabled,
   367→              ]}
   368→            >
   369→              <Text style={styles.buttonText}>
   370→                {dataIO.isExporting ? "Exporting..." : "Export to Cloud Storage"}
   371→              </Text>
   372→            </Pressable>
   373→            <Pressable
   374→              onPress={dataIO.handleImportData}
   375→              disabled={dataIO.isExporting || dataIO.isImporting}
   376→              style={[
   377→                styles.button,
   378→                { backgroundColor: theme.buttonPrimary },
   379→                styles.importButton,
   380→                (dataIO.isExporting || dataIO.isImporting) && styles.buttonDisabled,
   381→              ]}
   382→            >
   383→              <Text style={styles.buttonText}>
   384→                {dataIO.isImporting ? "Importing..." : "Import from Cloud Storage"}
   385→              </Text>
   386→            </Pressable>
   387→          </View>
   388→
   389→          {/* Dark Mode */}
   390→          <View style={[styles.section, { backgroundColor: theme.surface }]}>
   391→            <Text style={[styles.sectionTitle, { color: theme.text }]}>{t("darkMode")}</Text>
   392→            <ToggleSegments
   393→              options={themeOptions}
   394→              selectedValue={state.themePreference}
   395→              onSelect={handleThemeChange}
   396→              colorScheme={colorScheme}
   397→              theme={theme}
   398→            />
   399→            <Text style={[styles.themeCaption, { color: theme.subText }]}>
   400→              {t("standardCaption", { scheme: colorScheme === "dark" ? t("dark") : t("light") })}
   401→            </Text>
   402→          </View>
   403→
   404→          {/* Data Info */}
   405→          <View style={[styles.section, { backgroundColor: theme.surface }]}>
   406→            <Text style={[styles.sectionTitle, { color: theme.text }]}>{t("dataInfo")}</Text>
   407→            <InfoRow
   408→              label={`${t("totalSheets")}:`}
   409→              value={String(state.sheets.length)}
   410→              theme={theme}
   411→            />
   412→            <InfoRow
   413→              label={`${t("totalMembers")}:`}
   414→              value={String(state.members.length)}
   415→              theme={theme}
   416→            />
   417→            <InfoRow label={`${t("baseCurrency")}:`} value={state.baseCurrency} theme={theme} />
   418→          </View>
   419→
   420→          {/* Support Developer / Tips */}
   421→          {tips.isAvailable && (
   422→            <View style={[styles.section, { backgroundColor: theme.surface }]}>
   423→              <Text style={[styles.sectionTitle, { color: theme.text }]}>
   424→                {t("supportDeveloper")}
   425→              </Text>
   426→              <Text style={[styles.sectionDescription, { color: theme.subText }]}>
   427→                {t("supportDeveloperDesc")}
   428→              </Text>
   429→
   430→              {tips.state === "loading" && (
   431→                <Text style={[styles.tipStatusText, { color: theme.subText }]}>
   432→                  {t("loading")}
   433→                </Text>
   434→              )}
   435→
   436→              {tips.state === "error" && (
   437→                <Text style={[styles.tipStatusText, { color: theme.expenseText }]}>
   438→                  {t("tipError")}
   439→                </Text>
   440→              )}
   441→
   442→              {showTipThankYou && (
   443→                <View style={[styles.tipThankYou, { backgroundColor: theme.successBg }]}>
   444→                  <Text style={[styles.tipThankYouText, { color: theme.successText }]}>
   445→                    {t("tipThankYou")}
   446→                  </Text>
   447→                </View>
   448→              )}
   449→
   450→              {tips.products.length > 0 && !showTipThankYou && (
   451→                <View style={styles.tipButtonsRow}>
   452→                  {tips.products.map((product) => (
   453→                    <Pressable
   454→                      key={product.id}
   455→                      onPress={() => handleTipPurchase(product.id)}
   456→                      disabled={tips.state === "purchasing"}
   457→                      style={[
   458→                        styles.tipButton,
   459→                        { backgroundColor: theme.buttonDark },
   460→                        tips.state === "purchasing" && styles.buttonDisabled,
   461→                      ]}
   462→                    >
   463→                      <Text style={styles.tipButtonEmoji}>{getTipEmoji(product.id)}</Text>
   464→                      <Text style={styles.tipButtonPrice}>{product.displayPrice}</Text>
   465→                      <Text style={styles.tipButtonName}>{getTipName(product.id)}</Text>
   466→                    </Pressable>
   467→                  ))}
   468→                </View>
   469→              )}
   470→
   471→              {tips.state === "purchasing" && (
   472→                <Text style={[styles.tipStatusText, { color: theme.subText, marginTop: 8 }]}>
   473→                  {t("tipPurchasing")}
   474→                </Text>
   475→              )}
   476→            </View>
   477→          )}
   478→        </View>
   479→      </ScrollView>
   480→    </GlassModalContainer>
   481→  );
   482→}
   483→
   484→// Helper component for toggle segments
   485→function ToggleSegments<T extends string | boolean>({
   486→  options,
   487→  selectedValue,
   488→  onSelect,
   489→  colorScheme,
   490→  theme,
   491→}: {
   492→  options: { value: T; label: string }[];
   493→  selectedValue: T;
   494→  onSelect: (value: T) => void;
   495→  colorScheme: "light" | "dark" | null | undefined;
   496→  theme: ReturnType<typeof useAppTheme>;
   497→}) {
   498→  return (
   499→    <View
   500→      style={[
   501→        styles.toggleTrack,
   502→        {
   503→          backgroundColor:
   504→            colorScheme === "light" ? "rgba(0,0,0,0.06)" : "rgba(255,255,255,0.08)",
   505→        },
   506→      ]}
   507→    >
   508→      {options.map((opt) => {
   509→        const isSelected = selectedValue === opt.value;
   510→        return (
   511→          <Pressable
   512→            key={String(opt.value)}
   513→            onPress={() => onSelect(opt.value)}
   514→            style={[
   515→              styles.toggleSegment,
   516→              isSelected && [
   517→                styles.toggleSegmentSelected,
   518→                {
   519→                  backgroundColor:
   520→                    colorScheme === "light" ? "#ffffff" : "rgba(255,255,255,0.15)",
   521→                },
   522→              ],
   523→            ]}
   524→          >
   525→            <Text
   526→              style={[
   527→                styles.toggleLabel,
   528→                {
   529→                  color: isSelected ? theme.text : theme.subText,
   530→                  fontWeight: isSelected ? "700" : "500",
   531→                },
   532→              ]}
   533→            >
   534→              {opt.label}
   535→            </Text>
   536→          </Pressable>
   537→        );
   538→      })}
   539→    </View>
   540→  );
   541→}
   542→
   543→// Helper component for info rows
   544→function InfoRow({
   545→  label,
   546→  value,
   547→  theme,
   548→}: {
   549→  label: string;
   550→  value: string;
   551→  theme: ReturnType<typeof useAppTheme>;
   552→}) {
   553→  return (
   554→    <View style={[styles.infoRow, { borderBottomColor: theme.border }]}>
   555→      <Text style={[styles.infoLabel, { color: theme.subText }]}>{label}</Text>
   556→      <Text style={[styles.infoValue, { color: theme.text }]}>{value}</Text>
   557→    </View>
   558→  );
   559→}
   560→
   561→const styles = StyleSheet.create({
   562→  ...sharedStyles.layout,
   563→  // Settings-specific styles
   564→  section: { padding: 16, borderRadius: 12, gap: 12 },
   565→  sectionTitle: { fontSize: 18, fontWeight: "700", marginBottom: 4 },
   566→  sectionDescription: { fontSize: 14, lineHeight: 20, marginBottom: 8 },
   567→  button: { paddingVertical: 14, paddingHorizontal: 20, borderRadius: 10, alignItems: "center", justifyContent: "center" },
   568→  importButton: { marginTop: 8 },
   569→  disableSyncButton: { marginTop: 8 },
   570→  buttonDisabled: { opacity: 0.5 },
   571→  buttonText: { color: "#fff", fontSize: 16, fontWeight: "700" },
   572→  syncStatus: { padding: 12, borderRadius: 8, marginBottom: 8 },
   573→  syncStatusText: { fontSize: 14, fontWeight: "700", marginBottom: 4 },
