   576→  subsectionTitle: { fontSize: 18, fontWeight: "700", marginBottom: 8 },
   577→  infoRow: { flexDirection: "row", justifyContent: "space-between", alignItems: "center", paddingVertical: 8, borderBottomWidth: StyleSheet.hairlineWidth },
