   582→  toggleSegmentSelected: { shadowColor: "#000", shadowOffset: { width: 0, height: 1 }, shadowOpacity: 0.08, shadowRadius: 4, elevation: 2 },
   583→  toggleLabel: { fontSize: 14 },
