});

import { Dropdown } from "@/components/dropdown";
import { GlassModalContainer } from "@/components/glass-modal-container";
import { SUPPORTED_CURRENCIES } from "@/constants/currencies";
import { sharedStyles } from "@/constants/sharedStyles";
import { useModalTheme } from "@/hooks/use-modal-theme";
import { useColorScheme } from "@/hooks/use-color-scheme";
import { useLanguage } from "@/hooks/use-language";
import { useCloudSyncSetup } from "@/hooks/use-cloud-sync-setup";
import { useDataExportImport } from "@/hooks/use-data-export-import";
import { useTipPurchase } from "@/hooks/use-tip-purchase";
import { saveState } from "@/src/storage";
import { useStore } from "@/src/store";
import { useLocalSearchParams } from "expo-router";
import React, { useState, useEffect } from "react";
import { Pressable, ScrollView, StyleSheet, Text, View } from "react-native";

export default function SettingsScreen() {
  const { state, setState, syncFromCloud, syncing, skipNextCloudPush } = useStore();
  const colorScheme = useColorScheme();
  const theme = useAppTheme();
  const { t, isJa } = useLanguage();
  const { openCloudSync } = useLocalSearchParams<{ openCloudSync?: string }>();

  // Cloud sync setup hook
  const cloudSync = useCloudSyncSetup({ state, setState, openCloudSync });

  // Export/Import hook
  const dataIO = useDataExportImport({ state, setState });

  // Tip purchase hook
  const tips = useTipPurchase();
  const [showTipThankYou, setShowTipThankYou] = useState(false);

  // Auto-hide thank you message after 3 seconds
  const tipState = tips.state;
  const tipResetState = tips.resetState;
  useEffect(() => {
    if (tipState === "success") {
      setShowTipThankYou(true);
      const timer = setTimeout(() => {
        setShowTipThankYou(false);
        tipResetState();
      }, 3000);
      return () => clearTimeout(timer);
    }
  }, [tipState, tipResetState]);

  const handleTipPurchase = async (productId: string) => {
    await tips.purchase(productId);
  };

  // Get emoji for tip product
  const getTipEmoji = (productId: string) => {
    switch (productId) {
      case "tip_small":
        return "\u2615"; // coffee
      case "tip_medium":
        return "\ud83c\udf71"; // bento
      case "tip_large":
        return "\ud83c\udf7b"; // drinks
      default:
        return "\ud83d\udc9d"; // heart
    }
  };

  // Get localized tip name
  const getTipName = (productId: string) => {
    switch (productId) {
      case "tip_small":
        return t("tipCoffee");
      case "tip_medium":
        return t("tipLunch");
      case "tip_large":
        return t("tipDrinks");
      default:
        return productId;
    }
  };

  const handleThemeChange = async (pref: "system" | "light" | "dark") => {
    const updatedState = { ...state, themePreference: pref };
    await saveState(updatedState);
    setState(updatedState);
  };

  const handleBaseCurrencyChange = async (newBase: string) => {
    const oldBase = state.baseCurrency;
    if (newBase === oldBase) return;

    const usedCurrencies = state.usedCurrencies ?? [];
    const nextUsed = usedCurrencies.filter((c) => c !== newBase);

    const updatedSheets = state.sheets.map((sheet) => ({
      ...sheet,
      incomeItems: sheet.incomeItems.map((it) => ({
        ...it,
        ...(it.inputCurrency != null ? {} : { inputCurrency: oldBase, rate: 1 }),
      })),
      fixedExpenses: (sheet.fixedExpenses ?? []).map((it) => ({
        ...it,
        ...(it.inputCurrency != null ? {} : { inputCurrency: oldBase, rate: 1 }),
      })),
      savingsItems: (sheet.savingsItems ?? []).map((it) => ({
        ...it,
        ...(it.inputCurrency != null ? {} : { inputCurrency: oldBase, rate: 1 }),
      })),
      expenses: sheet.expenses.map((e) => ({
        ...e,
        ...(e.inputCurrency != null ? {} : { inputCurrency: oldBase, rate: 1 }),
      })),
    }));

    const updatedState = {
      ...state,
      baseCurrency: newBase,
      usedCurrencies: nextUsed,
      sheets: updatedSheets,
    };
    await saveState(updatedState);
    skipNextCloudPush();
    setState(updatedState);
  };

  const handleLanguageChange = (lang: "en" | "ja") => {
    setState({ ...state, language: lang });
  };

  const usedCurrencies = state.usedCurrencies ?? [];
  const addableCurrencies = SUPPORTED_CURRENCIES.filter(
    (c) => c.code !== state.baseCurrency && !usedCurrencies.includes(c.code)
  );
  const [addCurrencyDraft, setAddCurrencyDraft] = useState<string>("");

  const handleAddUsedCurrency = (code: string) => {
    if (!code || usedCurrencies.includes(code) || code === state.baseCurrency) return;
    setState({ ...state, usedCurrencies: [...usedCurrencies, code] });
    setAddCurrencyDraft("");
  };

  const handleRemoveUsedCurrency = (code: string) => {
    const next = (state.usedCurrencies ?? []).filter((c) => c !== code);
    setState({ ...state, usedCurrencies: next });
  };

  const themeOptions: { value: "system" | "light" | "dark"; label: string }[] = [
    { value: "system", label: t("standard") },
    { value: "light", label: t("light") },
    { value: "dark", label: t("dark") },
  ];

  const languageOptions: { value: "en" | "ja"; label: string }[] = [
    { value: "en", label: t("languageEn") },
    { value: "ja", label: t("languageJa") },
  ];

  return (
    <GlassModalContainer>
      <ScrollView
        style={styles.scrollView}
        contentInsetAdjustmentBehavior="automatic"
        contentContainerStyle={{ paddingTop: 16, paddingBottom: 12 }}
      >
        <View style={{ gap: 12, paddingHorizontal: 18 }}>
          {/* Main Currency */}
          <View style={[styles.section, { backgroundColor: theme.surface }]}>
            <Text style={[styles.sectionTitle, { color: theme.text }]}>{t("mainCurrency")}</Text>
            <Dropdown
              options={SUPPORTED_CURRENCIES.map((c) => ({
                label: isJa ? `${c.code} ${c.nameJa}` : `${c.code} ${c.nameEn}`,
                value: c.code,
              }))}
              selectedValue={state.baseCurrency}
              onValueChange={handleBaseCurrencyChange}
              theme={theme}
              placeholder={t("mainCurrency")}
            />
          </View>

          {/* Used Currencies */}
          <View style={[styles.section, { backgroundColor: theme.surface }]}>
            <Text style={[styles.sectionTitle, { color: theme.text }]}>{t("usedCurrencies")}</Text>
            <Text style={[styles.sectionDescription, { color: theme.subText }]}>
              {t("usedCurrenciesHelp")}
            </Text>
            {usedCurrencies.length > 0 && (
              <View style={{ flexDirection: "row", flexWrap: "wrap", gap: 8, marginBottom: 8 }}>
                {usedCurrencies.map((code) => {
                  const info = SUPPORTED_CURRENCIES.find((c) => c.code === code);
                  const label = info
                    ? isJa
                      ? `${code} ${info.nameJa}`
                      : `${code} ${info.nameEn}`
                    : code;
                  return (
                    <View
                      key={code}
                      style={[
                        styles.usedCurrencyChip,
                        { backgroundColor: theme.inputBg, borderColor: theme.border },
                      ]}
                    >
                      <Text style={[styles.usedCurrencyChipText, { color: theme.text }]}>
                        {label}
                      </Text>
                      <Pressable
                        onPress={() => handleRemoveUsedCurrency(code)}
                        hitSlop={8}
                        style={{ paddingLeft: 6 }}
                      >
                        <Text style={{ color: theme.subText, fontSize: 14 }}>×</Text>
                      </Pressable>
                    </View>
                  );
                })}
              </View>
            )}
            {addableCurrencies.length > 0 && (
              <View style={{ flexDirection: "row", gap: 8, alignItems: "center" }}>
                <View style={{ flex: 1 }}>
                  <Dropdown
                    options={[
                      { label: t("selectCurrencyToAdd"), value: "" },
                      ...addableCurrencies.map((c) => ({
                        label: isJa ? `${c.code} ${c.nameJa}` : `${c.code} ${c.nameEn}`,
                        value: c.code,
                      })),
                    ]}
                    selectedValue={addCurrencyDraft || ""}
                    onValueChange={(v) => setAddCurrencyDraft(v || "")}
                    theme={theme}
                    placeholder={t("selectCurrencyToAdd")}
                  />
                </View>
                <Pressable
                  onPress={() => {
                    if (addCurrencyDraft) handleAddUsedCurrency(addCurrencyDraft);
                    setAddCurrencyDraft("");
                  }}
                  disabled={!addCurrencyDraft}
                  style={[
                    styles.addCurrencyButton,
                    { backgroundColor: theme.buttonDark },
                    !addCurrencyDraft && { opacity: 0.5 },
                  ]}
                >
                  <Text style={styles.addCurrencyButtonText}>{t("addCurrency")}</Text>
                </Pressable>
              </View>
            )}
          </View>

          {/* Language */}
          <View style={[styles.section, { backgroundColor: theme.surface }]}>
            <Text style={[styles.sectionTitle, { color: theme.text }]}>{t("language")}</Text>
            <ToggleSegments
              options={languageOptions}
              selectedValue={state.language}
              onSelect={handleLanguageChange}
              colorScheme={colorScheme}
              theme={theme}
            />
          </View>

          {/* Cloud Sync */}
          <View style={[styles.section, { backgroundColor: theme.surface }]}>
            <Text style={[styles.sectionTitle, { color: theme.text }]}>Cloud Storage Sync</Text>
            <Text style={[styles.sectionDescription, { color: theme.subText }]}>
              {state.cloudSyncFileUri
                ? "Your data is automatically synced with cloud storage."
                : "Set up cloud sync to keep your data synchronized across devices. Tap below to select a folder (e.g. iCloud, Google Drive, Dropbox, or device storage). If the folder already contains NOKORI data, you can load it."}
            </Text>

            {state.cloudSyncFileUri ? (
              <>
                <View style={[styles.syncStatus, { backgroundColor: theme.successBg }]}>
                  <Text style={[styles.syncStatusText, { color: theme.successText }]}>
                    ✓ Cloud Sync Active
                  </Text>
                  <Text style={[styles.syncFileText, { color: theme.subText }]} numberOfLines={1}>
                    {state.cloudSyncFileUri.split("/").pop() || state.cloudSyncFileUri}
                  </Text>
                </View>
                <Text style={[styles.subsectionTitle, { color: theme.text }]}>{t("syncMode")}</Text>
                <ToggleSegments
                  options={[
                    { value: false, label: t("syncModeEdit") },
                    { value: true, label: t("syncModeView") },
                  ]}
                  selectedValue={state.cloudSyncReadOnly ?? false}
                  onSelect={cloudSync.handleSyncModeChange}
                  colorScheme={colorScheme}
                  theme={theme}
                />
                <Text style={[styles.themeCaption, { color: theme.subText }]}>
                  {state.cloudSyncReadOnly ?? false ? t("syncModeViewDesc") : t("syncModeEditDesc")}
                </Text>
                {!(state.cloudSyncReadOnly ?? false) && (
                  <Pressable
                    onPress={() => syncFromCloud()}
                    disabled={syncing}
                    style={[
                      styles.button,
                      { backgroundColor: theme.buttonDark },
                      syncing && styles.buttonDisabled,
                    ]}
                  >
                    <Text style={styles.buttonText}>{syncing ? "…" : t("syncNow")}</Text>
                  </Pressable>
                )}
                <Pressable
                  onPress={cloudSync.handleSelectSyncFolder}
                  disabled={cloudSync.isSettingSync}
                  style={[
                    styles.button,
                    { backgroundColor: theme.buttonPrimary },
                    cloudSync.isSettingSync && styles.buttonDisabled,
                  ]}
                >
                  <Text style={styles.buttonText}>{cloudSync.isSettingSync ? "…" : "Reconnect Folder"}</Text>
                </Pressable>
                <Pressable
                  onPress={cloudSync.handleDisableCloudSync}
                  style={[
                    styles.button,
                    { backgroundColor: theme.buttonDanger },
                    styles.disableSyncButton,
                  ]}
                >
                  <Text style={styles.buttonText}>Disable Cloud Sync</Text>
                </Pressable>
              </>
            ) : (
              <View style={{ gap: 8 }}>
                <Pressable
                  onPress={cloudSync.handleSelectSyncFolder}
                  disabled={cloudSync.isSettingSync}
                  style={[
                    styles.button,
                    { backgroundColor: theme.buttonSuccess },
                    cloudSync.isSettingSync && styles.buttonDisabled,
                  ]}
                >
                  <Text style={styles.buttonText}>
                    {cloudSync.isSettingSync ? "Setting up..." : "Set Up Cloud Sync"}
                  </Text>
                </Pressable>
                {cloudSync.isSettingSync && (
                  <Pressable
                    onPress={cloudSync.cancelSetup}
                    style={[styles.button, { backgroundColor: theme.buttonDark }]}
                  >
                    <Text style={styles.buttonText}>Cancel</Text>
                  </Pressable>
                )}
              </View>
            )}

            <View style={[styles.divider, { backgroundColor: theme.border }]} />
            <Text style={[styles.subsectionTitle, { color: theme.text }]}>Manual Export/Import</Text>
            <Pressable
              onPress={dataIO.handleExportData}
              disabled={dataIO.isExporting || dataIO.isImporting}
              style={[
                styles.button,
                { backgroundColor: theme.buttonDark },
                (dataIO.isExporting || dataIO.isImporting) && styles.buttonDisabled,
              ]}
            >
              <Text style={styles.buttonText}>
                {dataIO.isExporting ? "Exporting..." : "Export to Cloud Storage"}
              </Text>
            </Pressable>
            <Pressable
              onPress={dataIO.handleImportData}
              disabled={dataIO.isExporting || dataIO.isImporting}
              style={[
                styles.button,
                { backgroundColor: theme.buttonPrimary },
                styles.importButton,
                (dataIO.isExporting || dataIO.isImporting) && styles.buttonDisabled,
              ]}
            >
              <Text style={styles.buttonText}>
                {dataIO.isImporting ? "Importing..." : "Import from Cloud Storage"}
              </Text>
            </Pressable>
          </View>

          {/* Dark Mode */}
          <View style={[styles.section, { backgroundColor: theme.surface }]}>
            <Text style={[styles.sectionTitle, { color: theme.text }]}>{t("darkMode")}</Text>
            <ToggleSegments
              options={themeOptions}
              selectedValue={state.themePreference}
              onSelect={handleThemeChange}
              colorScheme={colorScheme}
              theme={theme}
            />
            <Text style={[styles.themeCaption, { color: theme.subText }]}>
              {t("standardCaption", { scheme: colorScheme === "dark" ? t("dark") : t("light") })}
            </Text>
          </View>

          {/* Data Info */}
          <View style={[styles.section, { backgroundColor: theme.surface }]}>
            <Text style={[styles.sectionTitle, { color: theme.text }]}>{t("dataInfo")}</Text>
            <InfoRow
              label={`${t("totalSheets")}:`}
              value={String(state.sheets.length)}
              theme={theme}
            />
            <InfoRow
              label={`${t("totalMembers")}:`}
              value={String(state.members.length)}
              theme={theme}
            />
            <InfoRow label={`${t("baseCurrency")}:`} value={state.baseCurrency} theme={theme} />
          </View>

          {/* Support Developer / Tips */}
          {tips.isAvailable && (
            <View style={[styles.section, { backgroundColor: theme.surface }]}>
              <Text style={[styles.sectionTitle, { color: theme.text }]}>
                {t("supportDeveloper")}
              </Text>
              <Text style={[styles.sectionDescription, { color: theme.subText }]}>
                {t("supportDeveloperDesc")}
              </Text>

              {tips.state === "loading" && (
                <Text style={[styles.tipStatusText, { color: theme.subText }]}>
                  {t("loading")}
                </Text>
              )}

              {tips.state === "error" && (
                <Text style={[styles.tipStatusText, { color: theme.expenseText }]}>
                  {t("tipError")}
                </Text>
              )}

              {showTipThankYou && (
                <View style={[styles.tipThankYou, { backgroundColor: theme.successBg }]}>
                  <Text style={[styles.tipThankYouText, { color: theme.successText }]}>
                    {t("tipThankYou")}
                  </Text>
                </View>
              )}

              {tips.products.length > 0 && !showTipThankYou && (
                <View style={styles.tipButtonsRow}>
                  {tips.products.map((product) => (
                    <Pressable
                      key={product.id}
                      onPress={() => handleTipPurchase(product.id)}
                      disabled={tips.state === "purchasing"}
                      style={[
                        styles.tipButton,
                        { backgroundColor: theme.buttonDark },
                        tips.state === "purchasing" && styles.buttonDisabled,
                      ]}
                    >
                      <Text style={styles.tipButtonEmoji}>{getTipEmoji(product.id)}</Text>
                      <Text style={styles.tipButtonPrice}>{product.displayPrice}</Text>
                      <Text style={styles.tipButtonName}>{getTipName(product.id)}</Text>
                    </Pressable>
                  ))}
                </View>
              )}

              {tips.state === "purchasing" && (
                <Text style={[styles.tipStatusText, { color: theme.subText, marginTop: 8 }]}>
                  {t("tipPurchasing")}
                </Text>
              )}
            </View>
          )}
        </View>
      </ScrollView>
    </GlassModalContainer>
  );
}

// Helper component for toggle segments
function ToggleSegments<T extends string | boolean>({
  options,
  selectedValue,
  onSelect,
  colorScheme,
  theme,
}: {
  options: { value: T; label: string }[];
  selectedValue: T;
  onSelect: (value: T) => void;
  colorScheme: "light" | "dark" | null | undefined;
  theme: ReturnType<typeof useAppTheme>;
}) {
  return (
    <View
      style={[
        styles.toggleTrack,
        {
          backgroundColor:
            colorScheme === "light" ? "rgba(0,0,0,0.06)" : "rgba(255,255,255,0.08)",
        },
      ]}
    >
      {options.map((opt) => {
        const isSelected = selectedValue === opt.value;
        return (
          <Pressable
            key={String(opt.value)}
            onPress={() => onSelect(opt.value)}
            style={[
              styles.toggleSegment,
              isSelected && [
                styles.toggleSegmentSelected,
                {
                  backgroundColor:
                    colorScheme === "light" ? "#ffffff" : "rgba(255,255,255,0.15)",
                },
              ],
            ]}
          >
            <Text
              style={[
                styles.toggleLabel,
                {
                  color: isSelected ? theme.text : theme.subText,
                  fontWeight: isSelected ? "700" : "500",
                },
              ]}
            >
              {opt.label}
            </Text>
          </Pressable>
        );
      })}
    </View>
  );
}

// Helper component for info rows
function InfoRow({
  label,
  value,
  theme,
}: {
  label: string;
  value: string;
  theme: ReturnType<typeof useAppTheme>;
}) {
  return (
    <View style={[styles.infoRow, { borderBottomColor: theme.border }]}>
      <Text style={[styles.infoLabel, { color: theme.subText }]}>{label}</Text>
      <Text style={[styles.infoValue, { color: theme.text }]}>{value}</Text>
    </View>
  );
}

