import { useRouter } from "expo-router";
import React, { useEffect, useMemo, useState } from "react";
import { Alert, KeyboardAvoidingView, Platform, Pressable, ScrollView, StyleSheet, Text, TextInput, View } from "react-native";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { AmountItemSection } from "../components/amount-item-section";
import { Dropdown } from "../components/dropdown";
import { GlassModalContainer } from "../components/glass-modal-container";
import { SwipeableRow, createDeleteAction } from "../components/swipeable-row";
import { sharedStyles } from "../constants/sharedStyles";
import { useAppTheme } from "../hooks/use-app-theme";
import { useFormStyles } from "../hooks/use-form-styles";
import { pressedStyle } from "../hooks/use-themed-styles";
import { useLanguage } from "../hooks/use-language";
import { useSetupAmountItem, useSetupSimpleList, useSetupCategoryList } from "../hooks/setup";
import { getPickerCurrencies, shouldShowCurrencyDropdown } from "../src/currency-input";
import { useStore } from "../src/store";
import { FixedExpenseItem, IncomeItem, Member, SavingItem, Sheet } from "../src/types";
import {
  clamp,
  daysBetweenInclusive,
  endOfMonthISO,
  itemAmountToBaseForSum,
  parseLocalDate,
  startOfMonthISO,
  uuid,
} from "../src/utils";

export default function SetupScreen() {
  const router = useRouter();
  const insets = useSafeAreaInsets();
  const { state, setState, activeSheet, rateCache, fillRateCacheForActiveSheet } = useStore();
  useEffect(() => {
    if (activeSheet) fillRateCacheForActiveSheet();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeSheet?.id, fillRateCacheForActiveSheet]);
  const theme = useAppTheme();
  const { t } = useLanguage();
  const { labelStyle, captionStyle, inputStyle, listTextStyle } = useFormStyles(theme);

  const [sheetName, setSheetName] = useState("");

  useEffect(() => {
    if (activeSheet?.name) setSheetName(activeSheet.name);
  }, [activeSheet?.name]);

  const base = state.baseCurrency;
  const periodStart = activeSheet?.periodStartISO ?? "";
  const opts = { rateCache, dateISO: periodStart };

  // Helper to update the active sheet, reducing repetitive setState patterns
  const updateActiveSheet = (updater: (sheet: Sheet) => Partial<Sheet>) => {
    setState((prev) => ({
      ...prev,
      sheets: prev.sheets.map((sh) =>
        sh.id === activeSheet?.id ? { ...sh, ...updater(sh) } : sh
      ),
    }));
  };

  // Period state
  const initialStartDate = activeSheet?.periodStartISO ?? startOfMonthISO(new Date());
  const initialEndDate = activeSheet?.periodEndISO ?? endOfMonthISO(new Date());
  const [periodStartISO, setPeriodStartISO] = useState(initialStartDate);
  const [periodEndISO, setPeriodEndISO] = useState(initialEndDate);

  const startDate = parseLocalDate(periodStartISO);
  const [selectedYear, setSelectedYear] = useState(startDate.getFullYear());
  const [selectedMonth, setSelectedMonth] = useState(startDate.getMonth() + 1);
  const [selectedDay, setSelectedDay] = useState(startDate.getDate());

  const determinePeriodType = (startISO: string, endISO: string): "month" | "custom" => {
    const start = parseLocalDate(startISO);
    const end = parseLocalDate(endISO);
    const monthEnd = new Date(start.getFullYear(), start.getMonth() + 1, 0);
    return end.getTime() === monthEnd.getTime() ? "month" : "custom";
  };

  const initialPeriodType = determinePeriodType(initialStartDate, initialEndDate);
  const [periodType, setPeriodType] = useState<"month" | "custom">(initialPeriodType);
  const [customPeriodDays, setCustomPeriodDays] = useState(daysBetweenInclusive(initialStartDate, initialEndDate));

  const currentYear = new Date().getFullYear();
  const yearOptions = Array.from({ length: 5 }, (_, i) => currentYear - 2 + i);
  const monthOptions = Array.from({ length: 12 }, (_, i) => i + 1);
  const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
  const getDaysInMonth = (year: number, month: number) => new Date(year, month, 0).getDate();
  const daysInSelectedMonth = getDaysInMonth(selectedYear, selectedMonth);
  const validSelectedDay = Math.min(selectedDay, daysInSelectedMonth);
  const dayOptions = Array.from({ length: daysInSelectedMonth }, (_, i) => i + 1);

  const updateEndDate = (startISO: string, pType: "month" | "custom", customDays: number) => {
    const start = parseLocalDate(startISO);
    let end: Date;
    if (pType === "month") {
      end = new Date(start.getFullYear(), start.getMonth() + 1, 0);
    } else {
      end = new Date(start);
      end.setDate(start.getDate() + customDays - 1);
    }
    setPeriodEndISO(`${end.getFullYear()}-${String(end.getMonth() + 1).padStart(2, "0")}-${String(end.getDate()).padStart(2, "0")}`);
  };

  const handleStartDateChange = (year: number, month: number, day: number) => {
    const newStart = `${year}-${String(month).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
    setPeriodStartISO(newStart);
    setSelectedYear(year);
    setSelectedMonth(month);
    setSelectedDay(day);
    updateEndDate(newStart, periodType, customPeriodDays);
  };

  const handlePeriodTypeChange = (type: "month" | "custom") => {
    setPeriodType(type);
    updateEndDate(periodStartISO, type, customPeriodDays);
  };

  const handleCustomPeriodDaysChange = (days: number) => {
    setCustomPeriodDays(days);
    updateEndDate(periodStartISO, "custom", days);
  };

  // Balance rule state
  const [needsPct, setNeedsPct] = useState(String(Math.round((activeSheet?.balanceRule.needsPct ?? 0.5) * 100)));
  const [wantsPct, setWantsPct] = useState(String(Math.round((activeSheet?.balanceRule.wantsPct ?? 0.3) * 100)));
  const [savingsPct, setSavingsPct] = useState(String(Math.round((activeSheet?.balanceRule.savingsPct ?? 0.2) * 100)));
  const pctSum = useMemo(() => (Number(needsPct) || 0) + (Number(wantsPct) || 0) + (Number(savingsPct) || 0), [needsPct, wantsPct, savingsPct]);

  // Data from active sheet (memoized to avoid re-renders from ?? creating new arrays)
  const incomeItems = useMemo(() => activeSheet?.incomeItems ?? [], [activeSheet]);
  const categories = useMemo(() => activeSheet?.categories ?? [], [activeSheet]);
  const fixedExpenses = useMemo(() => activeSheet?.fixedExpenses ?? [], [activeSheet]);
  const savingsItems = useMemo(() => activeSheet?.savingsItems ?? [], [activeSheet]);

  // Currency picker helpers
  const usedCurrencies = state.usedCurrencies ?? [];
  const currenciesInExistingIncome = useMemo(() => [...new Set(incomeItems.map((it) => it.inputCurrency ?? base).filter((c) => c !== base))], [incomeItems, base]);
  const currenciesInExistingFixed = useMemo(() => [...new Set(fixedExpenses.map((it) => it.inputCurrency ?? base).filter((c) => c !== base))], [fixedExpenses, base]);
  const currenciesInExistingSaving = useMemo(() => [...new Set(savingsItems.map((it) => it.inputCurrency ?? base).filter((c) => c !== base))], [savingsItems, base]);

  const getIncomePickerCurrencies = (current?: string) => getPickerCurrencies(base, [...usedCurrencies, ...currenciesInExistingIncome], current);
  const getFixedPickerCurrencies = (current?: string) => getPickerCurrencies(base, [...usedCurrencies, ...currenciesInExistingFixed], current);
  const getSavingPickerCurrencies = (current?: string) => getPickerCurrencies(base, [...usedCurrencies, ...currenciesInExistingSaving], current);

  // Member list management
  const memberList = useSetupSimpleList<Member>({
    items: state.members,
    onAdd: (member) => setState((prev) => ({ ...prev, members: [...prev.members, member] })),
    onUpdate: (id, updates) => setState((prev) => ({ ...prev, members: prev.members.map((m) => (m.id === id ? { ...m, ...updates } : m)) })),
    onDelete: (id) => setState((prev) => ({ ...prev, members: prev.members.filter((m) => m.id !== id) })),
    onReorder: (members) => setState((prev) => ({ ...prev, members })),
    createItem: (name) => ({ id: uuid(), name }),
    deleteTitle: "Delete Member",
  });

  // Income list management
  const incomeList = useSetupAmountItem({
    baseCurrency: base,
    periodStartISO,
    onAdd: (item) => updateActiveSheet((sh) => ({ incomeItems: [...(sh.incomeItems ?? []), item as IncomeItem] })),
    onUpdate: (id, updates) => updateActiveSheet((sh) => ({ incomeItems: (sh.incomeItems ?? []).map((it) => it.id === id ? { ...it, ...updates } : it) })),
    onDelete: (id) => updateActiveSheet((sh) => ({ incomeItems: (sh.incomeItems ?? []).filter((it) => it.id !== id) })),
    t,
  });

  // Fixed expenses list management
  const fixedList = useSetupAmountItem({
    baseCurrency: base,
    periodStartISO,
    onAdd: (item) => updateActiveSheet((sh) => ({ fixedExpenses: [...(sh.fixedExpenses ?? []), item as FixedExpenseItem] })),
    onUpdate: (id, updates) => updateActiveSheet((sh) => ({ fixedExpenses: (sh.fixedExpenses ?? []).map((it) => it.id === id ? { ...it, ...updates } : it) })),
    onDelete: (id) => updateActiveSheet((sh) => ({ fixedExpenses: (sh.fixedExpenses ?? []).filter((it) => it.id !== id) })),
    t,
  });

  // Savings list management
  const savingsList = useSetupAmountItem({
    baseCurrency: base,
    periodStartISO,
    onAdd: (item) => updateActiveSheet((sh) => ({ savingsItems: [...(sh.savingsItems ?? []), item as SavingItem] })),
    onUpdate: (id, updates) => updateActiveSheet((sh) => ({ savingsItems: (sh.savingsItems ?? []).map((it) => it.id === id ? { ...it, ...updates } : it) })),
    onDelete: (id) => updateActiveSheet((sh) => ({ savingsItems: (sh.savingsItems ?? []).filter((it) => it.id !== id) })),
    t,
  });

  // Category list management
  const categoryList = useSetupCategoryList({
    categories,
    onAdd: (cat) => updateActiveSheet(() => ({ categories: [...(categories ?? []), cat] })),
    onUpdate: (id, updates) => updateActiveSheet((sh) => ({ categories: (sh.categories ?? []).map((c) => c.id === id ? { ...c, ...updates } : c) })),
    onDelete: (id) => updateActiveSheet((sh) => ({ categories: (sh.categories ?? []).filter((c) => c.id !== id) })),
    onReorder: (cats) => updateActiveSheet(() => ({ categories: cats })),
  });

  // Income reordering
  const moveIncome = (fromIdx: number, direction: 1 | -1) => {
    const toIdx = fromIdx + direction;
    if (toIdx < 0 || toIdx >= incomeItems.length) return;
    const arr = [...incomeItems];
    [arr[fromIdx], arr[toIdx]] = [arr[toIdx], arr[fromIdx]];
    updateActiveSheet(() => ({ incomeItems: arr }));
  };

  // Fixed expense reordering
  const moveFixedExpense = (fromIdx: number, direction: 1 | -1) => {
    const toIdx = fromIdx + direction;
    if (toIdx < 0 || toIdx >= fixedExpenses.length) return;
    const arr = [...fixedExpenses];
    [arr[fromIdx], arr[toIdx]] = [arr[toIdx], arr[fromIdx]];
    updateActiveSheet(() => ({ fixedExpenses: arr }));
  };

  // Savings reordering
  const moveSavings = (fromIdx: number, direction: 1 | -1) => {
    const toIdx = fromIdx + direction;
    if (toIdx < 0 || toIdx >= savingsItems.length) return;
    const arr = [...savingsItems];
    [arr[fromIdx], arr[toIdx]] = [arr[toIdx], arr[fromIdx]];
    updateActiveSheet(() => ({ savingsItems: arr }));
  };

  // Reset currencies when base changes
  useEffect(() => {
    incomeList.resetCurrencies(base);
    fixedList.resetCurrencies(base);
    savingsList.resetCurrencies(base);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [base]);

  // Totals
  const incomeTotal = useMemo(() => {
    const opts = { rateCache, dateISO: periodStart };
    return incomeItems.reduce((a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts), 0);
  }, [incomeItems, base, rateCache, periodStart]);
  const fixedExpensesTotal = useMemo(() => {
    const opts = { rateCache, dateISO: periodStart };
    return fixedExpenses.reduce((a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts), 0);
  }, [fixedExpenses, base, rateCache, periodStart]);
  const savingsTotal = useMemo(() => {
    const opts = { rateCache, dateISO: periodStart };
    return savingsItems.reduce((a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts), 0);
  }, [savingsItems, base, rateCache, periodStart]);

  if (!activeSheet) return <View style={[styles.center, { backgroundColor: theme.background }]}><Text style={{ color: theme.text }}>{t("loading")}</Text></View>;

  const save = () => {
    if (state.members.length === 0) { Alert.alert(t("addMember"), t("addMemberFirst")); return; }
    if (incomeTotal <= 0) { Alert.alert(t("addIncome"), t("addIncomeFirst")); return; }
    if (categories.length === 0) { Alert.alert(t("addCategories"), t("addCategoriesFirst")); return; }
    const n = clamp((Number(needsPct) || 0) / 100, 0, 1);
    const w = clamp((Number(wantsPct) || 0) / 100, 0, 1);
    const s = clamp((Number(savingsPct) || 0) / 100, 0, 1);
    if (Math.abs(n + w + s - 1) > 0.001) { Alert.alert(t("totalMustBe100"), t("currentTotal", { total: pctSum })); return; }
    const catRatioTotal = categories.reduce((sum, c) => sum + c.ratio, 0);
    if (categories.length > 0 && Math.abs(catRatioTotal - 1) > 0.001) { Alert.alert(t("categoryRatiosMust100"), t("currentTotal", { total: categoryList.categoryRatioSum.toFixed(1) })); return; }

    const startDateParsed = parseLocalDate(periodStartISO);
    const endDateParsed = parseLocalDate(periodEndISO);
    if (isNaN(startDateParsed.getTime()) || isNaN(endDateParsed.getTime())) { Alert.alert(t("invalidDates")); return; }
    if (startDateParsed >= endDateParsed) { Alert.alert(t("invalidPeriod")); return; }

    const periodChanged = periodStartISO !== activeSheet.periodStartISO || periodEndISO !== activeSheet.periodEndISO;
    if (periodChanged) {
      const existingSheet = state.sheets.find((s) => s.id !== activeSheet.id && s.periodStartISO === periodStartISO && s.periodEndISO === periodEndISO);
      if (existingSheet) { Alert.alert(t("sheetAlreadyExists")); return; }
    }

    const monthStart = startOfMonthISO(startDateParsed);
    const monthEnd = endOfMonthISO(startDateParsed);
    const monthDays = daysBetweenInclusive(monthStart, monthEnd);
    const periodDays = daysBetweenInclusive(periodStartISO, periodEndISO);
    const periodRatio = periodDays / monthDays;
    const shouldProrate = periodRatio < 0.99;

    setState((prev) => {
      if (periodChanged && prev.sheets.find((s) => s.id !== activeSheet.id && s.periodStartISO === periodStartISO && s.periodEndISO === periodEndISO)) return prev;
      const baseSheet = prev.sheets.find((sh) => sh.id === activeSheet.id);
      if (!baseSheet) return prev;
      let pIncome = baseSheet.incomeItems, pFixed = baseSheet.fixedExpenses, pSavings = baseSheet.savingsItems;
      if (shouldProrate) {
        pIncome = baseSheet.incomeItems.map(i => ({ ...i, amount: i.amount * periodRatio }));
        pFixed = baseSheet.fixedExpenses.map(i => ({ ...i, amount: i.amount * periodRatio }));
        pSavings = baseSheet.savingsItems.map(i => ({ ...i, amount: i.amount * periodRatio }));
      }
      return { ...prev, sheets: prev.sheets.map(sh => sh.id === activeSheet.id ? { ...sh, name: sheetName.trim() || sh.name, periodStartISO, periodEndISO, balanceRule: { needsPct: n, wantsPct: w, savingsPct: s }, incomeItems: pIncome, fixedExpenses: pFixed, savingsItems: pSavings } : sh) };
    });
    router.back();
  };

  // Show currency dropdown helpers
  const showIncomeCurrency = shouldShowCurrencyDropdown(incomeList.addForm.inputCurrency, base, usedCurrencies, currenciesInExistingIncome);
  const showFixedCurrency = shouldShowCurrencyDropdown(fixedList.addForm.inputCurrency, base, usedCurrencies, currenciesInExistingFixed);
  const showSavingCurrency = shouldShowCurrencyDropdown(savingsList.addForm.inputCurrency, base, usedCurrencies, currenciesInExistingSaving);
  const showEditingIncomeCurrency = shouldShowCurrencyDropdown(incomeList.editForm.inputCurrency, base, usedCurrencies, currenciesInExistingIncome);
  const showEditingFixedCurrency = shouldShowCurrencyDropdown(fixedList.editForm.inputCurrency, base, usedCurrencies, currenciesInExistingFixed);
  const showEditingSavingCurrency = shouldShowCurrencyDropdown(savingsList.editForm.inputCurrency, base, usedCurrencies, currenciesInExistingSaving);


  return (
    <GlassModalContainer>
      <KeyboardAvoidingView style={{ flex: 1 }} behavior={Platform.OS === "ios" ? "padding" : undefined}>
        <ScrollView
          style={{ flex: 1 }}
          contentInsetAdjustmentBehavior="automatic"
          contentContainerStyle={[styles.container, { paddingTop: 24, paddingBottom: 100 }]}
          keyboardShouldPersistTaps="handled"
        >
      <Text style={[styles.p, { color: theme.subText }]}>Edit your budget sheet settings. Track daily spending safely.</Text>

      <View style={[styles.section, { backgroundColor: theme.surface }]}>
        <Text style={[styles.h2, { color: theme.text }]}>{t("sheetName")}</Text>
        <TextInput value={sheetName} onChangeText={setSheetName} placeholder={t("sheetName")} style={[styles.input, inputStyle]} placeholderTextColor={theme.subText} />
      </View>

      <View style={[styles.section, { backgroundColor: theme.surface }]}>
        <Text style={[styles.h2, { color: theme.text }]}>{t("period")}</Text>
        <Text style={labelStyle}>{t("periodType")}</Text>
        <Dropdown options={[{ label: t("monthly"), value: "month" }, { label: t("customDays"), value: "custom" }]} selectedValue={periodType} onValueChange={handlePeriodTypeChange} theme={theme} style={{ width: "100%" }} />
        {periodType === "custom" && (
          <><Text style={labelStyle}>{t("periodLength")}</Text><TextInput value={String(customPeriodDays)} onChangeText={(txt) => { const d = parseInt(txt, 10); if (!isNaN(d) && d > 0) handleCustomPeriodDaysChange(d); }} keyboardType="numeric" style={[styles.input, inputStyle]} /></>
        )}
        <Text style={labelStyle}>{t("startDate")}</Text>
        <View style={styles.row}>
          <View style={[styles.dropdownCol, styles.dropdownYear]}><Dropdown options={yearOptions.map((y) => ({ label: String(y), value: y }))} selectedValue={selectedYear} onValueChange={(y) => handleStartDateChange(y, selectedMonth, selectedDay)} theme={theme} /></View>
          <View style={[styles.dropdownCol, styles.dropdownMonth]}><Dropdown options={monthOptions.map((m) => ({ label: monthNames[m - 1], value: m }))} selectedValue={selectedMonth} onValueChange={(m) => { const max = getDaysInMonth(selectedYear, m); handleStartDateChange(selectedYear, m, Math.min(selectedDay, max)); }} theme={theme} /></View>
          <View style={styles.dropdownCol}><Dropdown options={dayOptions.map((d) => ({ label: String(d), value: d }))} selectedValue={validSelectedDay} onValueChange={(d) => handleStartDateChange(selectedYear, selectedMonth, d)} theme={theme} /></View>
        </View>
        <Text style={captionStyle}>{t("period")}: {periodStartISO} ~ {periodEndISO}</Text>
      </View>

      {/* Members Section */}
      <View style={[styles.section, { backgroundColor: theme.surface }]}>
        <Text style={[styles.h2, { color: theme.text }]}>{t("members")}</Text>
        <View style={styles.row}>
          <TextInput value={memberList.inputName} onChangeText={memberList.setInputName} placeholder={t("name")} style={[styles.input, inputStyle, { flex: 1 }]} placeholderTextColor={theme.subText} />
          <Pressable onPress={memberList.handleAdd} style={({ pressed }) => [styles.btn, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}><Text style={styles.btnText}>{t("add")}</Text></Pressable>
        </View>
        {state.members.map((m, idx) => (
          memberList.editingId === m.id ? (
            <View key={m.id} style={[styles.listRow2, { backgroundColor: theme.card, borderColor: theme.border }]}>
              <TextInput value={memberList.editingName} onChangeText={memberList.setEditingName} style={[styles.input, inputStyle, { flex: 1 }]} />
              <Pressable onPress={memberList.saveEdit} style={({ pressed }) => [styles.btn, styles.btnSmall, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}><Text style={styles.btnText}>{t("save")}</Text></Pressable>
              <Pressable onPress={memberList.cancelEdit} style={({ pressed }) => [styles.btn, styles.btnSmall, styles.btnCancel, { backgroundColor: theme.surface, borderColor: theme.border }, pressedStyle(pressed)]}><Text style={[styles.btnText, { color: theme.text }]}>{t("cancel")}</Text></Pressable>
            </View>
          ) : (
            <SwipeableRow key={m.id} id={m.id} theme={theme} actions={createDeleteAction(theme, () => memberList.handleDelete(m.id, m.name))} setRef={memberList.setSwipeableRef} onPress={() => memberList.startEdit(m)} rowStyle={styles.listRowWithReorder}>
              <View style={styles.reorderButtons}>
                <Pressable onPress={() => memberList.move(idx, -1)} disabled={!memberList.canMoveUp(idx)} style={[styles.reorderBtn, !memberList.canMoveUp(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↑</Text></Pressable>
                <Pressable onPress={() => memberList.move(idx, 1)} disabled={!memberList.canMoveDown(idx)} style={[styles.reorderBtn, !memberList.canMoveDown(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↓</Text></Pressable>
              </View>
              <Text style={[listTextStyle, { flex: 1 }]}>{m.name}</Text>
            </SwipeableRow>
          )
        ))}
      </View>

      {/* Income Section */}
      <AmountItemSection
        title={t("income")}
        hook={incomeList}
        items={incomeItems}
        theme={theme}
        t={t}
        baseCurrency={base}
        opts={opts}
        namePlaceholder={t("source")}
        getPickerCurrencies={getIncomePickerCurrencies}
        showAddCurrency={showIncomeCurrency}
        showEditCurrency={showEditingIncomeCurrency}
        onMove={moveIncome}
        total={incomeTotal}
      />

      {/* Fixed Expenses Section */}
      <AmountItemSection
        title={t("fixedExpenses")}
        hook={fixedList}
        items={fixedExpenses}
        theme={theme}
        t={t}
        baseCurrency={base}
        opts={opts}
        namePlaceholder={t("item")}
        getPickerCurrencies={getFixedPickerCurrencies}
        showAddCurrency={showFixedCurrency}
        showEditCurrency={showEditingFixedCurrency}
        onMove={moveFixedExpense}
        total={fixedExpensesTotal}
      />

      {/* Savings Section */}
      <AmountItemSection
        title={t("savings")}
        hook={savingsList}
        items={savingsItems}
        theme={theme}
        t={t}
        baseCurrency={base}
        opts={opts}
        namePlaceholder={t("goal")}
        getPickerCurrencies={getSavingPickerCurrencies}
        showAddCurrency={showSavingCurrency}
        showEditCurrency={showEditingSavingCurrency}
        onMove={moveSavings}
        total={savingsTotal}
      />

      {/* Categories Section */}
      <View style={[styles.section, { backgroundColor: theme.surface }]}>
        <Text style={[styles.h2, { color: theme.text }]}>{t("categories")}</Text>
        <View style={styles.row}>
          <TextInput value={categoryList.inputName} onChangeText={categoryList.setInputName} placeholder={t("category")} style={[styles.input, inputStyle, { flex: 1 }]} placeholderTextColor={theme.subText} />
          <Pressable onPress={categoryList.handleAdd} style={({ pressed }) => [styles.btn, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}><Text style={styles.btnText}>{t("add")}</Text></Pressable>
        </View>
        {categories.length > 0 && (
          <Text style={[captionStyle, Math.abs(categoryList.displayCategoryRatioSum - 100) > 0.1 && { color: theme.buttonDanger, fontWeight: "700" }]}>
            {t("total")}: {categoryList.displayCategoryRatioSum.toFixed(1)}% {Math.abs(categoryList.displayCategoryRatioSum - 100) > 0.1 && `(${t("mustBe100")})`}
          </Text>
        )}
        {categories.map((c, idx) => (
          categoryList.editingId === c.id ? (
            <View key={c.id} style={[styles.listRow2, { backgroundColor: theme.card, borderColor: theme.border }]}>
              <TextInput value={categoryList.editingName} onChangeText={categoryList.setEditingName} style={[styles.input, inputStyle, { flex: 1 }]} />
              <TextInput value={categoryList.editingRatio} onChangeText={categoryList.setEditingRatio} keyboardType="numeric" placeholder="%" style={[styles.input, inputStyle, { width: 60 }]} />
              <Pressable onPress={categoryList.saveEdit} style={({ pressed }) => [styles.btn, styles.btnSmall, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}><Text style={styles.btnText}>{t("save")}</Text></Pressable>
              <Pressable onPress={categoryList.cancelEdit} style={({ pressed }) => [styles.btn, styles.btnSmall, styles.btnCancel, { backgroundColor: theme.surface, borderColor: theme.border }, pressedStyle(pressed)]}><Text style={[styles.btnText, { color: theme.text }]}>{t("cancel")}</Text></Pressable>
            </View>
          ) : (
            <SwipeableRow key={c.id} id={c.id} theme={theme} actions={createDeleteAction(theme, () => categoryList.handleDelete(c.id, c.name))} setRef={categoryList.setSwipeableRef} onPress={() => categoryList.startEdit(c)} rowStyle={styles.listRowWithReorder}>
              <View style={styles.reorderButtons}>
                <Pressable onPress={() => categoryList.move(idx, -1)} disabled={!categoryList.canMoveUp(idx)} style={[styles.reorderBtn, !categoryList.canMoveUp(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↑</Text></Pressable>
                <Pressable onPress={() => categoryList.move(idx, 1)} disabled={!categoryList.canMoveDown(idx)} style={[styles.reorderBtn, !categoryList.canMoveDown(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↓</Text></Pressable>
              </View>
              <Text style={[listTextStyle, { flex: 1 }]}>{c.name}</Text>
              <Text style={listTextStyle}>{(c.ratio * 100).toFixed(0)}%</Text>
            </SwipeableRow>
          )
        ))}
      </View>

      {/* Ideal Balance Section */}
      <View style={[styles.section, { backgroundColor: theme.surface }]}>
        <Text style={[styles.h2, { color: theme.text }]}>{t("idealBalance")}</Text>
        <View style={styles.grid}>
          <View style={styles.gridItem}><Text style={labelStyle}>{t("needsPercent")}</Text><TextInput value={needsPct} onChangeText={setNeedsPct} keyboardType="numeric" style={[styles.input, inputStyle]} /></View>
          <View style={styles.gridItem}><Text style={labelStyle}>{t("wantsPercent")}</Text><TextInput value={wantsPct} onChangeText={setWantsPct} keyboardType="numeric" style={[styles.input, inputStyle]} /></View>
          <View style={styles.gridItem}><Text style={labelStyle}>{t("savingsPercent")}</Text><TextInput value={savingsPct} onChangeText={setSavingsPct} keyboardType="numeric" style={[styles.input, inputStyle]} /></View>
        </View>
        <Text style={captionStyle}>{t("total")}: {pctSum}%</Text>
      </View>
        </ScrollView>
        <View style={[styles.saveBar, { backgroundColor: 'transparent', paddingBottom: 12 + insets.bottom }]}>
          <Pressable onPress={save} style={({ pressed }) => [styles.btn, styles.saveBtn, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}><Text style={styles.btnText}>{t("saveSettings")}</Text></Pressable>
        </View>
      </KeyboardAvoidingView>
    </GlassModalContainer>
  );
}

const styles = StyleSheet.create({
  ...sharedStyles.layout,
  ...sharedStyles.typography,
  ...sharedStyles.form,
  ...sharedStyles.button,
  ...sharedStyles.list,
  // Local overrides
  container: { padding: 20, gap: 12, paddingBottom: 40, flexGrow: 1 },
  dropdownYear: { flex: 1.2 },
  dropdownMonth: { flex: 1.2 },
});

import { useRouter } from "expo-router";
import React, { useEffect, useMemo, useState } from "react";
import { Alert, KeyboardAvoidingView, Platform, Pressable, ScrollView, StyleSheet, Text, TextInput, View } from "react-native";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { AmountItemSection } from "../components/amount-item-section";
import { Dropdown } from "../components/dropdown";
import { GlassModalContainer } from "../components/glass-modal-container";
import { SwipeableRow, createDeleteAction } from "../components/swipeable-row";
import { sharedStyles } from "../constants/sharedStyles";
import { useModalTheme } from "../hooks/use-modal-theme";
import { useFormStyles } from "../hooks/use-form-styles";
import { pressedStyle } from "../hooks/use-themed-styles";
import { useLanguage } from "../hooks/use-language";
import { useSetupAmountItem, useSetupSimpleList, useSetupCategoryList } from "../hooks/setup";
import { getPickerCurrencies, shouldShowCurrencyDropdown } from "../src/currency-input";
import { useStore } from "../src/store";
import { FixedExpenseItem, IncomeItem, Member, SavingItem, Sheet } from "../src/types";
import {
  clamp,
  daysBetweenInclusive,
  endOfMonthISO,
  itemAmountToBaseForSum,
  parseLocalDate,
  startOfMonthISO,
  uuid,
} from "../src/utils";

export default function SetupScreen() {
  const router = useRouter();
  const insets = useSafeAreaInsets();
  const { state, setState, activeSheet, rateCache, fillRateCacheForActiveSheet } = useStore();
  useEffect(() => {
    if (activeSheet) fillRateCacheForActiveSheet();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeSheet?.id, fillRateCacheForActiveSheet]);
  const theme = useAppTheme();
  const { t } = useLanguage();
  const { labelStyle, captionStyle, inputStyle, listTextStyle } = useFormStyles(theme);

  const [sheetName, setSheetName] = useState("");

  useEffect(() => {
    if (activeSheet?.name) setSheetName(activeSheet.name);
  }, [activeSheet?.name]);

  const base = state.baseCurrency;
  const periodStart = activeSheet?.periodStartISO ?? "";
  const opts = { rateCache, dateISO: periodStart };

  // Helper to update the active sheet, reducing repetitive setState patterns
  const updateActiveSheet = (updater: (sheet: Sheet) => Partial<Sheet>) => {
    setState((prev) => ({
      ...prev,
      sheets: prev.sheets.map((sh) =>
        sh.id === activeSheet?.id ? { ...sh, ...updater(sh) } : sh
      ),
    }));
  };

  // Period state
  const initialStartDate = activeSheet?.periodStartISO ?? startOfMonthISO(new Date());
  const initialEndDate = activeSheet?.periodEndISO ?? endOfMonthISO(new Date());
  const [periodStartISO, setPeriodStartISO] = useState(initialStartDate);
  const [periodEndISO, setPeriodEndISO] = useState(initialEndDate);

  const startDate = parseLocalDate(periodStartISO);
  const [selectedYear, setSelectedYear] = useState(startDate.getFullYear());
  const [selectedMonth, setSelectedMonth] = useState(startDate.getMonth() + 1);
  const [selectedDay, setSelectedDay] = useState(startDate.getDate());

  const determinePeriodType = (startISO: string, endISO: string): "month" | "custom" => {
    const start = parseLocalDate(startISO);
    const end = parseLocalDate(endISO);
    const monthEnd = new Date(start.getFullYear(), start.getMonth() + 1, 0);
    return end.getTime() === monthEnd.getTime() ? "month" : "custom";
  };

  const initialPeriodType = determinePeriodType(initialStartDate, initialEndDate);
  const [periodType, setPeriodType] = useState<"month" | "custom">(initialPeriodType);
  const [customPeriodDays, setCustomPeriodDays] = useState(daysBetweenInclusive(initialStartDate, initialEndDate));

  const currentYear = new Date().getFullYear();
  const yearOptions = Array.from({ length: 5 }, (_, i) => currentYear - 2 + i);
  const monthOptions = Array.from({ length: 12 }, (_, i) => i + 1);
  const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
  const getDaysInMonth = (year: number, month: number) => new Date(year, month, 0).getDate();
  const daysInSelectedMonth = getDaysInMonth(selectedYear, selectedMonth);
  const validSelectedDay = Math.min(selectedDay, daysInSelectedMonth);
  const dayOptions = Array.from({ length: daysInSelectedMonth }, (_, i) => i + 1);

  const updateEndDate = (startISO: string, pType: "month" | "custom", customDays: number) => {
    const start = parseLocalDate(startISO);
    let end: Date;
    if (pType === "month") {
      end = new Date(start.getFullYear(), start.getMonth() + 1, 0);
    } else {
      end = new Date(start);
      end.setDate(start.getDate() + customDays - 1);
    }
    setPeriodEndISO(`${end.getFullYear()}-${String(end.getMonth() + 1).padStart(2, "0")}-${String(end.getDate()).padStart(2, "0")}`);
  };

  const handleStartDateChange = (year: number, month: number, day: number) => {
    const newStart = `${year}-${String(month).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
    setPeriodStartISO(newStart);
    setSelectedYear(year);
    setSelectedMonth(month);
    setSelectedDay(day);
    updateEndDate(newStart, periodType, customPeriodDays);
  };

  const handlePeriodTypeChange = (type: "month" | "custom") => {
    setPeriodType(type);
    updateEndDate(periodStartISO, type, customPeriodDays);
  };

  const handleCustomPeriodDaysChange = (days: number) => {
    setCustomPeriodDays(days);
    updateEndDate(periodStartISO, "custom", days);
  };

  // Balance rule state
  const [needsPct, setNeedsPct] = useState(String(Math.round((activeSheet?.balanceRule.needsPct ?? 0.5) * 100)));
  const [wantsPct, setWantsPct] = useState(String(Math.round((activeSheet?.balanceRule.wantsPct ?? 0.3) * 100)));
  const [savingsPct, setSavingsPct] = useState(String(Math.round((activeSheet?.balanceRule.savingsPct ?? 0.2) * 100)));
  const pctSum = useMemo(() => (Number(needsPct) || 0) + (Number(wantsPct) || 0) + (Number(savingsPct) || 0), [needsPct, wantsPct, savingsPct]);

  // Data from active sheet (memoized to avoid re-renders from ?? creating new arrays)
  const incomeItems = useMemo(() => activeSheet?.incomeItems ?? [], [activeSheet]);
  const categories = useMemo(() => activeSheet?.categories ?? [], [activeSheet]);
  const fixedExpenses = useMemo(() => activeSheet?.fixedExpenses ?? [], [activeSheet]);
  const savingsItems = useMemo(() => activeSheet?.savingsItems ?? [], [activeSheet]);

  // Currency picker helpers
  const usedCurrencies = state.usedCurrencies ?? [];
  const currenciesInExistingIncome = useMemo(() => [...new Set(incomeItems.map((it) => it.inputCurrency ?? base).filter((c) => c !== base))], [incomeItems, base]);
  const currenciesInExistingFixed = useMemo(() => [...new Set(fixedExpenses.map((it) => it.inputCurrency ?? base).filter((c) => c !== base))], [fixedExpenses, base]);
  const currenciesInExistingSaving = useMemo(() => [...new Set(savingsItems.map((it) => it.inputCurrency ?? base).filter((c) => c !== base))], [savingsItems, base]);

  const getIncomePickerCurrencies = (current?: string) => getPickerCurrencies(base, [...usedCurrencies, ...currenciesInExistingIncome], current);
  const getFixedPickerCurrencies = (current?: string) => getPickerCurrencies(base, [...usedCurrencies, ...currenciesInExistingFixed], current);
  const getSavingPickerCurrencies = (current?: string) => getPickerCurrencies(base, [...usedCurrencies, ...currenciesInExistingSaving], current);

  // Member list management
  const memberList = useSetupSimpleList<Member>({
    items: state.members,
    onAdd: (member) => setState((prev) => ({ ...prev, members: [...prev.members, member] })),
    onUpdate: (id, updates) => setState((prev) => ({ ...prev, members: prev.members.map((m) => (m.id === id ? { ...m, ...updates } : m)) })),
    onDelete: (id) => setState((prev) => ({ ...prev, members: prev.members.filter((m) => m.id !== id) })),
    onReorder: (members) => setState((prev) => ({ ...prev, members })),
    createItem: (name) => ({ id: uuid(), name }),
    deleteTitle: "Delete Member",
  });

  // Income list management
  const incomeList = useSetupAmountItem({
    baseCurrency: base,
    periodStartISO,
    onAdd: (item) => updateActiveSheet((sh) => ({ incomeItems: [...(sh.incomeItems ?? []), item as IncomeItem] })),
    onUpdate: (id, updates) => updateActiveSheet((sh) => ({ incomeItems: (sh.incomeItems ?? []).map((it) => it.id === id ? { ...it, ...updates } : it) })),
    onDelete: (id) => updateActiveSheet((sh) => ({ incomeItems: (sh.incomeItems ?? []).filter((it) => it.id !== id) })),
    t,
  });

  // Fixed expenses list management
  const fixedList = useSetupAmountItem({
    baseCurrency: base,
    periodStartISO,
    onAdd: (item) => updateActiveSheet((sh) => ({ fixedExpenses: [...(sh.fixedExpenses ?? []), item as FixedExpenseItem] })),
    onUpdate: (id, updates) => updateActiveSheet((sh) => ({ fixedExpenses: (sh.fixedExpenses ?? []).map((it) => it.id === id ? { ...it, ...updates } : it) })),
    onDelete: (id) => updateActiveSheet((sh) => ({ fixedExpenses: (sh.fixedExpenses ?? []).filter((it) => it.id !== id) })),
    t,
  });

  // Savings list management
  const savingsList = useSetupAmountItem({
    baseCurrency: base,
    periodStartISO,
    onAdd: (item) => updateActiveSheet((sh) => ({ savingsItems: [...(sh.savingsItems ?? []), item as SavingItem] })),
    onUpdate: (id, updates) => updateActiveSheet((sh) => ({ savingsItems: (sh.savingsItems ?? []).map((it) => it.id === id ? { ...it, ...updates } : it) })),
    onDelete: (id) => updateActiveSheet((sh) => ({ savingsItems: (sh.savingsItems ?? []).filter((it) => it.id !== id) })),
    t,
  });

  // Category list management
  const categoryList = useSetupCategoryList({
    categories,
    onAdd: (cat) => updateActiveSheet(() => ({ categories: [...(categories ?? []), cat] })),
    onUpdate: (id, updates) => updateActiveSheet((sh) => ({ categories: (sh.categories ?? []).map((c) => c.id === id ? { ...c, ...updates } : c) })),
    onDelete: (id) => updateActiveSheet((sh) => ({ categories: (sh.categories ?? []).filter((c) => c.id !== id) })),
    onReorder: (cats) => updateActiveSheet(() => ({ categories: cats })),
  });

  // Income reordering
  const moveIncome = (fromIdx: number, direction: 1 | -1) => {
    const toIdx = fromIdx + direction;
    if (toIdx < 0 || toIdx >= incomeItems.length) return;
    const arr = [...incomeItems];
    [arr[fromIdx], arr[toIdx]] = [arr[toIdx], arr[fromIdx]];
    updateActiveSheet(() => ({ incomeItems: arr }));
  };

  // Fixed expense reordering
  const moveFixedExpense = (fromIdx: number, direction: 1 | -1) => {
    const toIdx = fromIdx + direction;
    if (toIdx < 0 || toIdx >= fixedExpenses.length) return;
    const arr = [...fixedExpenses];
    [arr[fromIdx], arr[toIdx]] = [arr[toIdx], arr[fromIdx]];
    updateActiveSheet(() => ({ fixedExpenses: arr }));
  };

  // Savings reordering
  const moveSavings = (fromIdx: number, direction: 1 | -1) => {
    const toIdx = fromIdx + direction;
    if (toIdx < 0 || toIdx >= savingsItems.length) return;
    const arr = [...savingsItems];
    [arr[fromIdx], arr[toIdx]] = [arr[toIdx], arr[fromIdx]];
    updateActiveSheet(() => ({ savingsItems: arr }));
  };

  // Reset currencies when base changes
  useEffect(() => {
    incomeList.resetCurrencies(base);
    fixedList.resetCurrencies(base);
    savingsList.resetCurrencies(base);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [base]);

  // Totals
  const incomeTotal = useMemo(() => {
    const opts = { rateCache, dateISO: periodStart };
    return incomeItems.reduce((a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts), 0);
  }, [incomeItems, base, rateCache, periodStart]);
  const fixedExpensesTotal = useMemo(() => {
    const opts = { rateCache, dateISO: periodStart };
    return fixedExpenses.reduce((a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts), 0);
  }, [fixedExpenses, base, rateCache, periodStart]);
  const savingsTotal = useMemo(() => {
    const opts = { rateCache, dateISO: periodStart };
    return savingsItems.reduce((a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts), 0);
  }, [savingsItems, base, rateCache, periodStart]);

  if (!activeSheet) return <View style={[styles.center, { backgroundColor: theme.background }]}><Text style={{ color: theme.text }}>{t("loading")}</Text></View>;

  const save = () => {
    if (state.members.length === 0) { Alert.alert(t("addMember"), t("addMemberFirst")); return; }
    if (incomeTotal <= 0) { Alert.alert(t("addIncome"), t("addIncomeFirst")); return; }
    if (categories.length === 0) { Alert.alert(t("addCategories"), t("addCategoriesFirst")); return; }
    const n = clamp((Number(needsPct) || 0) / 100, 0, 1);
    const w = clamp((Number(wantsPct) || 0) / 100, 0, 1);
    const s = clamp((Number(savingsPct) || 0) / 100, 0, 1);
    if (Math.abs(n + w + s - 1) > 0.001) { Alert.alert(t("totalMustBe100"), t("currentTotal", { total: pctSum })); return; }
    const catRatioTotal = categories.reduce((sum, c) => sum + c.ratio, 0);
    if (categories.length > 0 && Math.abs(catRatioTotal - 1) > 0.001) { Alert.alert(t("categoryRatiosMust100"), t("currentTotal", { total: categoryList.categoryRatioSum.toFixed(1) })); return; }

    const startDateParsed = parseLocalDate(periodStartISO);
    const endDateParsed = parseLocalDate(periodEndISO);
    if (isNaN(startDateParsed.getTime()) || isNaN(endDateParsed.getTime())) { Alert.alert(t("invalidDates")); return; }
    if (startDateParsed >= endDateParsed) { Alert.alert(t("invalidPeriod")); return; }

    const periodChanged = periodStartISO !== activeSheet.periodStartISO || periodEndISO !== activeSheet.periodEndISO;
    if (periodChanged) {
      const existingSheet = state.sheets.find((s) => s.id !== activeSheet.id && s.periodStartISO === periodStartISO && s.periodEndISO === periodEndISO);
      if (existingSheet) { Alert.alert(t("sheetAlreadyExists")); return; }
    }

    const monthStart = startOfMonthISO(startDateParsed);
    const monthEnd = endOfMonthISO(startDateParsed);
    const monthDays = daysBetweenInclusive(monthStart, monthEnd);
    const periodDays = daysBetweenInclusive(periodStartISO, periodEndISO);
    const periodRatio = periodDays / monthDays;
    const shouldProrate = periodRatio < 0.99;

    setState((prev) => {
      if (periodChanged && prev.sheets.find((s) => s.id !== activeSheet.id && s.periodStartISO === periodStartISO && s.periodEndISO === periodEndISO)) return prev;
      const baseSheet = prev.sheets.find((sh) => sh.id === activeSheet.id);
      if (!baseSheet) return prev;
      let pIncome = baseSheet.incomeItems, pFixed = baseSheet.fixedExpenses, pSavings = baseSheet.savingsItems;
      if (shouldProrate) {
        pIncome = baseSheet.incomeItems.map(i => ({ ...i, amount: i.amount * periodRatio }));
        pFixed = baseSheet.fixedExpenses.map(i => ({ ...i, amount: i.amount * periodRatio }));
        pSavings = baseSheet.savingsItems.map(i => ({ ...i, amount: i.amount * periodRatio }));
      }
      return { ...prev, sheets: prev.sheets.map(sh => sh.id === activeSheet.id ? { ...sh, name: sheetName.trim() || sh.name, periodStartISO, periodEndISO, balanceRule: { needsPct: n, wantsPct: w, savingsPct: s }, incomeItems: pIncome, fixedExpenses: pFixed, savingsItems: pSavings } : sh) };
    });
    router.back();
  };

  // Show currency dropdown helpers
  const showIncomeCurrency = shouldShowCurrencyDropdown(incomeList.addForm.inputCurrency, base, usedCurrencies, currenciesInExistingIncome);
  const showFixedCurrency = shouldShowCurrencyDropdown(fixedList.addForm.inputCurrency, base, usedCurrencies, currenciesInExistingFixed);
  const showSavingCurrency = shouldShowCurrencyDropdown(savingsList.addForm.inputCurrency, base, usedCurrencies, currenciesInExistingSaving);
  const showEditingIncomeCurrency = shouldShowCurrencyDropdown(incomeList.editForm.inputCurrency, base, usedCurrencies, currenciesInExistingIncome);
  const showEditingFixedCurrency = shouldShowCurrencyDropdown(fixedList.editForm.inputCurrency, base, usedCurrencies, currenciesInExistingFixed);
  const showEditingSavingCurrency = shouldShowCurrencyDropdown(savingsList.editForm.inputCurrency, base, usedCurrencies, currenciesInExistingSaving);


  return (
    <GlassModalContainer>
      <KeyboardAvoidingView style={{ flex: 1 }} behavior={Platform.OS === "ios" ? "padding" : undefined}>
        <ScrollView
          style={{ flex: 1 }}
          contentInsetAdjustmentBehavior="automatic"
          contentContainerStyle={[styles.container, { paddingTop: 24, paddingBottom: 100 }]}
          keyboardShouldPersistTaps="handled"
        >
      <Text style={[styles.p, { color: theme.subText }]}>Edit your budget sheet settings. Track daily spending safely.</Text>

      <View style={[styles.section, { backgroundColor: theme.surface }]}>
        <Text style={[styles.h2, { color: theme.text }]}>{t("sheetName")}</Text>
        <TextInput value={sheetName} onChangeText={setSheetName} placeholder={t("sheetName")} style={[styles.input, inputStyle]} placeholderTextColor={theme.subText} />
      </View>

      <View style={[styles.section, { backgroundColor: theme.surface }]}>
        <Text style={[styles.h2, { color: theme.text }]}>{t("period")}</Text>
        <Text style={labelStyle}>{t("periodType")}</Text>
        <Dropdown options={[{ label: t("monthly"), value: "month" }, { label: t("customDays"), value: "custom" }]} selectedValue={periodType} onValueChange={handlePeriodTypeChange} theme={theme} style={{ width: "100%" }} />
        {periodType === "custom" && (
          <><Text style={labelStyle}>{t("periodLength")}</Text><TextInput value={String(customPeriodDays)} onChangeText={(txt) => { const d = parseInt(txt, 10); if (!isNaN(d) && d > 0) handleCustomPeriodDaysChange(d); }} keyboardType="numeric" style={[styles.input, inputStyle]} /></>
        )}
        <Text style={labelStyle}>{t("startDate")}</Text>
        <View style={styles.row}>
          <View style={[styles.dropdownCol, styles.dropdownYear]}><Dropdown options={yearOptions.map((y) => ({ label: String(y), value: y }))} selectedValue={selectedYear} onValueChange={(y) => handleStartDateChange(y, selectedMonth, selectedDay)} theme={theme} /></View>
          <View style={[styles.dropdownCol, styles.dropdownMonth]}><Dropdown options={monthOptions.map((m) => ({ label: monthNames[m - 1], value: m }))} selectedValue={selectedMonth} onValueChange={(m) => { const max = getDaysInMonth(selectedYear, m); handleStartDateChange(selectedYear, m, Math.min(selectedDay, max)); }} theme={theme} /></View>
          <View style={styles.dropdownCol}><Dropdown options={dayOptions.map((d) => ({ label: String(d), value: d }))} selectedValue={validSelectedDay} onValueChange={(d) => handleStartDateChange(selectedYear, selectedMonth, d)} theme={theme} /></View>
        </View>
        <Text style={captionStyle}>{t("period")}: {periodStartISO} ~ {periodEndISO}</Text>
      </View>

      {/* Members Section */}
      <View style={[styles.section, { backgroundColor: theme.surface }]}>
        <Text style={[styles.h2, { color: theme.text }]}>{t("members")}</Text>
        <View style={styles.row}>
          <TextInput value={memberList.inputName} onChangeText={memberList.setInputName} placeholder={t("name")} style={[styles.input, inputStyle, { flex: 1 }]} placeholderTextColor={theme.subText} />
          <Pressable onPress={memberList.handleAdd} style={({ pressed }) => [styles.btn, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}><Text style={styles.btnText}>{t("add")}</Text></Pressable>
        </View>
        {state.members.map((m, idx) => (
          memberList.editingId === m.id ? (
            <View key={m.id} style={[styles.listRow2, { backgroundColor: theme.card, borderColor: theme.border }]}>
              <TextInput value={memberList.editingName} onChangeText={memberList.setEditingName} style={[styles.input, inputStyle, { flex: 1 }]} />
              <Pressable onPress={memberList.saveEdit} style={({ pressed }) => [styles.btn, styles.btnSmall, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}><Text style={styles.btnText}>{t("save")}</Text></Pressable>
              <Pressable onPress={memberList.cancelEdit} style={({ pressed }) => [styles.btn, styles.btnSmall, styles.btnCancel, { backgroundColor: theme.surface, borderColor: theme.border }, pressedStyle(pressed)]}><Text style={[styles.btnText, { color: theme.text }]}>{t("cancel")}</Text></Pressable>
            </View>
          ) : (
            <SwipeableRow key={m.id} id={m.id} theme={theme} actions={createDeleteAction(theme, () => memberList.handleDelete(m.id, m.name))} setRef={memberList.setSwipeableRef} onPress={() => memberList.startEdit(m)} rowStyle={styles.listRowWithReorder}>
              <View style={styles.reorderButtons}>
                <Pressable onPress={() => memberList.move(idx, -1)} disabled={!memberList.canMoveUp(idx)} style={[styles.reorderBtn, !memberList.canMoveUp(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↑</Text></Pressable>
                <Pressable onPress={() => memberList.move(idx, 1)} disabled={!memberList.canMoveDown(idx)} style={[styles.reorderBtn, !memberList.canMoveDown(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↓</Text></Pressable>
              </View>
              <Text style={[listTextStyle, { flex: 1 }]}>{m.name}</Text>
            </SwipeableRow>
          )
        ))}
      </View>

      {/* Income Section */}
      <AmountItemSection
        title={t("income")}
        hook={incomeList}
        items={incomeItems}
        theme={theme}
        t={t}
        baseCurrency={base}
        opts={opts}
        namePlaceholder={t("source")}
        getPickerCurrencies={getIncomePickerCurrencies}
        showAddCurrency={showIncomeCurrency}
        showEditCurrency={showEditingIncomeCurrency}
        onMove={moveIncome}
        total={incomeTotal}
      />

      {/* Fixed Expenses Section */}
      <AmountItemSection
        title={t("fixedExpenses")}
        hook={fixedList}
        items={fixedExpenses}
        theme={theme}
        t={t}
        baseCurrency={base}
        opts={opts}
        namePlaceholder={t("item")}
        getPickerCurrencies={getFixedPickerCurrencies}
        showAddCurrency={showFixedCurrency}
        showEditCurrency={showEditingFixedCurrency}
        onMove={moveFixedExpense}
        total={fixedExpensesTotal}
      />

      {/* Savings Section */}
      <AmountItemSection
        title={t("savings")}
        hook={savingsList}
        items={savingsItems}
        theme={theme}
        t={t}
        baseCurrency={base}
        opts={opts}
        namePlaceholder={t("goal")}
        getPickerCurrencies={getSavingPickerCurrencies}
        showAddCurrency={showSavingCurrency}
        showEditCurrency={showEditingSavingCurrency}
        onMove={moveSavings}
        total={savingsTotal}
      />

      {/* Categories Section */}
      <View style={[styles.section, { backgroundColor: theme.surface }]}>
        <Text style={[styles.h2, { color: theme.text }]}>{t("categories")}</Text>
        <View style={styles.row}>
          <TextInput value={categoryList.inputName} onChangeText={categoryList.setInputName} placeholder={t("category")} style={[styles.input, inputStyle, { flex: 1 }]} placeholderTextColor={theme.subText} />
          <Pressable onPress={categoryList.handleAdd} style={({ pressed }) => [styles.btn, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}><Text style={styles.btnText}>{t("add")}</Text></Pressable>
        </View>
        {categories.length > 0 && (
          <Text style={[captionStyle, Math.abs(categoryList.displayCategoryRatioSum - 100) > 0.1 && { color: theme.buttonDanger, fontWeight: "700" }]}>
            {t("total")}: {categoryList.displayCategoryRatioSum.toFixed(1)}% {Math.abs(categoryList.displayCategoryRatioSum - 100) > 0.1 && `(${t("mustBe100")})`}
          </Text>
        )}
        {categories.map((c, idx) => (
          categoryList.editingId === c.id ? (
            <View key={c.id} style={[styles.listRow2, { backgroundColor: theme.card, borderColor: theme.border }]}>
              <TextInput value={categoryList.editingName} onChangeText={categoryList.setEditingName} style={[styles.input, inputStyle, { flex: 1 }]} />
              <TextInput value={categoryList.editingRatio} onChangeText={categoryList.setEditingRatio} keyboardType="numeric" placeholder="%" style={[styles.input, inputStyle, { width: 60 }]} />
              <Pressable onPress={categoryList.saveEdit} style={({ pressed }) => [styles.btn, styles.btnSmall, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}><Text style={styles.btnText}>{t("save")}</Text></Pressable>
              <Pressable onPress={categoryList.cancelEdit} style={({ pressed }) => [styles.btn, styles.btnSmall, styles.btnCancel, { backgroundColor: theme.surface, borderColor: theme.border }, pressedStyle(pressed)]}><Text style={[styles.btnText, { color: theme.text }]}>{t("cancel")}</Text></Pressable>
            </View>
          ) : (
            <SwipeableRow key={c.id} id={c.id} theme={theme} actions={createDeleteAction(theme, () => categoryList.handleDelete(c.id, c.name))} setRef={categoryList.setSwipeableRef} onPress={() => categoryList.startEdit(c)} rowStyle={styles.listRowWithReorder}>
              <View style={styles.reorderButtons}>
                <Pressable onPress={() => categoryList.move(idx, -1)} disabled={!categoryList.canMoveUp(idx)} style={[styles.reorderBtn, !categoryList.canMoveUp(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↑</Text></Pressable>
                <Pressable onPress={() => categoryList.move(idx, 1)} disabled={!categoryList.canMoveDown(idx)} style={[styles.reorderBtn, !categoryList.canMoveDown(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↓</Text></Pressable>
              </View>
              <Text style={[listTextStyle, { flex: 1 }]}>{c.name}</Text>
              <Text style={listTextStyle}>{(c.ratio * 100).toFixed(0)}%</Text>
            </SwipeableRow>
          )
        ))}
      </View>

      {/* Ideal Balance Section */}
      <View style={[styles.section, { backgroundColor: theme.surface }]}>
        <Text style={[styles.h2, { color: theme.text }]}>{t("idealBalance")}</Text>
        <View style={styles.grid}>
          <View style={styles.gridItem}><Text style={labelStyle}>{t("needsPercent")}</Text><TextInput value={needsPct} onChangeText={setNeedsPct} keyboardType="numeric" style={[styles.input, inputStyle]} /></View>
          <View style={styles.gridItem}><Text style={labelStyle}>{t("wantsPercent")}</Text><TextInput value={wantsPct} onChangeText={setWantsPct} keyboardType="numeric" style={[styles.input, inputStyle]} /></View>
          <View style={styles.gridItem}><Text style={labelStyle}>{t("savingsPercent")}</Text><TextInput value={savingsPct} onChangeText={setSavingsPct} keyboardType="numeric" style={[styles.input, inputStyle]} /></View>
        </View>
        <Text style={captionStyle}>{t("total")}: {pctSum}%</Text>
      </View>
        </ScrollView>
        <View style={[styles.saveBar, { backgroundColor: 'transparent', paddingBottom: 12 + insets.bottom }]}>
          <Pressable onPress={save} style={({ pressed }) => [styles.btn, styles.saveBtn, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}><Text style={styles.btnText}>{t("saveSettings")}</Text></Pressable>
        </View>
      </KeyboardAvoidingView>
    </GlassModalContainer>
  );
}

const styles = StyleSheet.create({
  ...sharedStyles.layout,
  ...sharedStyles.typography,
  ...sharedStyles.form,
  ...sharedStyles.button,
  ...sharedStyles.list,
  // Local overrides
  container: { padding: 20, gap: 12, paddingBottom: 40, flexGrow: 1 },
  dropdownYear: { flex: 1.2 },
  dropdownMonth: { flex: 1.2 },
});

