import { useFocusEffect, useRouter } from "expo-router";
import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useNavigation } from "@react-navigation/native";
import {
  Alert,
  KeyboardAvoidingView,
  Platform,
  Pressable,
  ScrollView,
  StyleSheet,
  Text,
  TextInput,
  View,
} from "react-native";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { sharedStyles } from "../constants/sharedStyles";
import { AmountItemSection } from "../components/amount-item-section";
import { Dropdown } from "../components/dropdown";
import { GlassModalContainer } from "../components/glass-modal-container";
import { SwipeableRow, createDeleteAction } from "../components/swipeable-row";
import { useAppTheme } from "../hooks/use-app-theme";
import { useFormStyles } from "../hooks/use-form-styles";
import { pressedStyle } from "../hooks/use-themed-styles";
import { useLanguage } from "../hooks/use-language";
import { usePeriodForm, useAmountItemList } from "../hooks/create-sheet";
import { useSetupSimpleList, useSetupCategoryList } from "../hooks/setup";
import { useStore } from "../src/store";
import { Category, Member, Sheet } from "../src/types";
import {
  clamp,
  daysBetweenInclusive,
  formatMoney,
  itemAmountToBaseForSum,
  parseLocalDate,
  startOfMonthISO,
  endOfMonthISO,
  toISODateTime,
  uuid,
} from "../src/utils";

export default function CreateSheetScreen() {
  const router = useRouter();
  const navigation = useNavigation();
  const { state, setState, activeSheet, rateCache, fillRateCacheForActiveSheet } = useStore();
  const theme = useAppTheme();
  const hasUnsavedChangesRef = useRef(false);
  const allowCloseRef = useRef(false);
  const isFirstRenderRef = useRef(true);
  const saveRef = useRef<() => void>(() => {});
  const insets = useSafeAreaInsets();

  useFocusEffect(
    useCallback(() => {
      if (activeSheet) fillRateCacheForActiveSheet();
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeSheet?.id, fillRateCacheForActiveSheet])
  );
  const { t } = useLanguage();
  const { labelStyle, captionStyle, inputStyle, listTextStyle } = useFormStyles(theme);

  const lastSheet = state.sheets[0] ?? null;
  const base = state.baseCurrency;
  const usedCurrencies = state.usedCurrencies ?? [];

  // Period form
  const period = usePeriodForm();

  // Members - using shared hook with global state callbacks
  const members = useSetupSimpleList<Member>({
    items: state.members,
    onAdd: (m) => setState((p) => ({ ...p, members: [...p.members, m] })),
    onUpdate: (id, updates) =>
      setState((p) => ({ ...p, members: p.members.map((m) => (m.id === id ? { ...m, ...updates } : m)) })),
    onDelete: (id) => setState((p) => ({ ...p, members: p.members.filter((m) => m.id !== id) })),
    onReorder: (reordered) => setState((p) => ({ ...p, members: reordered })),
    createItem: (name) => ({ id: uuid(), name, updatedAt: toISODateTime(new Date()) }),
    deleteTitle: "Delete Member",
  });

  // Income items
  const income = useAmountItemList({
    initialItems: lastSheet?.incomeItems ? lastSheet.incomeItems.map((i) => ({ ...i, id: uuid() })) : [],
    baseCurrency: base,
    usedCurrencies,
    dateISO: period.periodStartISO,
    itemLabel: "Income",
  });

  // Fixed expenses
  const fixed = useAmountItemList({
    initialItems: lastSheet?.fixedExpenses ? lastSheet.fixedExpenses.map((i) => ({ ...i, id: uuid() })) : [],
    baseCurrency: base,
    usedCurrencies,
    dateISO: period.periodStartISO,
    itemLabel: "Fixed Expense",
  });

  // Savings
  const savings = useAmountItemList({
    initialItems: lastSheet?.savingsItems ? lastSheet.savingsItems.map((i) => ({ ...i, id: uuid() })) : [],
    baseCurrency: base,
    usedCurrencies,
    dateISO: period.periodStartISO,
    itemLabel: "Saving",
  });

  // Categories - local state with shared hook
  const defaultCategories: Category[] = [
    { id: uuid(), name: "Groceries", ratio: 0.35 },
    { id: uuid(), name: "Home Supplies", ratio: 0.1 },
    { id: uuid(), name: "Kids Supplies", ratio: 0.1 },
    { id: uuid(), name: "Eating Out", ratio: 0.05 },
    { id: uuid(), name: "Electronics", ratio: 0.07 },
    { id: uuid(), name: "Transport", ratio: 0.05 },
    { id: uuid(), name: "Business Expenses", ratio: 0.05 },
    { id: uuid(), name: "Clothing", ratio: 0.05 },
    { id: uuid(), name: "Personal Care", ratio: 0.1 },
    { id: uuid(), name: "Medical", ratio: 0.03 },
    { id: uuid(), name: "Other", ratio: 0.05 },
  ];
  const [localCategories, setLocalCategories] = useState<Category[]>(
    lastSheet?.categories ? lastSheet.categories.map((c) => ({ ...c })) : defaultCategories
  );
  const categories = useSetupCategoryList({
    categories: localCategories,
    onAdd: (c) => setLocalCategories((p) => [...p, c]),
    onUpdate: (id, updates) => setLocalCategories((p) => p.map((c) => (c.id === id ? { ...c, ...updates } : c))),
    onDelete: (id) => setLocalCategories((p) => p.filter((c) => c.id !== id)),
    onReorder: setLocalCategories,
  });

  // Balance rule
  const [needsPct, setNeedsPct] = useState(String(Math.round((lastSheet?.balanceRule.needsPct ?? 0.5) * 100)));
  const [wantsPct, setWantsPct] = useState(String(Math.round((lastSheet?.balanceRule.wantsPct ?? 0.3) * 100)));
  const [savingsPct, setSavingsPct] = useState(String(Math.round((lastSheet?.balanceRule.savingsPct ?? 0.2) * 100)));

  // Track unsaved changes
  useEffect(() => {
    if (isFirstRenderRef.current) {
      isFirstRenderRef.current = false;
      return;
    }
    hasUnsavedChangesRef.current = true;
  }, [
    period.sheetName,
    income.items.length,
    localCategories.length,
    fixed.items.length,
    savings.items.length,
    period.periodStartISO,
    period.periodEndISO,
    needsPct,
    wantsPct,
    savingsPct,
    state.members.length,
  ]);

  // Prevent accidental close
  useEffect(() => {
    const unsubscribe = navigation.addListener("beforeRemove", (e) => {
      if (allowCloseRef.current || !hasUnsavedChangesRef.current) return;
      e.preventDefault();
      Alert.alert(t("discardChanges"), t("unsavedChangesMsg"), [
        { text: t("cancel"), style: "cancel" },
        {
          text: t("discard"),
          style: "destructive",
          onPress: () => {
            allowCloseRef.current = true;
            router.back();
          },
        },
        { text: t("save"), onPress: () => saveRef.current() },
      ]);
    });
    return unsubscribe;
  }, [navigation, router]);

  // Computed values
  const opts = { rateCache, dateISO: period.periodStartISO };
  const incomeTotal = useMemo(() => {
    const opts = { rateCache, dateISO: period.periodStartISO };
    return income.items.reduce((a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts), 0);
  }, [income.items, base, rateCache, period.periodStartISO]);
  const fixedExpensesTotal = useMemo(() => {
    const opts = { rateCache, dateISO: period.periodStartISO };
    return fixed.items.reduce((a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts), 0);
  }, [fixed.items, base, rateCache, period.periodStartISO]);
  const savingsTotal = useMemo(() => {
    const opts = { rateCache, dateISO: period.periodStartISO };
    return savings.items.reduce((a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts), 0);
  }, [savings.items, base, rateCache, period.periodStartISO]);
  const pctSum = useMemo(
    () => (Number(needsPct) || 0) + (Number(wantsPct) || 0) + (Number(savingsPct) || 0),
    [needsPct, wantsPct, savingsPct]
  );
  // Save handler
  const save = () => {
    if (state.members.length === 0) {
      Alert.alert(t("addMember"), t("addMemberFirst"));
      return;
    }
    if (incomeTotal <= 0) {
      Alert.alert(t("addIncome"), t("addIncomeFirst"));
      return;
    }
    if (localCategories.length === 0) {
      Alert.alert(t("addCategories"), t("addCategoriesFirst"));
      return;
    }
    const n = clamp((Number(needsPct) || 0) / 100, 0, 1);
    const w = clamp((Number(wantsPct) || 0) / 100, 0, 1);
    const s = clamp((Number(savingsPct) || 0) / 100, 0, 1);
    if (Math.abs(n + w + s - 1) > 0.001) {
      Alert.alert(t("totalMustBe100"), t("currentTotal", { total: pctSum }));
      return;
    }
    const catRatioTotal = localCategories.reduce((sum, c) => sum + c.ratio, 0);
    if (localCategories.length > 0 && Math.abs(catRatioTotal - 1) > 0.001) {
      Alert.alert(t("categoryRatiosMust100"), t("currentTotal", { total: categories.categoryRatioSum.toFixed(1) }));
      return;
    }

    const startDate = parseLocalDate(period.periodStartISO);
    const endDate = parseLocalDate(period.periodEndISO);
    if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) {
      Alert.alert(t("invalidDates"));
      return;
    }
    if (startDate >= endDate) {
      Alert.alert(t("invalidPeriod"));
      return;
    }

    const generateUniqueName = (baseName: string): string => {
      const trimmedName = baseName.trim() || `${period.periodStartISO} ~ ${period.periodEndISO}`;
      let finalName = trimmedName,
        counter = 0;
      while (state.sheets.some((s) => s.name === finalName)) {
        finalName = `${trimmedName}_${counter}`;
        counter++;
      }
      return finalName;
    };

    const uniqueSheetName = generateUniqueName(period.sheetName);
    const monthStart = startOfMonthISO(startDate),
      monthEnd = endOfMonthISO(startDate);
    const monthDays = daysBetweenInclusive(monthStart, monthEnd),
      periodDays = daysBetweenInclusive(period.periodStartISO, period.periodEndISO);
    const periodRatio = periodDays / monthDays,
      shouldProrate = periodRatio < 0.99;

    let pIncome = income.items.map((i) => ({ ...i })),
      pFixed = fixed.items.map((i) => ({ ...i })),
      pSavings = savings.items.map((i) => ({ ...i }));
    if (shouldProrate) {
      pIncome = pIncome.map((i) => ({ ...i, amount: i.amount * periodRatio }));
      pFixed = pFixed.map((i) => ({ ...i, amount: i.amount * periodRatio }));
      pSavings = pSavings.map((i) => ({ ...i, amount: i.amount * periodRatio }));
    }

    const newSheet: Sheet = {
      id: uuid(),
      name: uniqueSheetName,
      periodStartISO: period.periodStartISO,
      periodEndISO: period.periodEndISO,
      createdAtISO: toISODateTime(new Date()),
      balanceRule: { needsPct: n, wantsPct: w, savingsPct: s },
      incomeItems: pIncome,
      fixedExpenses: pFixed,
      savingsItems: pSavings,
      categories: localCategories.map((c) => ({ ...c })),
      expenses: [],
    };

    setState((prev) => ({ ...prev, sheets: [newSheet, ...prev.sheets], activeSheetId: newSheet.id }));
    allowCloseRef.current = true;
    router.back();
  };
  saveRef.current = save;

  const getDaysInMonth = (year: number, month: number) => new Date(year, month, 0).getDate();

  return (
    <GlassModalContainer>
      <KeyboardAvoidingView
        style={{ flex: 1 }}
        behavior={Platform.OS === "ios" ? "padding" : undefined}
      >
        <ScrollView
          style={{ flex: 1 }}
          contentInsetAdjustmentBehavior="automatic"
          contentContainerStyle={[styles.container, { paddingTop: 24, paddingBottom: 100 }]}
          keyboardShouldPersistTaps="handled"
        >
        <Text style={[styles.p, { color: theme.subText }]}>
          Create a new budget sheet. Settings are inherited from the previous sheet.
        </Text>

        {/* Sheet Name */}
        <View style={[styles.section, { backgroundColor: theme.surface }]}>
          <Text style={[styles.h2, { color: theme.text }]}>{t("sheetName")}</Text>
          <TextInput
            value={period.sheetName}
            onChangeText={period.setSheetName}
            placeholder={`${period.periodStartISO} ~ ${period.periodEndISO}`}
            style={[styles.input, inputStyle]}
            placeholderTextColor={theme.subText}
          />
        </View>

        {/* Period */}
        <View style={[styles.section, { backgroundColor: theme.surface }]}>
          <Text style={[styles.h2, { color: theme.text }]}>{t("period")}</Text>
          <Text style={labelStyle}>{t("periodType")}</Text>
          <Dropdown
            options={[
              { label: t("monthly"), value: "month" },
              { label: t("customDays"), value: "custom" },
            ]}
            selectedValue={period.periodType}
            onValueChange={period.handlePeriodTypeChange}
            theme={theme}
            style={{ width: "100%" }}
          />
          {period.periodType === "custom" && (
            <>
              <Text style={labelStyle}>{t("periodLength")}</Text>
              <TextInput
                value={String(period.customPeriodDays)}
                onChangeText={(txt) => {
                  const d = parseInt(txt, 10);
                  if (!isNaN(d) && d > 0) period.handleCustomPeriodDaysChange(d);
                }}
                keyboardType="numeric"
                style={[styles.input, inputStyle]}
              />
            </>
          )}
          <Text style={labelStyle}>{t("startDate")}</Text>
          <View style={styles.row}>
            <View style={[styles.dropdownCol, styles.dropdownYear]}>
              <Dropdown
                options={period.yearOptions.map((y) => ({ label: String(y), value: y }))}
                selectedValue={period.selectedYear}
                onValueChange={(y) => period.handleStartDateChange(y, period.selectedMonth, period.selectedDay)}
                theme={theme}
              />
            </View>
            <View style={[styles.dropdownCol, styles.dropdownMonth]}>
              <Dropdown
                options={period.monthOptions.map((m) => ({ label: period.monthNames[m - 1], value: m }))}
                selectedValue={period.selectedMonth}
                onValueChange={(m) => {
                  const max = getDaysInMonth(period.selectedYear, m);
                  period.handleStartDateChange(period.selectedYear, m, Math.min(period.selectedDay, max));
                }}
                theme={theme}
              />
            </View>
            <View style={styles.dropdownCol}>
              <Dropdown
                options={period.dayOptions.map((d) => ({ label: String(d), value: d }))}
                selectedValue={period.validSelectedDay}
                onValueChange={(d) => period.handleStartDateChange(period.selectedYear, period.selectedMonth, d)}
                theme={theme}
              />
            </View>
          </View>
          <Text style={captionStyle}>
            {t("period")}: {period.periodStartISO} ~ {period.periodEndISO}
          </Text>
        </View>

        {/* Members */}
        <View style={[styles.section, { backgroundColor: theme.surface }]}>
          <Text style={[styles.h2, { color: theme.text }]}>{t("members")}</Text>
          <View style={styles.row}>
            <TextInput
              value={members.inputName}
              onChangeText={members.setInputName}
              placeholder={t("name")}
              style={[styles.input, inputStyle, { flex: 1 }]}
              placeholderTextColor={theme.subText}
            />
            <Pressable onPress={members.handleAdd} style={({ pressed }) => [styles.btn, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}>
              <Text style={styles.btnText}>{t("add")}</Text>
            </Pressable>
          </View>
          {state.members.map((m, idx) =>
            members.editingId === m.id ? (
              <View key={m.id} style={[styles.listRow2, { backgroundColor: theme.card, borderColor: theme.border }]}>
                <TextInput
                  value={members.editingName}
                  onChangeText={members.setEditingName}
                  style={[styles.input, inputStyle, { flex: 1 }]}
                />
                <Pressable
                  onPress={members.saveEdit}
                  style={({ pressed }) => [styles.btn, styles.btnSmall, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}
                >
                  <Text style={styles.btnText}>{t("save")}</Text>
                </Pressable>
                <Pressable onPress={members.cancelEdit} style={({ pressed }) => [styles.btn, styles.btnSmall, styles.btnCancel, { backgroundColor: theme.surface, borderColor: theme.border }, pressedStyle(pressed)]}>
                  <Text style={[styles.btnText, { color: theme.text }]}>{t("cancel")}</Text>
                </Pressable>
              </View>
            ) : (
              <SwipeableRow
                key={m.id}
                id={m.id}
                theme={theme}
                actions={createDeleteAction(theme, () => members.handleDelete(m.id, m.name))}
                setRef={members.setSwipeableRef}
                onPress={() => members.startEdit(m)}
                rowStyle={styles.listRowWithReorder}
              >
                <View style={styles.reorderButtons}>
                  <Pressable onPress={() => members.move(idx, -1)} disabled={!members.canMoveUp(idx)} style={[styles.reorderBtn, !members.canMoveUp(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↑</Text></Pressable>
                  <Pressable onPress={() => members.move(idx, 1)} disabled={!members.canMoveDown(idx)} style={[styles.reorderBtn, !members.canMoveDown(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↓</Text></Pressable>
                </View>
                <Text style={[listTextStyle, { flex: 1 }]}>{m.name}</Text>
              </SwipeableRow>
            )
          )}
        </View>

        {/* Income */}
        <AmountItemSection
          title={t("income")}
          hook={income}
          theme={theme}
          t={t}
          baseCurrency={base}
          opts={opts}
          namePlaceholder={t("source")}
          total={incomeTotal}
          formatTotal={(v) => formatMoney(v, base)}
        />

        {/* Fixed Expenses */}
        <AmountItemSection
          title={t("fixedExpenses")}
          hook={fixed}
          theme={theme}
          t={t}
          baseCurrency={base}
          opts={opts}
          namePlaceholder={t("item")}
          total={fixedExpensesTotal}
          formatTotal={(v) => formatMoney(v, base)}
        />

        {/* Savings */}
        <AmountItemSection
          title={t("savings")}
          hook={savings}
          theme={theme}
          t={t}
          baseCurrency={base}
          opts={opts}
          namePlaceholder={t("goal")}
          total={savingsTotal}
          formatTotal={(v) => formatMoney(v, base)}
        />

        {/* Categories */}
        <View style={[styles.section, { backgroundColor: theme.surface }]}>
          <Text style={[styles.h2, { color: theme.text }]}>{t("categories")}</Text>
          <View style={styles.row}>
            <TextInput
              value={categories.inputName}
              onChangeText={categories.setInputName}
              placeholder={t("category")}
              style={[styles.input, inputStyle, { flex: 1 }]}
              placeholderTextColor={theme.subText}
            />
            <Pressable onPress={categories.handleAdd} style={({ pressed }) => [styles.btn, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}>
              <Text style={styles.btnText}>{t("add")}</Text>
            </Pressable>
          </View>
          {localCategories.length > 0 && (
            <Text style={[captionStyle, Math.abs(categories.displayCategoryRatioSum - 100) > 0.1 && { color: theme.buttonDanger, fontWeight: "700" }]}>
              {t("total")}: {categories.displayCategoryRatioSum.toFixed(1)}% {Math.abs(categories.displayCategoryRatioSum - 100) > 0.1 && `(${t("mustBe100")})`}
            </Text>
          )}
          {localCategories.map((c, idx) =>
            categories.editingId === c.id ? (
              <View key={c.id} style={[styles.listRow2, { backgroundColor: theme.card, borderColor: theme.border }]}>
                <TextInput
                  value={categories.editingName}
                  onChangeText={categories.setEditingName}
                  style={[styles.input, inputStyle, { flex: 1 }]}
                />
                <TextInput
                  value={categories.editingRatio}
                  onChangeText={categories.setEditingRatio}
                  keyboardType="numeric"
                  placeholder="%"
                  style={[styles.input, inputStyle, { width: 60 }]}
                />
                <Pressable
                  onPress={categories.saveEdit}
                  style={({ pressed }) => [styles.btn, styles.btnSmall, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}
                >
                  <Text style={styles.btnText}>{t("save")}</Text>
                </Pressable>
                <Pressable onPress={categories.cancelEdit} style={({ pressed }) => [styles.btn, styles.btnSmall, styles.btnCancel, { backgroundColor: theme.surface, borderColor: theme.border }, pressedStyle(pressed)]}>
                  <Text style={[styles.btnText, { color: theme.text }]}>{t("cancel")}</Text>
                </Pressable>
              </View>
            ) : (
              <SwipeableRow
                key={c.id}
                id={c.id}
                theme={theme}
                actions={createDeleteAction(theme, () => categories.handleDelete(c.id, c.name))}
                setRef={categories.setSwipeableRef}
                onPress={() => categories.startEdit(c)}
                rowStyle={styles.listRowWithReorder}
              >
                <View style={styles.reorderButtons}>
                  <Pressable onPress={() => categories.move(idx, -1)} disabled={!categories.canMoveUp(idx)} style={[styles.reorderBtn, !categories.canMoveUp(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↑</Text></Pressable>
                  <Pressable onPress={() => categories.move(idx, 1)} disabled={!categories.canMoveDown(idx)} style={[styles.reorderBtn, !categories.canMoveDown(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↓</Text></Pressable>
                </View>
                <Text style={[listTextStyle, { flex: 1 }]}>{c.name}</Text>
                <Text style={listTextStyle}>{(c.ratio * 100).toFixed(0)}%</Text>
              </SwipeableRow>
            )
          )}
        </View>

        {/* Ideal Balance */}
        <View style={[styles.section, { backgroundColor: theme.surface }]}>
          <Text style={[styles.h2, { color: theme.text }]}>{t("idealBalance")}</Text>
          <View style={styles.grid}>
            <View style={styles.gridItem}>
              <Text style={labelStyle}>{t("needsPercent")}</Text>
              <TextInput
                value={needsPct}
                onChangeText={setNeedsPct}
                keyboardType="numeric"
                style={[styles.input, inputStyle]}
              />
            </View>
            <View style={styles.gridItem}>
              <Text style={labelStyle}>{t("wantsPercent")}</Text>
              <TextInput
                value={wantsPct}
                onChangeText={setWantsPct}
                keyboardType="numeric"
                style={[styles.input, inputStyle]}
              />
            </View>
            <View style={styles.gridItem}>
              <Text style={labelStyle}>{t("savingsPercent")}</Text>
              <TextInput
                value={savingsPct}
                onChangeText={setSavingsPct}
                keyboardType="numeric"
                style={[styles.input, inputStyle]}
              />
            </View>
          </View>
          <Text style={captionStyle}>{t("total")}: {pctSum}%</Text>
        </View>
        </ScrollView>
        <View style={[styles.saveBar, { paddingBottom: 12 + insets.bottom }]}>
          <Pressable onPress={save} style={({ pressed }) => [styles.btn, styles.saveBtn, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}>
            <Text style={styles.btnText}>{t("createSheet")}</Text>
          </Pressable>
        </View>
      </KeyboardAvoidingView>
    </GlassModalContainer>
  );
}

const styles = StyleSheet.create({
  ...sharedStyles.layout,
  ...sharedStyles.typography,
  ...sharedStyles.form,
  ...sharedStyles.button,
  ...sharedStyles.list,
  // Local overrides
  dropdownYear: { flex: 1.2 },
  dropdownMonth: { flex: 1.2 },
  buttonRow: { flexDirection: "row", gap: 12 },
});

import { useFocusEffect, useRouter } from "expo-router";
import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { useNavigation } from "@react-navigation/native";
import {
  Alert,
  KeyboardAvoidingView,
  Platform,
  Pressable,
  ScrollView,
  StyleSheet,
  Text,
  TextInput,
  View,
} from "react-native";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { sharedStyles } from "../constants/sharedStyles";
import { AmountItemSection } from "../components/amount-item-section";
import { Dropdown } from "../components/dropdown";
import { GlassModalContainer } from "../components/glass-modal-container";
import { SwipeableRow, createDeleteAction } from "../components/swipeable-row";
import { useModalTheme } from "../hooks/use-modal-theme";
import { useFormStyles } from "../hooks/use-form-styles";
import { pressedStyle } from "../hooks/use-themed-styles";
import { useLanguage } from "../hooks/use-language";
import { usePeriodForm, useAmountItemList } from "../hooks/create-sheet";
import { useSetupSimpleList, useSetupCategoryList } from "../hooks/setup";
import { useStore } from "../src/store";
import { Category, Member, Sheet } from "../src/types";
import {
  clamp,
  daysBetweenInclusive,
  formatMoney,
  itemAmountToBaseForSum,
  parseLocalDate,
  startOfMonthISO,
  endOfMonthISO,
  toISODateTime,
  uuid,
} from "../src/utils";

export default function CreateSheetScreen() {
  const router = useRouter();
  const navigation = useNavigation();
  const { state, setState, activeSheet, rateCache, fillRateCacheForActiveSheet } = useStore();
  const theme = useAppTheme();
  const hasUnsavedChangesRef = useRef(false);
  const allowCloseRef = useRef(false);
  const isFirstRenderRef = useRef(true);
  const saveRef = useRef<() => void>(() => {});
  const insets = useSafeAreaInsets();

  useFocusEffect(
    useCallback(() => {
      if (activeSheet) fillRateCacheForActiveSheet();
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeSheet?.id, fillRateCacheForActiveSheet])
  );
  const { t } = useLanguage();
  const { labelStyle, captionStyle, inputStyle, listTextStyle } = useFormStyles(theme);

  const lastSheet = state.sheets[0] ?? null;
  const base = state.baseCurrency;
  const usedCurrencies = state.usedCurrencies ?? [];

  // Period form
  const period = usePeriodForm();

  // Members - using shared hook with global state callbacks
  const members = useSetupSimpleList<Member>({
    items: state.members,
    onAdd: (m) => setState((p) => ({ ...p, members: [...p.members, m] })),
    onUpdate: (id, updates) =>
      setState((p) => ({ ...p, members: p.members.map((m) => (m.id === id ? { ...m, ...updates } : m)) })),
    onDelete: (id) => setState((p) => ({ ...p, members: p.members.filter((m) => m.id !== id) })),
    onReorder: (reordered) => setState((p) => ({ ...p, members: reordered })),
    createItem: (name) => ({ id: uuid(), name, updatedAt: toISODateTime(new Date()) }),
    deleteTitle: "Delete Member",
  });

  // Income items
  const income = useAmountItemList({
    initialItems: lastSheet?.incomeItems ? lastSheet.incomeItems.map((i) => ({ ...i, id: uuid() })) : [],
    baseCurrency: base,
    usedCurrencies,
    dateISO: period.periodStartISO,
    itemLabel: "Income",
  });

  // Fixed expenses
  const fixed = useAmountItemList({
    initialItems: lastSheet?.fixedExpenses ? lastSheet.fixedExpenses.map((i) => ({ ...i, id: uuid() })) : [],
    baseCurrency: base,
    usedCurrencies,
    dateISO: period.periodStartISO,
    itemLabel: "Fixed Expense",
  });

  // Savings
  const savings = useAmountItemList({
    initialItems: lastSheet?.savingsItems ? lastSheet.savingsItems.map((i) => ({ ...i, id: uuid() })) : [],
    baseCurrency: base,
    usedCurrencies,
    dateISO: period.periodStartISO,
    itemLabel: "Saving",
  });

  // Categories - local state with shared hook
  const defaultCategories: Category[] = [
    { id: uuid(), name: "Groceries", ratio: 0.35 },
    { id: uuid(), name: "Home Supplies", ratio: 0.1 },
    { id: uuid(), name: "Kids Supplies", ratio: 0.1 },
    { id: uuid(), name: "Eating Out", ratio: 0.05 },
    { id: uuid(), name: "Electronics", ratio: 0.07 },
    { id: uuid(), name: "Transport", ratio: 0.05 },
    { id: uuid(), name: "Business Expenses", ratio: 0.05 },
    { id: uuid(), name: "Clothing", ratio: 0.05 },
    { id: uuid(), name: "Personal Care", ratio: 0.1 },
    { id: uuid(), name: "Medical", ratio: 0.03 },
    { id: uuid(), name: "Other", ratio: 0.05 },
  ];
  const [localCategories, setLocalCategories] = useState<Category[]>(
    lastSheet?.categories ? lastSheet.categories.map((c) => ({ ...c })) : defaultCategories
  );
  const categories = useSetupCategoryList({
    categories: localCategories,
    onAdd: (c) => setLocalCategories((p) => [...p, c]),
    onUpdate: (id, updates) => setLocalCategories((p) => p.map((c) => (c.id === id ? { ...c, ...updates } : c))),
    onDelete: (id) => setLocalCategories((p) => p.filter((c) => c.id !== id)),
    onReorder: setLocalCategories,
  });

  // Balance rule
  const [needsPct, setNeedsPct] = useState(String(Math.round((lastSheet?.balanceRule.needsPct ?? 0.5) * 100)));
  const [wantsPct, setWantsPct] = useState(String(Math.round((lastSheet?.balanceRule.wantsPct ?? 0.3) * 100)));
  const [savingsPct, setSavingsPct] = useState(String(Math.round((lastSheet?.balanceRule.savingsPct ?? 0.2) * 100)));

  // Track unsaved changes
  useEffect(() => {
    if (isFirstRenderRef.current) {
      isFirstRenderRef.current = false;
      return;
    }
    hasUnsavedChangesRef.current = true;
  }, [
    period.sheetName,
    income.items.length,
    localCategories.length,
    fixed.items.length,
    savings.items.length,
    period.periodStartISO,
    period.periodEndISO,
    needsPct,
    wantsPct,
    savingsPct,
    state.members.length,
  ]);

  // Prevent accidental close
  useEffect(() => {
    const unsubscribe = navigation.addListener("beforeRemove", (e) => {
      if (allowCloseRef.current || !hasUnsavedChangesRef.current) return;
      e.preventDefault();
      Alert.alert(t("discardChanges"), t("unsavedChangesMsg"), [
        { text: t("cancel"), style: "cancel" },
        {
          text: t("discard"),
          style: "destructive",
          onPress: () => {
            allowCloseRef.current = true;
            router.back();
          },
        },
        { text: t("save"), onPress: () => saveRef.current() },
      ]);
    });
    return unsubscribe;
  }, [navigation, router]);

  // Computed values
  const opts = { rateCache, dateISO: period.periodStartISO };
  const incomeTotal = useMemo(() => {
    const opts = { rateCache, dateISO: period.periodStartISO };
    return income.items.reduce((a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts), 0);
  }, [income.items, base, rateCache, period.periodStartISO]);
  const fixedExpensesTotal = useMemo(() => {
    const opts = { rateCache, dateISO: period.periodStartISO };
    return fixed.items.reduce((a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts), 0);
  }, [fixed.items, base, rateCache, period.periodStartISO]);
  const savingsTotal = useMemo(() => {
    const opts = { rateCache, dateISO: period.periodStartISO };
    return savings.items.reduce((a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts), 0);
  }, [savings.items, base, rateCache, period.periodStartISO]);
  const pctSum = useMemo(
    () => (Number(needsPct) || 0) + (Number(wantsPct) || 0) + (Number(savingsPct) || 0),
    [needsPct, wantsPct, savingsPct]
  );
  // Save handler
  const save = () => {
    if (state.members.length === 0) {
      Alert.alert(t("addMember"), t("addMemberFirst"));
      return;
    }
    if (incomeTotal <= 0) {
      Alert.alert(t("addIncome"), t("addIncomeFirst"));
      return;
    }
    if (localCategories.length === 0) {
      Alert.alert(t("addCategories"), t("addCategoriesFirst"));
      return;
    }
    const n = clamp((Number(needsPct) || 0) / 100, 0, 1);
    const w = clamp((Number(wantsPct) || 0) / 100, 0, 1);
    const s = clamp((Number(savingsPct) || 0) / 100, 0, 1);
    if (Math.abs(n + w + s - 1) > 0.001) {
      Alert.alert(t("totalMustBe100"), t("currentTotal", { total: pctSum }));
      return;
    }
    const catRatioTotal = localCategories.reduce((sum, c) => sum + c.ratio, 0);
    if (localCategories.length > 0 && Math.abs(catRatioTotal - 1) > 0.001) {
      Alert.alert(t("categoryRatiosMust100"), t("currentTotal", { total: categories.categoryRatioSum.toFixed(1) }));
      return;
    }

    const startDate = parseLocalDate(period.periodStartISO);
    const endDate = parseLocalDate(period.periodEndISO);
    if (isNaN(startDate.getTime()) || isNaN(endDate.getTime())) {
      Alert.alert(t("invalidDates"));
      return;
    }
    if (startDate >= endDate) {
      Alert.alert(t("invalidPeriod"));
      return;
    }

    const generateUniqueName = (baseName: string): string => {
      const trimmedName = baseName.trim() || `${period.periodStartISO} ~ ${period.periodEndISO}`;
      let finalName = trimmedName,
        counter = 0;
      while (state.sheets.some((s) => s.name === finalName)) {
        finalName = `${trimmedName}_${counter}`;
        counter++;
      }
      return finalName;
    };

    const uniqueSheetName = generateUniqueName(period.sheetName);
    const monthStart = startOfMonthISO(startDate),
      monthEnd = endOfMonthISO(startDate);
    const monthDays = daysBetweenInclusive(monthStart, monthEnd),
      periodDays = daysBetweenInclusive(period.periodStartISO, period.periodEndISO);
    const periodRatio = periodDays / monthDays,
      shouldProrate = periodRatio < 0.99;

    let pIncome = income.items.map((i) => ({ ...i })),
      pFixed = fixed.items.map((i) => ({ ...i })),
      pSavings = savings.items.map((i) => ({ ...i }));
    if (shouldProrate) {
      pIncome = pIncome.map((i) => ({ ...i, amount: i.amount * periodRatio }));
      pFixed = pFixed.map((i) => ({ ...i, amount: i.amount * periodRatio }));
      pSavings = pSavings.map((i) => ({ ...i, amount: i.amount * periodRatio }));
    }

    const newSheet: Sheet = {
      id: uuid(),
      name: uniqueSheetName,
      periodStartISO: period.periodStartISO,
      periodEndISO: period.periodEndISO,
      createdAtISO: toISODateTime(new Date()),
      balanceRule: { needsPct: n, wantsPct: w, savingsPct: s },
      incomeItems: pIncome,
      fixedExpenses: pFixed,
      savingsItems: pSavings,
      categories: localCategories.map((c) => ({ ...c })),
      expenses: [],
    };

    setState((prev) => ({ ...prev, sheets: [newSheet, ...prev.sheets], activeSheetId: newSheet.id }));
    allowCloseRef.current = true;
    router.back();
  };
  saveRef.current = save;

  const getDaysInMonth = (year: number, month: number) => new Date(year, month, 0).getDate();

  return (
    <GlassModalContainer>
      <KeyboardAvoidingView
        style={{ flex: 1 }}
        behavior={Platform.OS === "ios" ? "padding" : undefined}
      >
        <ScrollView
          style={{ flex: 1 }}
          contentInsetAdjustmentBehavior="automatic"
          contentContainerStyle={[styles.container, { paddingTop: 24, paddingBottom: 100 }]}
          keyboardShouldPersistTaps="handled"
        >
        <Text style={[styles.p, { color: theme.subText }]}>
          Create a new budget sheet. Settings are inherited from the previous sheet.
        </Text>

        {/* Sheet Name */}
        <View style={[styles.section, { backgroundColor: theme.surface }]}>
          <Text style={[styles.h2, { color: theme.text }]}>{t("sheetName")}</Text>
          <TextInput
            value={period.sheetName}
            onChangeText={period.setSheetName}
            placeholder={`${period.periodStartISO} ~ ${period.periodEndISO}`}
            style={[styles.input, inputStyle]}
            placeholderTextColor={theme.subText}
          />
        </View>

        {/* Period */}
        <View style={[styles.section, { backgroundColor: theme.surface }]}>
          <Text style={[styles.h2, { color: theme.text }]}>{t("period")}</Text>
          <Text style={labelStyle}>{t("periodType")}</Text>
          <Dropdown
            options={[
              { label: t("monthly"), value: "month" },
              { label: t("customDays"), value: "custom" },
            ]}
            selectedValue={period.periodType}
            onValueChange={period.handlePeriodTypeChange}
            theme={theme}
            style={{ width: "100%" }}
          />
          {period.periodType === "custom" && (
            <>
              <Text style={labelStyle}>{t("periodLength")}</Text>
              <TextInput
                value={String(period.customPeriodDays)}
                onChangeText={(txt) => {
                  const d = parseInt(txt, 10);
                  if (!isNaN(d) && d > 0) period.handleCustomPeriodDaysChange(d);
                }}
                keyboardType="numeric"
                style={[styles.input, inputStyle]}
              />
            </>
          )}
          <Text style={labelStyle}>{t("startDate")}</Text>
          <View style={styles.row}>
            <View style={[styles.dropdownCol, styles.dropdownYear]}>
              <Dropdown
                options={period.yearOptions.map((y) => ({ label: String(y), value: y }))}
                selectedValue={period.selectedYear}
                onValueChange={(y) => period.handleStartDateChange(y, period.selectedMonth, period.selectedDay)}
                theme={theme}
              />
            </View>
            <View style={[styles.dropdownCol, styles.dropdownMonth]}>
              <Dropdown
                options={period.monthOptions.map((m) => ({ label: period.monthNames[m - 1], value: m }))}
                selectedValue={period.selectedMonth}
                onValueChange={(m) => {
                  const max = getDaysInMonth(period.selectedYear, m);
                  period.handleStartDateChange(period.selectedYear, m, Math.min(period.selectedDay, max));
                }}
                theme={theme}
              />
            </View>
            <View style={styles.dropdownCol}>
              <Dropdown
                options={period.dayOptions.map((d) => ({ label: String(d), value: d }))}
                selectedValue={period.validSelectedDay}
                onValueChange={(d) => period.handleStartDateChange(period.selectedYear, period.selectedMonth, d)}
                theme={theme}
              />
            </View>
          </View>
          <Text style={captionStyle}>
            {t("period")}: {period.periodStartISO} ~ {period.periodEndISO}
          </Text>
        </View>

        {/* Members */}
        <View style={[styles.section, { backgroundColor: theme.surface }]}>
          <Text style={[styles.h2, { color: theme.text }]}>{t("members")}</Text>
          <View style={styles.row}>
            <TextInput
              value={members.inputName}
              onChangeText={members.setInputName}
              placeholder={t("name")}
              style={[styles.input, inputStyle, { flex: 1 }]}
              placeholderTextColor={theme.subText}
            />
            <Pressable onPress={members.handleAdd} style={({ pressed }) => [styles.btn, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}>
              <Text style={styles.btnText}>{t("add")}</Text>
            </Pressable>
          </View>
          {state.members.map((m, idx) =>
            members.editingId === m.id ? (
              <View key={m.id} style={[styles.listRow2, { backgroundColor: theme.card, borderColor: theme.border }]}>
                <TextInput
                  value={members.editingName}
                  onChangeText={members.setEditingName}
                  style={[styles.input, inputStyle, { flex: 1 }]}
                />
                <Pressable
                  onPress={members.saveEdit}
                  style={({ pressed }) => [styles.btn, styles.btnSmall, { backgroundColor: theme.buttonDark }, pressedStyle(pressed)]}
                >
                  <Text style={styles.btnText}>{t("save")}</Text>
                </Pressable>
                <Pressable onPress={members.cancelEdit} style={({ pressed }) => [styles.btn, styles.btnSmall, styles.btnCancel, { backgroundColor: theme.surface, borderColor: theme.border }, pressedStyle(pressed)]}>
                  <Text style={[styles.btnText, { color: theme.text }]}>{t("cancel")}</Text>
                </Pressable>
              </View>
            ) : (
              <SwipeableRow
                key={m.id}
                id={m.id}
                theme={theme}
                actions={createDeleteAction(theme, () => members.handleDelete(m.id, m.name))}
                setRef={members.setSwipeableRef}
                onPress={() => members.startEdit(m)}
                rowStyle={styles.listRowWithReorder}
              >
                <View style={styles.reorderButtons}>
                  <Pressable onPress={() => members.move(idx, -1)} disabled={!members.canMoveUp(idx)} style={[styles.reorderBtn, !members.canMoveUp(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↑</Text></Pressable>
                  <Pressable onPress={() => members.move(idx, 1)} disabled={!members.canMoveDown(idx)} style={[styles.reorderBtn, !members.canMoveDown(idx) && styles.reorderBtnDisabled]}><Text style={[styles.reorderBtnText, { color: theme.text }]}>↓</Text></Pressable>
                </View>
