import { GlassModalContainer } from "@/components/glass-modal-container";
import * as FileSystem from "expo-file-system/legacy";
import { useRouter } from "expo-router";
import React, { useMemo, useRef, useState } from "react";
import { Alert, Pressable, RefreshControl, ScrollView, Share, StyleSheet, Text, View } from "react-native";
import { Swipeable } from "react-native-gesture-handler";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { SwipeableRow, SwipeAction } from "../components/swipeable-row";
import { sharedStyles } from "../constants/sharedStyles";
import { useAppTheme } from "../hooks/use-app-theme";
import { useLanguage } from "../hooks/use-language";
import { generateSheetCSV } from "../src/csv-export";
import { useStore } from "../src/store";
import { formatDateTime } from "../src/utils";

type SheetSortBy = "created" | "period";
type SheetSortOrder = "asc" | "desc";

export default function SheetsScreen() {
  const router = useRouter();
  const insets = useSafeAreaInsets();
  const { state, setState, switchSheet, activeSheet, syncFromCloud } = useStore();
  const [refreshing, setRefreshing] = useState(false);
  const swipeableRefs = useRef<{ [key: string]: Swipeable | null }>({});
  const theme = useAppTheme();
  const { t } = useLanguage();
  const [sortBy, setSortBy] = useState<SheetSortBy>("period");
  const [sortOrder, setSortOrder] = useState<SheetSortOrder>("desc");

  const sortedSheets = useMemo(() => {
    const sheets = [...state.sheets];
    const mult = sortOrder === "desc" ? -1 : 1;
    if (sortBy === "created") {
      return sheets.sort((a, b) => mult * (a.createdAtISO.localeCompare(b.createdAtISO)));
    }
    return sheets.sort((a, b) => {
      if (a.periodStartISO !== b.periodStartISO) return mult * (a.periodStartISO.localeCompare(b.periodStartISO));
      return mult * (a.periodEndISO.localeCompare(b.periodEndISO));
    });
  }, [state.sheets, sortBy, sortOrder]);

  const closeAllSwipeables = () => Object.values(swipeableRefs.current).forEach(ref => ref?.close());
  const handleSwitchSheet = (id: string) => { closeAllSwipeables(); switchSheet(id); router.back(); };

  const showSortByMenu = () => {
    Alert.alert(t("sortBy"), undefined, [
      { text: t("sortByPeriod"), onPress: () => setSortBy("period") },
      { text: t("sortByCreated"), onPress: () => setSortBy("created") },
      { text: t("cancel"), style: "cancel" },
    ]);
  };

  const sortByLabel = sortBy === "period" ? t("sortByPeriod") : t("sortByCreated");

  const deleteSheet = (id: string) => {
    const sheet = state.sheets.find(s => s.id === id);
    if (!sheet) return;
    Alert.alert(t("deleteSheet"), t("deleteItemConfirm", { name: sheet.name }), [
      { text: t("cancel"), style: "cancel" },
      { text: t("delete"), style: "destructive", onPress: () => { setState(prev => { const remaining = prev.sheets.filter(s => s.id !== id); let newActiveId = prev.activeSheetId === id ? (remaining.length > 0 ? remaining[0].id : null) : prev.activeSheetId; return { ...prev, sheets: remaining, activeSheetId: newActiveId }; }); closeAllSwipeables(); } },
    ]);
  };

  const handleExportSheet = async (sheet: any) => {
    try {
      swipeableRefs.current[sheet.id]?.close();
      const csv = generateSheetCSV(sheet, state.members, state.baseCurrency);
      const fileName = `${sheet.name.replace(/[^a-zA-Z0-9_-]/g, "_")}.csv`;
      const docDir = FileSystem.documentDirectory || FileSystem.cacheDirectory;
      if (!docDir) { await Share.share({ message: csv, title: `Export ${sheet.name}.csv` }); return; }
      const fileUri = `${docDir.endsWith("/") ? docDir : `${docDir}/`}${fileName}`;
      await FileSystem.writeAsStringAsync(fileUri, csv);
      const shareUri = fileUri.startsWith("file://") ? fileUri : `file://${fileUri}`;
      await Share.share({ url: shareUri, title: `Export ${sheet.name}.csv`, message: `Export ${sheet.name}.csv` });
    } catch (e) { Alert.alert(t("exportFailed"), String(e)); }
  };

  return (
    <GlassModalContainer>
      <View style={styles.wrapper}>
      <ScrollView
        style={styles.sheetListScroll}
        contentContainerStyle={[styles.container, styles.sheetListContent, { paddingTop: 16 }]}
        contentInsetAdjustmentBehavior="automatic"
        refreshControl={
          <RefreshControl
            refreshing={refreshing}
            onRefresh={async () => {
              setRefreshing(true);
              try {
                await syncFromCloud();
              } finally {
                setRefreshing(false);
              }
            }}
          />
        }
      >
        <View style={styles.headerSection}>
          <View style={styles.headerRow}>
            <Text style={[styles.sectionDescription, { color: theme.text }]}>Select a sheet to view or edit.</Text>
            <View style={styles.sortRow}>
              <Pressable onPress={showSortByMenu} style={[styles.sortActionBtn, { backgroundColor: theme.card }]}>
                <Text style={[styles.sortActionText, { color: theme.text }]}>Sort: {sortByLabel}</Text>
              </Pressable>
              <Pressable onPress={() => setSortOrder((o) => (o === "asc" ? "desc" : "asc"))} style={[styles.sortToggle, { backgroundColor: theme.card }]}>
                <Text style={[styles.sortActionText, { color: theme.text }]}>{sortOrder === "asc" ? t("sortOldest") : t("sortNewest")}</Text>
              </Pressable>
            </View>
          </View>
        </View>
        <View style={styles.section}>
        {sortedSheets.map((sheet) => {
          const isActive = sheet.id === activeSheet?.id;
          const actions: SwipeAction[] = [
            { label: t("exportSheet"), onPress: () => handleExportSheet(sheet), backgroundColor: theme.buttonPrimary },
            { label: t("delete"), onPress: () => deleteSheet(sheet.id), backgroundColor: theme.buttonDanger },
          ];
          return (
            <SwipeableRow
              key={sheet.id}
              id={sheet.id}
              theme={theme}
              actions={actions}
              setRef={(id, r) => { swipeableRefs.current[id] = r; }}
              onPress={() => handleSwitchSheet(sheet.id)}
              rowStyle={[styles.sheetItem, { backgroundColor: isActive ? theme.successBg : theme.card }]}
            >
              {isActive && <View style={[styles.activeAccent, { backgroundColor: theme.successText }]} />}
              <View style={styles.sheetInfo}>
                <View style={styles.sheetNameContainer}>
                  <Text style={[styles.sheetName, { color: isActive ? theme.successText : theme.text, fontWeight: isActive ? "700" : "600" }]}>{sheet.name}</Text>
                  <Text style={[styles.sheetPeriod, { color: theme.subText }]}>{sheet.periodStartISO} ~ {sheet.periodEndISO}</Text>
                  <Text style={[styles.sheetCreatedAt, { color: theme.mutedText }]}>{t("created")}: {formatDateTime(sheet.createdAtISO)}</Text>
                </View>
                {isActive && <Text style={[styles.activeLabel, { color: theme.successText }]}>{t("current")}</Text>}
              </View>
            </SwipeableRow>
          );
        })}
        </View>
        </ScrollView>
        <View style={[styles.footer, { paddingBottom: insets.bottom + 12 }]}>
          <Pressable onPress={() => router.push("/create-sheet")} style={[styles.createButton, { backgroundColor: theme.buttonDark }]}><Text style={styles.createButtonText}>{t("createNewSheet")}</Text></Pressable>
        </View>
      </View>
    </GlassModalContainer>
  );
}

