import { pressedStyle, useThemedStyles } from "@/hooks/use-themed-styles";
import { getPickerCurrencies, shouldShowCurrencyDropdown } from "@/src/currency-input";
import { fetchRate } from "@/src/rates";
import { useStore } from "@/src/store";
import { formatMoney, formatRateInput, normalizeRateInput, parseAmountInput, parseLocalDate, roundAmountForCurrency, toISODate, toISODateTime, uuid } from "@/src/utils";
import { useNavigation } from "@react-navigation/native";
import { useFocusEffect, useLocalSearchParams, useRouter } from "expo-router";
import React, { useCallback, useEffect, useLayoutEffect, useMemo, useRef, useState } from "react";
import { Alert, InputAccessoryView, Keyboard, KeyboardAvoidingView, Platform, Pressable, ScrollView, StyleSheet, Text, TextInput, View } from "react-native";

const INPUT_ACCESSORY_VIEW_ID = "expense-entry-keyboard";

export default function ExpenseEntryScreen() {
  const router = useRouter();
  const params = useLocalSearchParams<{ id?: string }>();
  const editId = params.id ?? null;
  const { state, setState, activeSheet, rateCache, fillRateCacheForActiveSheet } = useStore();
  const theme = useAppTheme();
  const themedStyles = useThemedStyles();
  const { t } = useLanguage();
  const navigation = useNavigation();
  const { lastEntry, loaded: lastEntryLoaded, saveLastEntry } = useLastExpenseEntry();

  // Set header title for edit mode
  useLayoutEffect(() => {
    navigation.setOptions({
      title: t("updateExpense"),
    });
  }, [navigation, t]);

  const periodStart = activeSheet?.periodStartISO;
  const periodEnd = activeSheet?.periodEndISO;
  const todayISO = toISODate(new Date());
  const initialDate = (periodStart && periodEnd && todayISO >= periodStart && todayISO <= periodEnd) ? todayISO : (periodStart ?? todayISO);

  const [dateISO, setDateISO] = useState(initialDate);
  const dateObj = parseLocalDate(dateISO);
  const [selectedYear, setSelectedYear] = useState(dateObj.getFullYear());
  const [selectedMonth, setSelectedMonth] = useState(dateObj.getMonth() + 1);
  const [selectedDay, setSelectedDay] = useState(dateObj.getDate());
  const [amount, setAmount] = useState("");
  const [memo, setMemo] = useState("");
  const [inputCurrency, setInputCurrency] = useState<string>(state.baseCurrency);
  const [rateToBase, setRateToBase] = useState("");
  const [rateLoading, setRateLoading] = useState(false);
  const [editingEntryInputCurrency, setEditingEntryInputCurrency] = useState<string | null>(null);
  const [lastEntryApplied, setLastEntryApplied] = useState(false);

  const scrollViewRef = useRef<ScrollView>(null);
  const memoInputRef = useRef<TextInput>(null);
  const memoInputY = useRef(0);
  const [memoFocused, setMemoFocused] = useState(false);

  const handleMemoFocus = useCallback(() => {
    setMemoFocused(true);
    // Scroll to show memo input when focused
    setTimeout(() => {
      scrollViewRef.current?.scrollTo({ y: memoInputY.current - 100, animated: true });
    }, 100);
  }, []);

  const handleMemoBlur = useCallback(() => {
    setMemoFocused(false);
    // Reset scroll position when keyboard is dismissed
    setTimeout(() => {
      scrollViewRef.current?.scrollTo({ y: 0, animated: true });
    }, 100);
  }, []);

  const dismissKeyboard = useCallback(() => {
    Keyboard.dismiss();
    setMemoFocused(false);
    setTimeout(() => {
      scrollViewRef.current?.scrollTo({ y: 0, animated: true });
    }, 100);
  }, []);

  // Reset scroll position when keyboard hides (for all input fields)
  useEffect(() => {
    const hideListener = Keyboard.addListener(
      Platform.OS === "ios" ? "keyboardWillHide" : "keyboardDidHide",
      () => {
        setMemoFocused(false);
        setTimeout(() => {
          scrollViewRef.current?.scrollTo({ y: 0, animated: true });
        }, 100);
      }
    );
    return () => hideListener.remove();
  }, []);

  const categories = useMemo(() => activeSheet?.categories ?? [], [activeSheet?.categories]);
  const members = useMemo(() => state.members ?? [], [state.members]);
  const [categoryId, setCategoryId] = useState<string | null>(categories[0]?.id ?? null);
  const [memberId, setMemberId] = useState<string | null>(members[0]?.id ?? null);

  useFocusEffect(
    useCallback(() => {
      if (activeSheet) fillRateCacheForActiveSheet();
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeSheet?.id, fillRateCacheForActiveSheet])
  );

  useEffect(() => {
    if (!activeSheet?.periodStartISO || !activeSheet?.periodEndISO) return;
    const today = toISODate(new Date());
    const start = activeSheet.periodStartISO;
    const end = activeSheet.periodEndISO;
    const nextInitial = (today >= start && today <= end) ? today : start;
    setDateISO(nextInitial);
    const d = parseLocalDate(nextInitial);
    setSelectedYear(d.getFullYear());
    setSelectedMonth(d.getMonth() + 1);
    setSelectedDay(d.getDate());
  }, [activeSheet?.id, activeSheet?.periodStartISO, activeSheet?.periodEndISO]);

  // Restore last entry values (only for new entries, not edits)
  useEffect(() => {
    if (editId || !lastEntryLoaded || lastEntryApplied || !activeSheet) return;
    setLastEntryApplied(true);

    // Restore date (only if saved today)
    const restoredDate = getInitialDate(lastEntry, periodStart, periodEnd);
    setDateISO(restoredDate);
    const d = parseLocalDate(restoredDate);
    setSelectedYear(d.getFullYear());
    setSelectedMonth(d.getMonth() + 1);
    setSelectedDay(d.getDate());

    // Restore category (if it still exists in current sheet)
    if (lastEntry?.categoryId) {
      const categoryExists = categories.some((c) => c.id === lastEntry.categoryId);
      if (categoryExists) {
        setCategoryId(lastEntry.categoryId);
      }
    }

    // Restore member (if it still exists)
    if (lastEntry?.memberId) {
      const memberExists = members.some((m) => m.id === lastEntry.memberId);
      if (memberExists) {
        setMemberId(lastEntry.memberId);
      }
    }
  }, [editId, lastEntryLoaded, lastEntryApplied, lastEntry, activeSheet, periodStart, periodEnd, categories, members]);

  useEffect(() => {
    if (!editId || !activeSheet) return;
    const e = activeSheet.expenses.find((ex) => ex.id === editId);
    if (!e) return;
    const entryCurrency = e.inputCurrency ?? state.baseCurrency;
    setEditingEntryInputCurrency(entryCurrency);
    setDateISO(e.dateISO);
    const d = parseLocalDate(e.dateISO);
    setSelectedYear(d.getFullYear());
    setSelectedMonth(d.getMonth() + 1);
    setSelectedDay(d.getDate());
    setCategoryId(e.categoryId ?? categories[0]?.id ?? null);
    setMemberId(e.memberId ?? members[0]?.id ?? null);
    setMemo(e.memo || "");
    setAmount(String(e.amount));
    if (e.inputCurrency != null && e.inputCurrency !== state.baseCurrency) {
      setInputCurrency(e.inputCurrency);
      setRateToBase(e.rate != null ? String(e.rate) : "");
    } else {
      setInputCurrency(state.baseCurrency);
      setRateToBase("");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [editId, activeSheet?.id]);

  useEffect(() => {
    if (!editingEntryInputCurrency) setInputCurrency(state.baseCurrency);
  }, [state.baseCurrency, editingEntryInputCurrency]);

  // Parse period boundaries
  const periodStartDate = useMemo(() => periodStart ? parseLocalDate(periodStart) : null, [periodStart]);
  const periodEndDate = useMemo(() => periodEnd ? parseLocalDate(periodEnd) : null, [periodEnd]);

  const yearOptions = useMemo(() => {
    if (!periodStartDate || !periodEndDate) return [new Date().getFullYear()];
    const start = periodStartDate.getFullYear();
    const end = periodEndDate.getFullYear();
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }, [periodStartDate, periodEndDate]);

  const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

  // Filter months based on selected year and period
  const monthOptions = useMemo(() => {
    if (!periodStartDate || !periodEndDate) return Array.from({ length: 12 }, (_, i) => i + 1);
    const startYear = periodStartDate.getFullYear();
    const endYear = periodEndDate.getFullYear();
    const startMonth = periodStartDate.getMonth() + 1;
    const endMonth = periodEndDate.getMonth() + 1;

    let minMonth = 1;
    let maxMonth = 12;
    if (selectedYear === startYear) minMonth = startMonth;
    if (selectedYear === endYear) maxMonth = endMonth;

    return Array.from({ length: maxMonth - minMonth + 1 }, (_, i) => minMonth + i);
  }, [periodStartDate, periodEndDate, selectedYear]);

  // Filter days based on selected year/month and period
  const getDaysInMonth = (y: number, m: number) => new Date(y, m, 0).getDate();
  const dayOptions = useMemo(() => {
    const daysInMonth = getDaysInMonth(selectedYear, selectedMonth);
    if (!periodStartDate || !periodEndDate) return Array.from({ length: daysInMonth }, (_, i) => i + 1);

    const startYear = periodStartDate.getFullYear();
    const startMonth = periodStartDate.getMonth() + 1;
    const startDay = periodStartDate.getDate();
    const endYear = periodEndDate.getFullYear();
    const endMonth = periodEndDate.getMonth() + 1;
    const endDay = periodEndDate.getDate();

    let minDay = 1;
    let maxDay = daysInMonth;
    if (selectedYear === startYear && selectedMonth === startMonth) minDay = startDay;
    if (selectedYear === endYear && selectedMonth === endMonth) maxDay = Math.min(maxDay, endDay);

    return Array.from({ length: maxDay - minDay + 1 }, (_, i) => minDay + i);
  }, [selectedYear, selectedMonth, periodStartDate, periodEndDate]);

  const handleDateChange = (y: number, m: number, d: number) => {
    // Clamp values to period boundaries
    if (!periodStartDate || !periodEndDate) {
      setDateISO(`${y}-${String(m).padStart(2, "0")}-${String(d).padStart(2, "0")}`);
      setSelectedYear(y);
      setSelectedMonth(m);
      setSelectedDay(d);
      return;
    }

    let newYear = y;
    let newMonth = m;
    let newDay = d;

    // Clamp month based on year
    const startYear = periodStartDate.getFullYear();
    const endYear = periodEndDate.getFullYear();
    const startMonth = periodStartDate.getMonth() + 1;
    const endMonth = periodEndDate.getMonth() + 1;

    if (newYear === startYear && newMonth < startMonth) newMonth = startMonth;
    if (newYear === endYear && newMonth > endMonth) newMonth = endMonth;

    // Clamp day based on year/month
    const startDay = periodStartDate.getDate();
    const endDay = periodEndDate.getDate();
    const daysInNewMonth = getDaysInMonth(newYear, newMonth);

    if (newDay > daysInNewMonth) newDay = daysInNewMonth;
    if (newYear === startYear && newMonth === startMonth && newDay < startDay) newDay = startDay;
    if (newYear === endYear && newMonth === endMonth && newDay > endDay) newDay = endDay;

    const newDate = `${newYear}-${String(newMonth).padStart(2, "0")}-${String(newDay).padStart(2, "0")}`;
    setDateISO(newDate);
    setSelectedYear(newYear);
    setSelectedMonth(newMonth);
    setSelectedDay(newDay);
  };

  const usedCurrencies = state.usedCurrencies ?? [];
  const currenciesInExistingExpenses = useMemo(
    () => [...new Set((activeSheet?.expenses ?? []).map((e) => e.inputCurrency ?? state.baseCurrency).filter((c) => c !== state.baseCurrency))],
    [activeSheet?.expenses, state.baseCurrency]
  );
  const showCurrencyDropdown = shouldShowCurrencyDropdown(
    inputCurrency,
    state.baseCurrency,
    usedCurrencies,
    currenciesInExistingExpenses
  );
  const isOtherCurrency = inputCurrency !== state.baseCurrency;
  const showRateSection = isOtherCurrency && (!editId || inputCurrency !== editingEntryInputCurrency);

  const save = () => {
    if (!activeSheet) return;
    const inputNum = parseAmountInput(amount);
    if (inputNum === null || inputNum <= 0 || !categoryId || !memberId) {
      Alert.alert(t("invalidInput"));
      return;
    }
    const rateNum = Number(normalizeRateInput(rateToBase));
    const hasValidRate = !isNaN(rateNum) && rateNum > 0;
    const savedDateISO = `${selectedYear}-${String(selectedMonth).padStart(2, "0")}-${String(selectedDay).padStart(2, "0")}`;
    const cachedRate = isOtherCurrency && !hasValidRate ? rateCache[`${inputCurrency}:${state.baseCurrency}:${savedDateISO}`] : undefined;
    const rateToSave = hasValidRate ? rateNum : (cachedRate != null && cachedRate > 0 ? cachedRate : undefined);
    const amountInBase = !isOtherCurrency ? inputNum : (hasValidRate ? inputNum * rateNum : (rateToSave != null ? inputNum * rateToSave : inputNum));
    const amountToStore = isOtherCurrency ? inputNum : amountInBase;
    const currencyForAmount = isOtherCurrency ? inputCurrency : state.baseCurrency;
    const expensePayload = {
      dateISO: savedDateISO,
      amount: roundAmountForCurrency(amountToStore, currencyForAmount),
      memo: memo.trim() || undefined,
      memberId,
      categoryId,
      inputCurrency: currencyForAmount,
      ...(isOtherCurrency && rateToSave != null ? { rate: rateToSave } : {}),
      updatedAt: toISODateTime(new Date()),
    };
    Keyboard.dismiss();
    setState((prev) => ({
      ...prev,
      sheets: prev.sheets.map((sh) =>
        sh.id === activeSheet.id
          ? {
              ...sh,
              expenses: editId
                ? sh.expenses.map((e) => (e.id === editId ? { ...e, ...expensePayload } : e))
                : [{ id: uuid(), ...expensePayload }, ...sh.expenses],
            }
          : sh
      ),
    }));
    // Save last entry for next time (date, category, member)
    saveLastEntry({
      dateISO: savedDateISO,
      categoryId,
      memberId,
    });
    // Close screen immediately after saving
    router.back();
  };

  const fetchRateAndSet = async () => {
    if (inputCurrency === state.baseCurrency) return;
    setRateLoading(true);
    const result = await fetchRate(inputCurrency, state.baseCurrency, dateISO);
    setRateLoading(false);
    if (result) setRateToBase(String(result.rate));
    else Alert.alert(t("rateError"));
  };

  useEffect(() => {
    if (!activeSheet || inputCurrency === state.baseCurrency || editId) return;
    let cancelled = false;
    (async () => {
      setRateLoading(true);
      const result = await fetchRate(inputCurrency, state.baseCurrency, dateISO);
      if (cancelled) return;
      setRateLoading(false);
      if (result) setRateToBase(String(result.rate));
    })();
    return () => {
      cancelled = true;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [inputCurrency, dateISO, state.baseCurrency, activeSheet?.id, editId]);

  // This screen is for editing only - redirect if no editId
  useEffect(() => {
    if (!editId) {
      router.replace("/(tabs)/add");
    }
  }, [editId, router]);

  if (!editId) {
    return <View style={{ flex: 1, backgroundColor: theme.background }} />;
  }

  if (!activeSheet) {
    return (
      <View style={[styles.center, { flex: 1, backgroundColor: theme.background }]}>
        <Text style={{ color: theme.text }}>{t("setupRequired")}</Text>
        <Pressable
          onPress={() => router.back()}
          style={({ pressed }) => [
            styles.backBtn,
            { backgroundColor: theme.surface, borderColor: theme.border, borderWidth: 1, opacity: pressed ? 0.7 : 1 },
          ]}
        >
          <Text style={{ color: theme.text, fontWeight: "700" }}>{t("cancel")}</Text>
        </Pressable>
      </View>
    );
  }

  return (
    <GlassModalContainer>
      <KeyboardAvoidingView style={{ flex: 1 }} behavior={Platform.OS === "ios" ? "padding" : undefined} keyboardVerticalOffset={0}>
      <ScrollView ref={scrollViewRef} style={styles.scrollView} contentInsetAdjustmentBehavior="automatic" contentContainerStyle={{ paddingTop: 16, paddingBottom: 120 }} keyboardShouldPersistTaps="handled">
        <View style={{ gap: 12, paddingHorizontal: 18 }}>
          <View style={[styles.card, { backgroundColor: theme.surface }]}>
            <Text style={[styles.label, { color: theme.subText }]}>Date</Text>
            <View style={styles.row}>
              <View style={[styles.dropdownCol, { flex: 1.2 }]}>
                <Dropdown options={yearOptions.map((y) => ({ label: String(y), value: y }))} selectedValue={selectedYear} onValueChange={(y) => handleDateChange(y, selectedMonth, selectedDay)} theme={theme} />
              </View>
              <View style={[styles.dropdownCol, { flex: 1.2 }]}>
                <Dropdown options={monthOptions.map((m) => ({ label: monthNames[m - 1], value: m }))} selectedValue={selectedMonth} onValueChange={(m) => handleDateChange(selectedYear, m, Math.min(selectedDay, getDaysInMonth(selectedYear, m)))} theme={theme} />
              </View>
              <View style={styles.dropdownCol}>
                <Dropdown options={dayOptions.map((d) => ({ label: String(d), value: d }))} selectedValue={selectedDay} onValueChange={(d) => handleDateChange(selectedYear, selectedMonth, d)} theme={theme} />
              </View>
            </View>
            <Text style={[styles.label, { color: theme.subText }]}>Category</Text>
            <Dropdown options={categories.map((c) => ({ label: c.name, value: c.id }))} selectedValue={categoryId ?? ""} onValueChange={(v) => setCategoryId(v || null)} theme={theme} placeholder="Select category" />
            <Text style={[styles.label, { color: theme.subText }]}>Member</Text>
            <Dropdown options={members.map((m) => ({ label: m.name, value: m.id }))} selectedValue={memberId ?? ""} onValueChange={(v) => setMemberId(v || null)} theme={theme} placeholder="Select member" />
            <Text style={[styles.label, { color: theme.subText }]}>{showCurrencyDropdown ? t("amountInCurrency") : t("amount")}</Text>
            {showCurrencyDropdown && (
              <Dropdown
                options={getPickerCurrencies(state.baseCurrency, [...usedCurrencies, ...currenciesInExistingExpenses], inputCurrency, editId ? editingEntryInputCurrency ?? undefined : undefined).map((code) => ({ label: code, value: code }))}
                selectedValue={inputCurrency}
                onValueChange={(v) => {
                  setInputCurrency(v);
                  if (v === state.baseCurrency) setRateToBase("");
                }}
                theme={theme}
              />
            )}
            <TextInput
              value={amount}
              onChangeText={(v) => setAmount(v.replace(/,/g, "").replace(/[^\d.]/g, ""))}
              placeholder={t("amount")}
              placeholderTextColor={theme.subText}
              keyboardType="decimal-pad"
              returnKeyType="done"
              inputAccessoryViewID={Platform.OS === "ios" ? INPUT_ACCESSORY_VIEW_ID : undefined}
              style={themedStyles.input}
            />
            {showRateSection && (
              <>
                <Text style={[styles.label, { color: theme.subText }]}>
                  {rateToBase.trim() ? t("rateLabelWithRate", { input: inputCurrency, base: state.baseCurrency, rate: rateToBase.trim() }) : t("rateLabel", { input: inputCurrency, base: state.baseCurrency })}
                </Text>
                <Text style={[styles.caption, { color: theme.subText, marginBottom: 4 }]}>{t("rateForDate", { date: dateISO })}</Text>
                <View style={styles.row}>
                  <TextInput
                    value={formatRateInput(rateToBase)}
                    onChangeText={(v) => setRateToBase(normalizeRateInput(v))}
                    keyboardType="decimal-pad"
                    returnKeyType="done"
                    inputAccessoryViewID={Platform.OS === "ios" ? INPUT_ACCESSORY_VIEW_ID : undefined}
                    style={[themedStyles.input, { flex: 1 }]}
                    placeholder={t("ratePlaceholder")}
                    placeholderTextColor={theme.subText}
                  />
                  <Pressable
                    onPress={fetchRateAndSet}
                    disabled={rateLoading}
                    style={({ pressed }) => [
                      themedStyles.btnPrimary,
                      { flex: 0, minWidth: 100 },
                      pressedStyle(pressed || rateLoading),
                    ]}
                  >
                    <Text style={themedStyles.btnPrimaryText}>{rateLoading ? t("rateFetching") : t("getRate")}</Text>
                  </Pressable>
                </View>
                <Text style={[styles.caption, { color: theme.subText }]}>
                  ≈ {(() => {
                    const n = parseAmountInput(amount);
                    const r = Number(normalizeRateInput(rateToBase));
                    const conv = n != null && n > 0 && !isNaN(r) && r > 0 ? n * r : NaN;
                    return Number.isFinite(conv) ? formatMoney(conv, state.baseCurrency) : "—";
                  })()}
                </Text>
                <Text style={[styles.caption, { color: theme.subText }]}>{t("rateHelp")}</Text>
              </>
            )}
            <View onLayout={(e) => { memoInputY.current = e.nativeEvent.layout.y; }}>
              <View style={styles.labelRow}>
                <Text style={[styles.label, { color: theme.subText }]}>{t("memo")}</Text>
                <Text style={[styles.charCount, { color: theme.subText }]}>{memo.length}/40</Text>
              </View>
              <TextInput
                ref={memoInputRef}
                value={memo}
                onChangeText={setMemo}
                onFocus={handleMemoFocus}
                onBlur={handleMemoBlur}
                multiline
                numberOfLines={2}
                maxLength={40}
                blurOnSubmit
                inputAccessoryViewID={Platform.OS === "ios" ? INPUT_ACCESSORY_VIEW_ID : undefined}
                style={[themedStyles.input, styles.memoInput]}
                placeholderTextColor={theme.subText}
              />
            </View>
            <View style={styles.buttonRow}>
              <Pressable
                onPress={() => router.back()}
                style={({ pressed }) => [themedStyles.btnCancel, { flex: 1 }, pressedStyle(pressed)]}
              >
                <Text style={themedStyles.btnCancelText}>{t("cancel")}</Text>
              </Pressable>
              <Pressable
                onPress={save}
                style={({ pressed }) => [themedStyles.btnPrimary, { flex: 1 }, pressedStyle(pressed)]}
              >
                <Text style={themedStyles.btnPrimaryText}>{editId ? t("update") : t("add")}</Text>
              </Pressable>
            </View>
          </View>
        </View>
      </ScrollView>
      {Platform.OS === "ios" && (
        <InputAccessoryView nativeID={INPUT_ACCESSORY_VIEW_ID}>
          <View style={[styles.accessoryView, { backgroundColor: theme.surface, borderTopColor: theme.border }]}>
            <View style={{ flex: 1 }} />
            <Pressable onPress={dismissKeyboard} style={styles.doneButton} hitSlop={8}>
              <Text style={[styles.doneButtonText, { color: theme.buttonPrimary }]}>{t("done")}</Text>
            </Pressable>
          </View>
        </InputAccessoryView>
      )}
      </KeyboardAvoidingView>
    </GlassModalContainer>
  );
}

const styles = StyleSheet.create({
  ...sharedStyles.layout,
  ...sharedStyles.form,
  ...sharedStyles.list,
  // Local overrides
  center: { flex: 1, alignItems: "center", justifyContent: "center", gap: 12 },
  label: { fontSize: 12 },
  caption: { fontSize: 11 },
  labelRow: { flexDirection: "row", justifyContent: "space-between", alignItems: "center" },
  charCount: { fontSize: 11 },
  memoInput: { height: 56, textAlignVertical: "top", paddingTop: 8 },
  input: { paddingHorizontal: 12, paddingVertical: 12, borderRadius: 12, borderWidth: 1, fontSize: 16 },
  btn: { paddingVertical: 12, borderRadius: 12, alignItems: "center", flex: 1 },
  btnText: { color: "#fff", fontWeight: "700" },
  buttonRow: { flexDirection: "row", gap: 10 },
  backBtn: { paddingVertical: 12, paddingHorizontal: 24, borderRadius: 12 },
  accessoryView: {
    flexDirection: "row",
    alignItems: "center",
    paddingHorizontal: 12,
    paddingVertical: 8,
    borderTopWidth: StyleSheet.hairlineWidth,
  },
  doneButton: {
    paddingHorizontal: 12,
    paddingVertical: 8,
  },
  doneButtonText: {
    fontSize: 17,
    fontWeight: "600",
  },
});

import { Dropdown } from "@/components/dropdown";
import { GlassModalContainer } from "@/components/glass-modal-container";
import { sharedStyles } from "@/constants/sharedStyles";
import { useModalTheme } from "@/hooks/use-modal-theme";
import { useLanguage } from "@/hooks/use-language";
import { getInitialDate, useLastExpenseEntry } from "@/hooks/use-last-expense-entry";
import { pressedStyle, useThemedStyles } from "@/hooks/use-themed-styles";
import { getPickerCurrencies, shouldShowCurrencyDropdown } from "@/src/currency-input";
import { fetchRate } from "@/src/rates";
import { useStore } from "@/src/store";
import { formatMoney, formatRateInput, normalizeRateInput, parseAmountInput, parseLocalDate, roundAmountForCurrency, toISODate, toISODateTime, uuid } from "@/src/utils";
import { useNavigation } from "@react-navigation/native";
import { useFocusEffect, useLocalSearchParams, useRouter } from "expo-router";
import React, { useCallback, useEffect, useLayoutEffect, useMemo, useRef, useState } from "react";
import { Alert, InputAccessoryView, Keyboard, KeyboardAvoidingView, Platform, Pressable, ScrollView, StyleSheet, Text, TextInput, View } from "react-native";

const INPUT_ACCESSORY_VIEW_ID = "expense-entry-keyboard";

export default function ExpenseEntryScreen() {
  const router = useRouter();
  const params = useLocalSearchParams<{ id?: string }>();
  const editId = params.id ?? null;
  const { state, setState, activeSheet, rateCache, fillRateCacheForActiveSheet } = useStore();
  const theme = useAppTheme();
  const themedStyles = useThemedStyles();
  const { t } = useLanguage();
  const navigation = useNavigation();
  const { lastEntry, loaded: lastEntryLoaded, saveLastEntry } = useLastExpenseEntry();

  // Set header title for edit mode
  useLayoutEffect(() => {
    navigation.setOptions({
      title: t("updateExpense"),
    });
  }, [navigation, t]);

  const periodStart = activeSheet?.periodStartISO;
  const periodEnd = activeSheet?.periodEndISO;
  const todayISO = toISODate(new Date());
  const initialDate = (periodStart && periodEnd && todayISO >= periodStart && todayISO <= periodEnd) ? todayISO : (periodStart ?? todayISO);

  const [dateISO, setDateISO] = useState(initialDate);
  const dateObj = parseLocalDate(dateISO);
  const [selectedYear, setSelectedYear] = useState(dateObj.getFullYear());
  const [selectedMonth, setSelectedMonth] = useState(dateObj.getMonth() + 1);
  const [selectedDay, setSelectedDay] = useState(dateObj.getDate());
  const [amount, setAmount] = useState("");
  const [memo, setMemo] = useState("");
  const [inputCurrency, setInputCurrency] = useState<string>(state.baseCurrency);
  const [rateToBase, setRateToBase] = useState("");
  const [rateLoading, setRateLoading] = useState(false);
  const [editingEntryInputCurrency, setEditingEntryInputCurrency] = useState<string | null>(null);
  const [lastEntryApplied, setLastEntryApplied] = useState(false);

  const scrollViewRef = useRef<ScrollView>(null);
  const memoInputRef = useRef<TextInput>(null);
  const memoInputY = useRef(0);
  const [memoFocused, setMemoFocused] = useState(false);

  const handleMemoFocus = useCallback(() => {
    setMemoFocused(true);
    // Scroll to show memo input when focused
    setTimeout(() => {
      scrollViewRef.current?.scrollTo({ y: memoInputY.current - 100, animated: true });
    }, 100);
  }, []);

  const handleMemoBlur = useCallback(() => {
    setMemoFocused(false);
    // Reset scroll position when keyboard is dismissed
    setTimeout(() => {
      scrollViewRef.current?.scrollTo({ y: 0, animated: true });
    }, 100);
  }, []);

  const dismissKeyboard = useCallback(() => {
    Keyboard.dismiss();
    setMemoFocused(false);
    setTimeout(() => {
      scrollViewRef.current?.scrollTo({ y: 0, animated: true });
    }, 100);
  }, []);

  // Reset scroll position when keyboard hides (for all input fields)
  useEffect(() => {
    const hideListener = Keyboard.addListener(
      Platform.OS === "ios" ? "keyboardWillHide" : "keyboardDidHide",
      () => {
        setMemoFocused(false);
        setTimeout(() => {
          scrollViewRef.current?.scrollTo({ y: 0, animated: true });
        }, 100);
      }
    );
    return () => hideListener.remove();
  }, []);

  const categories = useMemo(() => activeSheet?.categories ?? [], [activeSheet?.categories]);
  const members = useMemo(() => state.members ?? [], [state.members]);
  const [categoryId, setCategoryId] = useState<string | null>(categories[0]?.id ?? null);
  const [memberId, setMemberId] = useState<string | null>(members[0]?.id ?? null);

  useFocusEffect(
    useCallback(() => {
      if (activeSheet) fillRateCacheForActiveSheet();
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeSheet?.id, fillRateCacheForActiveSheet])
  );

  useEffect(() => {
    if (!activeSheet?.periodStartISO || !activeSheet?.periodEndISO) return;
    const today = toISODate(new Date());
    const start = activeSheet.periodStartISO;
    const end = activeSheet.periodEndISO;
    const nextInitial = (today >= start && today <= end) ? today : start;
    setDateISO(nextInitial);
    const d = parseLocalDate(nextInitial);
    setSelectedYear(d.getFullYear());
    setSelectedMonth(d.getMonth() + 1);
    setSelectedDay(d.getDate());
  }, [activeSheet?.id, activeSheet?.periodStartISO, activeSheet?.periodEndISO]);

  // Restore last entry values (only for new entries, not edits)
  useEffect(() => {
    if (editId || !lastEntryLoaded || lastEntryApplied || !activeSheet) return;
    setLastEntryApplied(true);

    // Restore date (only if saved today)
    const restoredDate = getInitialDate(lastEntry, periodStart, periodEnd);
    setDateISO(restoredDate);
    const d = parseLocalDate(restoredDate);
    setSelectedYear(d.getFullYear());
    setSelectedMonth(d.getMonth() + 1);
    setSelectedDay(d.getDate());

    // Restore category (if it still exists in current sheet)
    if (lastEntry?.categoryId) {
      const categoryExists = categories.some((c) => c.id === lastEntry.categoryId);
      if (categoryExists) {
        setCategoryId(lastEntry.categoryId);
      }
    }

    // Restore member (if it still exists)
    if (lastEntry?.memberId) {
      const memberExists = members.some((m) => m.id === lastEntry.memberId);
      if (memberExists) {
        setMemberId(lastEntry.memberId);
      }
    }
  }, [editId, lastEntryLoaded, lastEntryApplied, lastEntry, activeSheet, periodStart, periodEnd, categories, members]);

  useEffect(() => {
    if (!editId || !activeSheet) return;
    const e = activeSheet.expenses.find((ex) => ex.id === editId);
    if (!e) return;
    const entryCurrency = e.inputCurrency ?? state.baseCurrency;
    setEditingEntryInputCurrency(entryCurrency);
    setDateISO(e.dateISO);
    const d = parseLocalDate(e.dateISO);
    setSelectedYear(d.getFullYear());
    setSelectedMonth(d.getMonth() + 1);
    setSelectedDay(d.getDate());
    setCategoryId(e.categoryId ?? categories[0]?.id ?? null);
    setMemberId(e.memberId ?? members[0]?.id ?? null);
    setMemo(e.memo || "");
    setAmount(String(e.amount));
    if (e.inputCurrency != null && e.inputCurrency !== state.baseCurrency) {
      setInputCurrency(e.inputCurrency);
      setRateToBase(e.rate != null ? String(e.rate) : "");
    } else {
      setInputCurrency(state.baseCurrency);
      setRateToBase("");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [editId, activeSheet?.id]);

  useEffect(() => {
    if (!editingEntryInputCurrency) setInputCurrency(state.baseCurrency);
  }, [state.baseCurrency, editingEntryInputCurrency]);

  // Parse period boundaries
  const periodStartDate = useMemo(() => periodStart ? parseLocalDate(periodStart) : null, [periodStart]);
  const periodEndDate = useMemo(() => periodEnd ? parseLocalDate(periodEnd) : null, [periodEnd]);

  const yearOptions = useMemo(() => {
    if (!periodStartDate || !periodEndDate) return [new Date().getFullYear()];
    const start = periodStartDate.getFullYear();
    const end = periodEndDate.getFullYear();
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }, [periodStartDate, periodEndDate]);

  const monthNames = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

  // Filter months based on selected year and period
  const monthOptions = useMemo(() => {
    if (!periodStartDate || !periodEndDate) return Array.from({ length: 12 }, (_, i) => i + 1);
    const startYear = periodStartDate.getFullYear();
    const endYear = periodEndDate.getFullYear();
    const startMonth = periodStartDate.getMonth() + 1;
    const endMonth = periodEndDate.getMonth() + 1;

    let minMonth = 1;
    let maxMonth = 12;
    if (selectedYear === startYear) minMonth = startMonth;
    if (selectedYear === endYear) maxMonth = endMonth;

    return Array.from({ length: maxMonth - minMonth + 1 }, (_, i) => minMonth + i);
  }, [periodStartDate, periodEndDate, selectedYear]);

  // Filter days based on selected year/month and period
  const getDaysInMonth = (y: number, m: number) => new Date(y, m, 0).getDate();
  const dayOptions = useMemo(() => {
    const daysInMonth = getDaysInMonth(selectedYear, selectedMonth);
    if (!periodStartDate || !periodEndDate) return Array.from({ length: daysInMonth }, (_, i) => i + 1);

    const startYear = periodStartDate.getFullYear();
    const startMonth = periodStartDate.getMonth() + 1;
    const startDay = periodStartDate.getDate();
    const endYear = periodEndDate.getFullYear();
    const endMonth = periodEndDate.getMonth() + 1;
    const endDay = periodEndDate.getDate();

    let minDay = 1;
    let maxDay = daysInMonth;
    if (selectedYear === startYear && selectedMonth === startMonth) minDay = startDay;
    if (selectedYear === endYear && selectedMonth === endMonth) maxDay = Math.min(maxDay, endDay);

    return Array.from({ length: maxDay - minDay + 1 }, (_, i) => minDay + i);
  }, [selectedYear, selectedMonth, periodStartDate, periodEndDate]);

  const handleDateChange = (y: number, m: number, d: number) => {
    // Clamp values to period boundaries
    if (!periodStartDate || !periodEndDate) {
      setDateISO(`${y}-${String(m).padStart(2, "0")}-${String(d).padStart(2, "0")}`);
      setSelectedYear(y);
      setSelectedMonth(m);
      setSelectedDay(d);
      return;
    }

    let newYear = y;
    let newMonth = m;
    let newDay = d;

    // Clamp month based on year
    const startYear = periodStartDate.getFullYear();
    const endYear = periodEndDate.getFullYear();
    const startMonth = periodStartDate.getMonth() + 1;
    const endMonth = periodEndDate.getMonth() + 1;

    if (newYear === startYear && newMonth < startMonth) newMonth = startMonth;
    if (newYear === endYear && newMonth > endMonth) newMonth = endMonth;

    // Clamp day based on year/month
    const startDay = periodStartDate.getDate();
    const endDay = periodEndDate.getDate();
    const daysInNewMonth = getDaysInMonth(newYear, newMonth);

    if (newDay > daysInNewMonth) newDay = daysInNewMonth;
    if (newYear === startYear && newMonth === startMonth && newDay < startDay) newDay = startDay;
    if (newYear === endYear && newMonth === endMonth && newDay > endDay) newDay = endDay;

    const newDate = `${newYear}-${String(newMonth).padStart(2, "0")}-${String(newDay).padStart(2, "0")}`;
    setDateISO(newDate);
    setSelectedYear(newYear);
    setSelectedMonth(newMonth);
    setSelectedDay(newDay);
  };

  const usedCurrencies = state.usedCurrencies ?? [];
  const currenciesInExistingExpenses = useMemo(
    () => [...new Set((activeSheet?.expenses ?? []).map((e) => e.inputCurrency ?? state.baseCurrency).filter((c) => c !== state.baseCurrency))],
    [activeSheet?.expenses, state.baseCurrency]
  );
  const showCurrencyDropdown = shouldShowCurrencyDropdown(
    inputCurrency,
    state.baseCurrency,
    usedCurrencies,
    currenciesInExistingExpenses
  );
  const isOtherCurrency = inputCurrency !== state.baseCurrency;
  const showRateSection = isOtherCurrency && (!editId || inputCurrency !== editingEntryInputCurrency);

  const save = () => {
    if (!activeSheet) return;
    const inputNum = parseAmountInput(amount);
    if (inputNum === null || inputNum <= 0 || !categoryId || !memberId) {
      Alert.alert(t("invalidInput"));
      return;
    }
    const rateNum = Number(normalizeRateInput(rateToBase));
    const hasValidRate = !isNaN(rateNum) && rateNum > 0;
    const savedDateISO = `${selectedYear}-${String(selectedMonth).padStart(2, "0")}-${String(selectedDay).padStart(2, "0")}`;
    const cachedRate = isOtherCurrency && !hasValidRate ? rateCache[`${inputCurrency}:${state.baseCurrency}:${savedDateISO}`] : undefined;
    const rateToSave = hasValidRate ? rateNum : (cachedRate != null && cachedRate > 0 ? cachedRate : undefined);
    const amountInBase = !isOtherCurrency ? inputNum : (hasValidRate ? inputNum * rateNum : (rateToSave != null ? inputNum * rateToSave : inputNum));
    const amountToStore = isOtherCurrency ? inputNum : amountInBase;
    const currencyForAmount = isOtherCurrency ? inputCurrency : state.baseCurrency;
    const expensePayload = {
      dateISO: savedDateISO,
      amount: roundAmountForCurrency(amountToStore, currencyForAmount),
      memo: memo.trim() || undefined,
      memberId,
      categoryId,
      inputCurrency: currencyForAmount,
      ...(isOtherCurrency && rateToSave != null ? { rate: rateToSave } : {}),
      updatedAt: toISODateTime(new Date()),
    };
    Keyboard.dismiss();
    setState((prev) => ({
      ...prev,
      sheets: prev.sheets.map((sh) =>
        sh.id === activeSheet.id
          ? {
              ...sh,
              expenses: editId
                ? sh.expenses.map((e) => (e.id === editId ? { ...e, ...expensePayload } : e))
                : [{ id: uuid(), ...expensePayload }, ...sh.expenses],
            }
          : sh
      ),
    }));
    // Save last entry for next time (date, category, member)
    saveLastEntry({
      dateISO: savedDateISO,
      categoryId,
      memberId,
    });
    // Close screen immediately after saving
    router.back();
  };

  const fetchRateAndSet = async () => {
    if (inputCurrency === state.baseCurrency) return;
    setRateLoading(true);
    const result = await fetchRate(inputCurrency, state.baseCurrency, dateISO);
    setRateLoading(false);
    if (result) setRateToBase(String(result.rate));
    else Alert.alert(t("rateError"));
  };

  useEffect(() => {
    if (!activeSheet || inputCurrency === state.baseCurrency || editId) return;
    let cancelled = false;
    (async () => {
      setRateLoading(true);
      const result = await fetchRate(inputCurrency, state.baseCurrency, dateISO);
      if (cancelled) return;
      setRateLoading(false);
      if (result) setRateToBase(String(result.rate));
    })();
    return () => {
      cancelled = true;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [inputCurrency, dateISO, state.baseCurrency, activeSheet?.id, editId]);

  // This screen is for editing only - redirect if no editId
  useEffect(() => {
    if (!editId) {
      router.replace("/(tabs)/add");
    }
  }, [editId, router]);

  if (!editId) {
    return <View style={{ flex: 1, backgroundColor: theme.background }} />;
  }

  if (!activeSheet) {
    return (
      <View style={[styles.center, { flex: 1, backgroundColor: theme.background }]}>
        <Text style={{ color: theme.text }}>{t("setupRequired")}</Text>
        <Pressable
          onPress={() => router.back()}
          style={({ pressed }) => [
            styles.backBtn,
            { backgroundColor: theme.surface, borderColor: theme.border, borderWidth: 1, opacity: pressed ? 0.7 : 1 },
          ]}
        >
          <Text style={{ color: theme.text, fontWeight: "700" }}>{t("cancel")}</Text>
        </Pressable>
      </View>
    );
  }

  return (
    <GlassModalContainer>
      <KeyboardAvoidingView style={{ flex: 1 }} behavior={Platform.OS === "ios" ? "padding" : undefined} keyboardVerticalOffset={0}>
      <ScrollView ref={scrollViewRef} style={styles.scrollView} contentInsetAdjustmentBehavior="automatic" contentContainerStyle={{ paddingTop: 16, paddingBottom: 120 }} keyboardShouldPersistTaps="handled">
        <View style={{ gap: 12, paddingHorizontal: 18 }}>
          <View style={[styles.card, { backgroundColor: theme.surface }]}>
            <Text style={[styles.label, { color: theme.subText }]}>Date</Text>
            <View style={styles.row}>
              <View style={[styles.dropdownCol, { flex: 1.2 }]}>
                <Dropdown options={yearOptions.map((y) => ({ label: String(y), value: y }))} selectedValue={selectedYear} onValueChange={(y) => handleDateChange(y, selectedMonth, selectedDay)} theme={theme} />
              </View>
              <View style={[styles.dropdownCol, { flex: 1.2 }]}>
                <Dropdown options={monthOptions.map((m) => ({ label: monthNames[m - 1], value: m }))} selectedValue={selectedMonth} onValueChange={(m) => handleDateChange(selectedYear, m, Math.min(selectedDay, getDaysInMonth(selectedYear, m)))} theme={theme} />
              </View>
              <View style={styles.dropdownCol}>
                <Dropdown options={dayOptions.map((d) => ({ label: String(d), value: d }))} selectedValue={selectedDay} onValueChange={(d) => handleDateChange(selectedYear, selectedMonth, d)} theme={theme} />
              </View>
            </View>
            <Text style={[styles.label, { color: theme.subText }]}>Category</Text>
            <Dropdown options={categories.map((c) => ({ label: c.name, value: c.id }))} selectedValue={categoryId ?? ""} onValueChange={(v) => setCategoryId(v || null)} theme={theme} placeholder="Select category" />
            <Text style={[styles.label, { color: theme.subText }]}>Member</Text>
            <Dropdown options={members.map((m) => ({ label: m.name, value: m.id }))} selectedValue={memberId ?? ""} onValueChange={(v) => setMemberId(v || null)} theme={theme} placeholder="Select member" />
            <Text style={[styles.label, { color: theme.subText }]}>{showCurrencyDropdown ? t("amountInCurrency") : t("amount")}</Text>
            {showCurrencyDropdown && (
              <Dropdown
                options={getPickerCurrencies(state.baseCurrency, [...usedCurrencies, ...currenciesInExistingExpenses], inputCurrency, editId ? editingEntryInputCurrency ?? undefined : undefined).map((code) => ({ label: code, value: code }))}
                selectedValue={inputCurrency}
                onValueChange={(v) => {
                  setInputCurrency(v);
                  if (v === state.baseCurrency) setRateToBase("");
                }}
                theme={theme}
              />
            )}
            <TextInput
              value={amount}
              onChangeText={(v) => setAmount(v.replace(/,/g, "").replace(/[^\d.]/g, ""))}
              placeholder={t("amount")}
              placeholderTextColor={theme.subText}
              keyboardType="decimal-pad"
              returnKeyType="done"
              inputAccessoryViewID={Platform.OS === "ios" ? INPUT_ACCESSORY_VIEW_ID : undefined}
              style={themedStyles.input}
            />
            {showRateSection && (
              <>
                <Text style={[styles.label, { color: theme.subText }]}>
                  {rateToBase.trim() ? t("rateLabelWithRate", { input: inputCurrency, base: state.baseCurrency, rate: rateToBase.trim() }) : t("rateLabel", { input: inputCurrency, base: state.baseCurrency })}
                </Text>
                <Text style={[styles.caption, { color: theme.subText, marginBottom: 4 }]}>{t("rateForDate", { date: dateISO })}</Text>
                <View style={styles.row}>
                  <TextInput
                    value={formatRateInput(rateToBase)}
                    onChangeText={(v) => setRateToBase(normalizeRateInput(v))}
                    keyboardType="decimal-pad"
                    returnKeyType="done"
                    inputAccessoryViewID={Platform.OS === "ios" ? INPUT_ACCESSORY_VIEW_ID : undefined}
                    style={[themedStyles.input, { flex: 1 }]}
                    placeholder={t("ratePlaceholder")}
                    placeholderTextColor={theme.subText}
                  />
                  <Pressable
                    onPress={fetchRateAndSet}
                    disabled={rateLoading}
                    style={({ pressed }) => [
                      themedStyles.btnPrimary,
                      { flex: 0, minWidth: 100 },
                      pressedStyle(pressed || rateLoading),
                    ]}
                  >
                    <Text style={themedStyles.btnPrimaryText}>{rateLoading ? t("rateFetching") : t("getRate")}</Text>
                  </Pressable>
                </View>
                <Text style={[styles.caption, { color: theme.subText }]}>
                  ≈ {(() => {
                    const n = parseAmountInput(amount);
                    const r = Number(normalizeRateInput(rateToBase));
                    const conv = n != null && n > 0 && !isNaN(r) && r > 0 ? n * r : NaN;
                    return Number.isFinite(conv) ? formatMoney(conv, state.baseCurrency) : "—";
                  })()}
                </Text>
                <Text style={[styles.caption, { color: theme.subText }]}>{t("rateHelp")}</Text>
              </>
            )}
            <View onLayout={(e) => { memoInputY.current = e.nativeEvent.layout.y; }}>
              <View style={styles.labelRow}>
                <Text style={[styles.label, { color: theme.subText }]}>{t("memo")}</Text>
                <Text style={[styles.charCount, { color: theme.subText }]}>{memo.length}/40</Text>
              </View>
              <TextInput
                ref={memoInputRef}
                value={memo}
                onChangeText={setMemo}
                onFocus={handleMemoFocus}
                onBlur={handleMemoBlur}
                multiline
                numberOfLines={2}
                maxLength={40}
                blurOnSubmit
                inputAccessoryViewID={Platform.OS === "ios" ? INPUT_ACCESSORY_VIEW_ID : undefined}
                style={[themedStyles.input, styles.memoInput]}
                placeholderTextColor={theme.subText}
              />
            </View>
            <View style={styles.buttonRow}>
              <Pressable
                onPress={() => router.back()}
                style={({ pressed }) => [themedStyles.btnCancel, { flex: 1 }, pressedStyle(pressed)]}
              >
                <Text style={themedStyles.btnCancelText}>{t("cancel")}</Text>
              </Pressable>
              <Pressable
                onPress={save}
                style={({ pressed }) => [themedStyles.btnPrimary, { flex: 1 }, pressedStyle(pressed)]}
              >
                <Text style={themedStyles.btnPrimaryText}>{editId ? t("update") : t("add")}</Text>
              </Pressable>
            </View>
          </View>
        </View>
      </ScrollView>
      {Platform.OS === "ios" && (
        <InputAccessoryView nativeID={INPUT_ACCESSORY_VIEW_ID}>
          <View style={[styles.accessoryView, { backgroundColor: theme.surface, borderTopColor: theme.border }]}>
            <View style={{ flex: 1 }} />
            <Pressable onPress={dismissKeyboard} style={styles.doneButton} hitSlop={8}>
              <Text style={[styles.doneButtonText, { color: theme.buttonPrimary }]}>{t("done")}</Text>
            </Pressable>
          </View>
        </InputAccessoryView>
      )}
      </KeyboardAvoidingView>
    </GlassModalContainer>
  );
}

const styles = StyleSheet.create({
  ...sharedStyles.layout,
  ...sharedStyles.form,
  ...sharedStyles.list,
  // Local overrides
  center: { flex: 1, alignItems: "center", justifyContent: "center", gap: 12 },
  label: { fontSize: 12 },
  caption: { fontSize: 11 },
  labelRow: { flexDirection: "row", justifyContent: "space-between", alignItems: "center" },
  charCount: { fontSize: 11 },
  memoInput: { height: 56, textAlignVertical: "top", paddingTop: 8 },
  input: { paddingHorizontal: 12, paddingVertical: 12, borderRadius: 12, borderWidth: 1, fontSize: 16 },
  btn: { paddingVertical: 12, borderRadius: 12, alignItems: "center", flex: 1 },
  btnText: { color: "#fff", fontWeight: "700" },
  buttonRow: { flexDirection: "row", gap: 10 },
  backBtn: { paddingVertical: 12, paddingHorizontal: 24, borderRadius: 12 },
  accessoryView: {
    flexDirection: "row",
    alignItems: "center",
    paddingHorizontal: 12,
    paddingVertical: 8,
    borderTopWidth: StyleSheet.hairlineWidth,
  },
  doneButton: {
    paddingHorizontal: 12,
    paddingVertical: 8,
  },
  doneButtonText: {
    fontSize: 17,
    fontWeight: "600",
  },
});

