     1→/**
     2→ * Modal for viewing fixed expenses and savings details.
     3→ */
     4→import React from "react";
     5→import { Alert, Modal, Platform, Pressable, ScrollView, StyleSheet, Text, View } from "react-native";
     6→import { modalStyles } from "../constants/modalStyles";
     7→import { AppThemeColors } from "../constants/theme";
     8→import { useLanguage } from "../hooks/use-language";
     9→import { FixedExpenseItem, SavingItem, Sheet } from "../src/types";
    10→import { formatMoneyInBase } from "../src/utils";
    11→import { RateCache } from "../src/store";
    12→
    13→/** Check if device supports Liquid Glass (iOS 26+) */
    14→const isLiquidGlass = Platform.OS === "ios" && (parseInt(String(Platform.Version), 10) || 0) >= 26;
    15→
    16→export type DetailPanel = "fixed" | "savings" | null;
    17→export type SelectedItem = { type: "fixed" | "savings"; id: string } | null;
    18→
    19→export type DetailPanelModalProps = {
    20→  detailPanel: DetailPanel;
    21→  selectedItem: SelectedItem;
    22→  setSelectedItem: (item: SelectedItem) => void;
    23→  onClose: () => void;
    24→  onEdit: () => void;
    25→  onDelete: (type: "fixed" | "savings", id: string, name: string) => void;
    26→  activeSheet: Sheet | null;
    27→  baseCurrency: string;
    28→  rateCache: RateCache;
    29→  theme: AppThemeColors;
    30→};
    31→
    32→export function DetailPanelModal({
    33→  detailPanel,
    34→  selectedItem,
    35→  setSelectedItem,
    36→  onClose,
    37→  onEdit,
    38→  onDelete,
    39→  activeSheet,
    40→  baseCurrency,
    41→  rateCache,
    42→  theme,
    43→}: DetailPanelModalProps) {
    44→  const { t } = useLanguage();
    45→  const base = baseCurrency;
    46→  const periodStart = activeSheet?.periodStartISO ?? "";
    47→  const opts = { rateCache, dateISO: periodStart };
    48→
    49→  const handleDelete = (item: FixedExpenseItem | SavingItem, type: "fixed" | "savings") => {
    50→    Alert.alert(t("delete"), t("deleteItemConfirm", { name: item.name }), [
    51→      { text: t("cancel"), style: "cancel" },
    52→      {
    53→        text: t("delete"),
    54→        style: "destructive",
    55→        onPress: () => onDelete(type, item.id, item.name),
    56→      },
    57→    ]);
    58→  };
    59→
    60→  return (
    61→    <Modal
    62→      visible={detailPanel !== null}
    63→      animationType="slide"
    64→      presentationStyle="pageSheet"
    65→      onRequestClose={onClose}
