/**
 * Modal for viewing fixed expenses and savings details.
 */
import React from "react";
import { Alert, Modal, Platform, Pressable, ScrollView, StyleSheet, Text, View } from "react-native";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { modalStyles } from "../constants/modalStyles";
import { AppThemeColors } from "../constants/theme";
import { useModalTheme } from "../hooks/use-modal-theme";
import { useLanguage } from "../hooks/use-language";
import { FixedExpenseItem, SavingItem, Sheet } from "../src/types";
import { formatMoneyInBase } from "../src/utils";
import { RateCache } from "../src/store";

/** Check if device supports Liquid Glass (iOS 26+) */
const isLiquidGlass = Platform.OS === "ios" && (parseInt(String(Platform.Version), 10) || 0) >= 26;

export type DetailPanel = "fixed" | "savings" | null;
export type SelectedItem = { type: "fixed" | "savings"; id: string } | null;

export type DetailPanelModalProps = {
  detailPanel: DetailPanel;
  selectedItem: SelectedItem;
  setSelectedItem: (item: SelectedItem) => void;
  onClose: () => void;
  onEdit: () => void;
  onDelete: (type: "fixed" | "savings", id: string, name: string) => void;
  activeSheet: Sheet | null;
  baseCurrency: string;
  rateCache: RateCache;
};

export function DetailPanelModal({
  detailPanel,
  selectedItem,
  setSelectedItem,
  onClose,
  onEdit,
  onDelete,
  activeSheet,
  baseCurrency,
  rateCache,
}: DetailPanelModalProps) {
  const { t } = useLanguage();
  const theme = useModalTheme();
  const insets = useSafeAreaInsets();
  const base = baseCurrency;
  const periodStart = activeSheet?.periodStartISO ?? "";
  const opts = { rateCache, dateISO: periodStart };

  const handleDelete = (item: FixedExpenseItem | SavingItem, type: "fixed" | "savings") => {
    Alert.alert(t("delete"), t("deleteItemConfirm", { name: item.name }), [
      { text: t("cancel"), style: "cancel" },
      {
        text: t("delete"),
        style: "destructive",
        onPress: () => onDelete(type, item.id, item.name),
      },
    ]);
  };

  return (
    <Modal
      visible={detailPanel !== null}
      animationType="slide"
      presentationStyle="pageSheet"
      onRequestClose={onClose}
    >
      <View style={[styles.modalContainer, { backgroundColor: theme.modalBackground }]}>
        <View style={[modalStyles.modalHeader, { backgroundColor: theme.modalBackground, borderBottomColor: theme.border }]}>
          <View style={modalStyles.modalHeaderSide}>
            {selectedItem ? (
              <Pressable onPress={() => setSelectedItem(null)} style={{ alignSelf: "flex-start" }}>
                <Text style={[modalStyles.modalHeaderBtnText, { color: theme.buttonDark }]}>
                  {t("back")}
                </Text>
              </Pressable>
            ) : null}
          </View>
          <View style={modalStyles.modalHeaderCenter}>
            <Text style={[modalStyles.modalTitle, { color: theme.text }]} numberOfLines={1}>
              {detailPanel === "fixed" ? t("fixedExpenses") : t("savings")}
              {selectedItem ? ` ${t("detail")}` : ""}
            </Text>
          </View>
          <View style={modalStyles.modalHeaderSide} />
        </View>
        <ScrollView
          style={[styles.modalScroll, { backgroundColor: theme.modalBackground }]}
          contentInsetAdjustmentBehavior="never"
          contentContainerStyle={[styles.modalScrollContent, { paddingBottom: 80 + insets.bottom }]}
        >
          {/* List view */}
          {!selectedItem && detailPanel === "fixed" && (
            <>
              {(activeSheet?.fixedExpenses ?? []).length === 0 ? (
                <Text style={[styles.modalEmpty, { color: theme.subText }]}>{t("noFixedExpenses")}</Text>
              ) : (
                (activeSheet?.fixedExpenses ?? []).map((it: FixedExpenseItem) => (
                  <Pressable
                    key={it.id}
                    style={[styles.detailRow, { backgroundColor: theme.surface }]}
                    onPress={() => setSelectedItem({ type: "fixed", id: it.id })}
                  >
                    <Text style={[styles.detailRowName, { color: theme.text }]}>{it.name}</Text>
                    <Text style={[styles.detailRowAmount, { color: theme.text }]}>
                      {formatMoneyInBase(it.amount, base, it, opts)}
                    </Text>
                  </Pressable>
                ))
              )}
            </>
          )}
          {!selectedItem && detailPanel === "savings" && (
            <>
              {(activeSheet?.savingsItems ?? []).length === 0 ? (
                <Text style={[styles.modalEmpty, { color: theme.subText }]}>{t("noSavingsItems")}</Text>
              ) : (
                (activeSheet?.savingsItems ?? []).map((it: SavingItem) => (
                  <Pressable
                    key={it.id}
                    style={[styles.detailRow, { backgroundColor: theme.surface }]}
                    onPress={() => setSelectedItem({ type: "savings", id: it.id })}
                  >
                    <Text style={[styles.detailRowName, { color: theme.text }]}>{it.name}</Text>
                    <Text style={[styles.detailRowAmount, { color: theme.text }]}>
                      {formatMoneyInBase(it.amount, base, it, opts)}
                    </Text>
                  </Pressable>
                ))
              )}
            </>
          )}

          {/* Detail view */}
          {selectedItem &&
            (() => {
              const item =
                selectedItem.type === "fixed"
                  ? (activeSheet?.fixedExpenses ?? []).find(
                      (f: FixedExpenseItem) => f.id === selectedItem.id
                    )
                  : (activeSheet?.savingsItems ?? []).find(
                      (s: SavingItem) => s.id === selectedItem.id
                    );
              if (!item)
                return (
                  <Text style={[styles.modalEmpty, { color: theme.subText }]}>{t("itemNotFound")}</Text>
                );
              return (
                <View style={[styles.detailCard, { backgroundColor: theme.surface }]}>
                  <View style={[styles.detailCardRow, { borderBottomColor: theme.border }]}>
                    <Text style={[styles.detailLabel, { color: theme.subText }]}>{t("name")}</Text>
                    <Text style={[styles.detailValue, { color: theme.text }]}>{item.name}</Text>
                  </View>
                  <View style={[styles.detailCardRow, { borderBottomColor: theme.border }]}>
                    <Text style={[styles.detailLabel, { color: theme.subText }]}>{t("amount")}</Text>
                    <Text style={[styles.detailValue, { color: theme.text }]}>
                      {formatMoneyInBase(item.amount, base, item, opts)}
                    </Text>
                  </View>
                  {item.inputCurrency && item.inputCurrency !== baseCurrency && (
                    <View style={[styles.detailCardRow, { borderBottomWidth: 0 }]}>
                      <Text style={[styles.detailLabel, { color: theme.subText }]}>{t("currency")}</Text>
                      <Text style={[styles.detailValue, { color: theme.text }]}>
                        {item.inputCurrency}
                      </Text>
                    </View>
                  )}
                </View>
              );
            })()}
        </ScrollView>

        {/* Floating bottom buttons */}
        <View style={[styles.floatingButtonContainer, { paddingBottom: insets.bottom + 16 }]}>
          <Pressable
            onPress={onEdit}
            style={[styles.floatingBtn, { backgroundColor: theme.buttonDark }]}
          >
            <Text style={styles.floatingBtnText}>{t("editInSetup")}</Text>
          </Pressable>
          {selectedItem &&
            (() => {
              const item =
                selectedItem.type === "fixed"
                  ? (activeSheet?.fixedExpenses ?? []).find(
                      (f: FixedExpenseItem) => f.id === selectedItem.id
                    )
                  : (activeSheet?.savingsItems ?? []).find(
                      (s: SavingItem) => s.id === selectedItem.id
                    );
              if (!item) return null;
              return (
                <Pressable
                  onPress={() => handleDelete(item, selectedItem.type)}
                  style={[
                    styles.floatingBtn,
                    {
                      backgroundColor: theme.modalBackground,
                      borderWidth: 1,
                      borderColor: theme.buttonDanger,
                    },
                  ]}
                >
                  <Text style={[styles.floatingBtnText, { color: theme.buttonDanger }]}>
                    {t("delete")}
                  </Text>
                </Pressable>
              );
            })()}
        </View>
      </View>
    </Modal>
  );
}

const styles = StyleSheet.create({
  modalContainer: { flex: 1 },
  modalScroll: { flex: 1 },
  modalScrollContent: { paddingHorizontal: 20, paddingTop: 24, gap: 12, flexGrow: 1 },
  modalEmpty: { fontSize: 14, paddingVertical: 24, textAlign: "center" },
  detailRow: {
    flexDirection: "row",
    justifyContent: "space-between",
    alignItems: "center",
    padding: 14,
    borderRadius: 12,
    marginBottom: 4,
  },
  detailRowName: { fontSize: 15, fontWeight: "600", flex: 1 },
  detailRowAmount: { fontSize: 15, fontWeight: "700" },
  detailCard: { padding: 16, borderRadius: 16, gap: 0 },
  detailCardRow: {
    flexDirection: "row",
    justifyContent: "space-between",
    alignItems: "center",
    paddingVertical: 12,
    borderBottomWidth: StyleSheet.hairlineWidth,
  },
  detailLabel: { fontSize: 13 },
  detailValue: { fontSize: 15, fontWeight: "600" },
  floatingButtonContainer: {
    position: "absolute",
    bottom: 0,
    left: 0,
    right: 0,
    paddingHorizontal: 20,
    paddingTop: 16,
    gap: 10,
  },
  floatingBtn: {
    paddingVertical: 14,
    borderRadius: 12,
    alignItems: "center",
  },
  floatingBtnText: { color: "#fff", fontWeight: "700", fontSize: 16 },
});

