/**
 * Theme hook for modal screens.
 * On iOS 26+ with Liquid Glass, modals always use dark theme for visibility
 * since the native glass effect creates a dark translucent background.
 */
import { Platform } from "react-native";
import { AppTheme } from "@/constants/theme";
import { useColorScheme } from "@/hooks/use-color-scheme";

/** Check if device supports Liquid Glass (iOS 26+) */
const isLiquidGlass = Platform.OS === "ios" && (parseInt(String(Platform.Version), 10) || 0) >= 26;

export function useModalTheme() {
  const scheme = useColorScheme() ?? "light";

  // iOS 26+ Liquid Glass modals always use dark theme for visibility
  if (isLiquidGlass) {
    return AppTheme.dark;
  }

  return AppTheme[scheme];
}

