/**
 * Glass Modal Container for iOS 26+ Liquid Glass effect.
 * On iOS 26+, the native formSheet presentation handles Liquid Glass automatically,
 * so we just need a transparent background.
 * Falls back to solid background on older iOS and Android.
 */
import React from "react";
import { Platform, StyleSheet, View } from "react-native";
import { useAppTheme } from "@/hooks/use-app-theme";

/** Check if device supports Liquid Glass (iOS 26+) */
const isLiquidGlass = Platform.OS === "ios" && (parseInt(String(Platform.Version), 10) || 0) >= 26;

export type GlassModalContainerProps = {
  children: React.ReactNode;
};

export function GlassModalContainer({ children }: GlassModalContainerProps) {
  const theme = useAppTheme();

  // iOS 26+: Native formSheet handles Liquid Glass, just use transparent background
  if (isLiquidGlass) {
    return (
      <View style={[styles.container, { backgroundColor: "transparent" }]}>
        {children}
      </View>
    );
  }

  // Fallback for older iOS and Android
  return (
    <View style={[styles.container, { backgroundColor: theme.modalBackground }]}>
      {children}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
  },
  content: {
    flex: 1,
  },
});

