import React, { useState } from "react";
import { Alert, Pressable, ScrollView, StyleSheet, Text, View } from "react-native";
import { useLocalSearchParams, useRouter } from "expo-router";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { GlassModalContainer } from "@/components/glass-modal-container";
import { useLanguage } from "@/hooks/use-language";
import { useModalTheme } from "@/hooks/use-modal-theme";
import { useStore } from "@/src/store";
import { FixedExpenseItem, SavingItem } from "@/src/types";
import { formatMoneyInBase } from "@/src/utils";

type SelectedItem = { type: "fixed" | "savings"; id: string } | null;

export default function DetailPanelScreen() {
  const router = useRouter();
  const params = useLocalSearchParams<{ type: "fixed" | "savings" }>();
  const panelType = params.type ?? "fixed";
  const { t } = useLanguage();
  const theme = useModalTheme();
  const insets = useSafeAreaInsets();
  const { state, setState, activeSheet, rateCache } = useStore();

  const [selectedItem, setSelectedItem] = useState<SelectedItem>(null);

  const base = state.baseCurrency;
  const periodStart = activeSheet?.periodStartISO ?? "";
  const opts = { rateCache, dateISO: periodStart };

  const handleDelete = (item: FixedExpenseItem | SavingItem, type: "fixed" | "savings") => {
    Alert.alert(t("delete"), t("deleteItemConfirm", { name: item.name }), [
      { text: t("cancel"), style: "cancel" },
      {
        text: t("delete"),
        style: "destructive",
        onPress: () => {
          setState((prev) => ({
            ...prev,
            sheets: prev.sheets.map((sh) =>
              sh.id === activeSheet?.id
                ? {
                    ...sh,
                    ...(type === "fixed"
                      ? { fixedExpenses: (sh.fixedExpenses ?? []).filter((f) => f.id !== item.id) }
                      : { savingsItems: (sh.savingsItems ?? []).filter((s) => s.id !== item.id) }),
                  }
                : sh
            ),
          }));
          setSelectedItem(null);
        },
      },
    ]);
  };

  const handleEdit = () => {
    router.dismiss();
    router.push("/setup");
  };

  const handleBack = () => {
    if (selectedItem) {
      setSelectedItem(null);
    } else {
      router.back();
    }
  };

  return (
    <GlassModalContainer>
      <ScrollView
        style={styles.scroll}
        contentInsetAdjustmentBehavior="automatic"
        contentContainerStyle={[styles.scrollContent, { paddingBottom: 80 + insets.bottom }]}
      >
        {/* List view */}
        {!selectedItem && panelType === "fixed" && (
          <>
            {(activeSheet?.fixedExpenses ?? []).length === 0 ? (
              <Text style={[styles.empty, { color: theme.subText }]}>{t("noFixedExpenses")}</Text>
            ) : (
              (activeSheet?.fixedExpenses ?? []).map((it: FixedExpenseItem) => (
                <Pressable
                  key={it.id}
                  style={[styles.row, { backgroundColor: theme.surface }]}
                  onPress={() => setSelectedItem({ type: "fixed", id: it.id })}
                >
                  <Text style={[styles.rowName, { color: theme.text }]}>{it.name}</Text>
