                    {formatMoneyInBase(it.amount, base, it, opts)}
                  </Text>
                </Pressable>
              ))
            )}
          </>
        )}
        {!selectedItem && panelType === "savings" && (
          <>
            {(activeSheet?.savingsItems ?? []).length === 0 ? (
              <Text style={[styles.empty, { color: theme.subText }]}>{t("noSavingsItems")}</Text>
            ) : (
              (activeSheet?.savingsItems ?? []).map((it: SavingItem) => (
                <Pressable
                  key={it.id}
                  style={[styles.row, { backgroundColor: theme.surface }]}
                  onPress={() => setSelectedItem({ type: "savings", id: it.id })}
                >
                  <Text style={[styles.rowName, { color: theme.text }]}>{it.name}</Text>
                  <Text style={[styles.rowAmount, { color: theme.text }]}>
                    {formatMoneyInBase(it.amount, base, it, opts)}
                  </Text>
                </Pressable>
              ))
            )}
          </>
        )}

        {/* Detail view */}
        {selectedItem &&
          (() => {
            const item =
              selectedItem.type === "fixed"
                ? (activeSheet?.fixedExpenses ?? []).find(
                    (f: FixedExpenseItem) => f.id === selectedItem.id
                  )
                : (activeSheet?.savingsItems ?? []).find(
                    (s: SavingItem) => s.id === selectedItem.id
                  );
            if (!item)
              return (
                <Text style={[styles.empty, { color: theme.subText }]}>{t("itemNotFound")}</Text>
              );
            return (
              <View style={[styles.card, { backgroundColor: theme.surface }]}>
                <View style={[styles.cardRow, { borderBottomColor: theme.border }]}>
                  <Text style={[styles.cardLabel, { color: theme.subText }]}>{t("name")}</Text>
                  <Text style={[styles.cardValue, { color: theme.text }]}>{item.name}</Text>
                </View>
                <View style={[styles.cardRow, { borderBottomColor: theme.border }]}>
                  <Text style={[styles.cardLabel, { color: theme.subText }]}>{t("amount")}</Text>
                  <Text style={[styles.cardValue, { color: theme.text }]}>
                    {formatMoneyInBase(item.amount, base, item, opts)}
                  </Text>
                </View>
                {item.inputCurrency && item.inputCurrency !== state.baseCurrency && (
                  <View style={[styles.cardRow, { borderBottomWidth: 0 }]}>
                    <Text style={[styles.cardLabel, { color: theme.subText }]}>{t("currency")}</Text>
                    <Text style={[styles.cardValue, { color: theme.text }]}>
                      {item.inputCurrency}
                    </Text>
                  </View>
                )}
              </View>
            );
          })()}
      </ScrollView>

      {/* Floating bottom buttons */}
      <View style={[styles.floatingContainer, { paddingBottom: insets.bottom + 16 }]}>
        <Pressable
          onPress={handleEdit}
          style={[styles.floatingBtn, { backgroundColor: theme.buttonDark }]}
        >
          <Text style={styles.floatingBtnText}>{t("editInSetup")}</Text>
        </Pressable>
        {selectedItem &&
          (() => {
            const item =
              selectedItem.type === "fixed"
                ? (activeSheet?.fixedExpenses ?? []).find(
                    (f: FixedExpenseItem) => f.id === selectedItem.id
                  )
                : (activeSheet?.savingsItems ?? []).find(
                    (s: SavingItem) => s.id === selectedItem.id
                  );
            if (!item) return null;
            return (
              <Pressable
                onPress={() => handleDelete(item, selectedItem.type)}
                style={[
                  styles.floatingBtn,
                  {
                    backgroundColor: theme.modalBackground,
                    borderWidth: 1,
                    borderColor: theme.buttonDanger,
                  },
                ]}
              >
                <Text style={[styles.floatingBtnText, { color: theme.buttonDanger }]}>
                  {t("delete")}
                </Text>
              </Pressable>
            );
          })()}
      </View>
    </GlassModalContainer>
  );
}

const styles = StyleSheet.create({
