     1→import { ErrorBoundary } from "@/components/error-boundary";
     2→import { SyncIndicator } from "@/components/sync-indicator";
     3→import { Stack } from "expo-router";
     4→import * as SplashScreen from "expo-splash-screen";
     5→import React, { useEffect } from "react";
     6→import { Platform, View } from "react-native";
     7→import { GestureHandlerRootView } from "react-native-gesture-handler";
     8→import { SafeAreaProvider, initialWindowMetrics } from "react-native-safe-area-context";
     9→import { useAppTheme } from "../hooks/use-app-theme";
    10→import { StoreProvider, useStore } from "../src/store";
    11→
    12→/** Check if device supports Liquid Glass (iOS 26+) */
    13→const isLiquidGlass = Platform.OS === "ios" && (parseInt(String(Platform.Version), 10) || 0) >= 26;
    14→
    15→// スプラッシュを自動で隠さず、アプリ準備完了時に手動で隠す
    16→SplashScreen.preventAutoHideAsync();
    17→
    18→
    19→// モーダル画面のヘッダー・背景を一元管理（theme.modalBackground でメイン画面と区別）
    20→// iOS 26+ uses formSheet for native Liquid Glass effect with swipe gestures
    21→export const getModalHeaderOptions = (theme: any, title: string) => ({
    22→  // formSheet supports native Liquid Glass on iOS 26+ with swipe gestures
    23→  // For non-Liquid Glass, use fullScreenModal to avoid system theme background
    24→  presentation: isLiquidGlass ? "formSheet" as const : "fullScreenModal" as const,
    25→  headerShown: true,
    26→  title,
    27→  headerStyle: {
    28→    backgroundColor: isLiquidGlass ? "transparent" : theme.modalBackground,
    29→  },
    30→  headerTintColor: theme.text,
    31→  headerTitleStyle: {
    32→    fontSize: 20,
    33→    fontWeight: "700" as const,
    34→    color: theme.text,
    35→  },
    36→  // iOS 26+ Liquid Glass settings
    37→  headerBlurEffect: isLiquidGlass ? "systemUltraThinMaterial" as const : undefined,
    38→  headerTransparent: isLiquidGlass,
    39→  // Background color controlled by app theme
    40→  contentStyle: { backgroundColor: isLiquidGlass ? "transparent" : theme.modalBackground },
    41→  // Sheet options for formSheet presentation (iOS 26+)
    42→  ...(isLiquidGlass ? {
    43→    sheetAllowedDetents: [1.0] as number[],
    44→    sheetGrabberVisible: true,
    45→    sheetCornerRadius: 20,
    46→  } : {}),
    47→  // Enable swipe to dismiss
    48→  gestureEnabled: true,
    49→  fullScreenGestureEnabled: true,
    50→});
    51→
    52→// ページ画面のヘッダー（通常のpush遷移）
    53→export const getPageHeaderOptions = (theme: any, title: string) => ({
    54→  headerShown: true,
    55→  title,
    56→  headerStyle: {
    57→    backgroundColor: theme.background,
    58→  },
    59→  headerTintColor: theme.text,
    60→  headerTitleStyle: {
    61→    fontSize: 20,
    62→    fontWeight: "700" as const,
    63→    color: theme.text,
    64→  },
    65→  headerBlurEffect: isLiquidGlass ? "systemMaterial" as const : undefined,
    66→  contentStyle: { backgroundColor: theme.background },
    67→});
    68→
    69→function Boot() {
    70→  const { loaded } = useStore();
    71→  const theme = useAppTheme();
    72→
    73→  useEffect(() => {
    74→    if (loaded) {
    75→      SplashScreen.hideAsync();
    76→      return;
    77→    }
    78→    const fallback = setTimeout(() => SplashScreen.hideAsync(), 5000);
    79→    return () => clearTimeout(fallback);
    80→  }, [loaded]);
    81→
    82→  // Memoize modal options so they update when theme changes
    83→  const setupOptions = React.useMemo(() => getModalHeaderOptions(theme, "Setup"), [theme]);
    84→  const createSheetOptions = React.useMemo(() => getModalHeaderOptions(theme, "Create New Sheet"), [theme]);
    85→  const sheetsOptions = React.useMemo(() => getModalHeaderOptions(theme, "Sheets"), [theme]);
    86→  const expenseEntryOptions = React.useMemo(() => getModalHeaderOptions(theme, ""), [theme]);
    87→  const settingsOptions = React.useMemo(() => getModalHeaderOptions(theme, "Settings"), [theme]);
    88→
    89→  return (
    90→    <View style={{ flex: 1 }}>
    91→      <Stack screenOptions={{ headerShown: false }}>
    92→        <Stack.Screen name="(tabs)" />
    93→        <Stack.Screen name="setup" options={setupOptions} />
    94→        <Stack.Screen name="create-sheet" options={createSheetOptions} />
    95→        <Stack.Screen name="sheets" options={sheetsOptions} />
    96→        <Stack.Screen name="expense-entry" options={expenseEntryOptions} />
    97→        <Stack.Screen name="settings" options={settingsOptions} />
    98→      </Stack>
    99→      <SyncIndicator />
   100→    </View>
   101→  );
   102→}
   103→
   104→export default function RootLayout() {
   105→  return (
   106→    <GestureHandlerRootView style={{ flex: 1 }}>
   107→      <ErrorBoundary>
   108→        <SafeAreaProvider initialMetrics={initialWindowMetrics ?? undefined}>
   109→          <StoreProvider>
   110→            <Boot />
   111→          </StoreProvider>
   112→        </SafeAreaProvider>
   113→      </ErrorBoundary>
   114→    </GestureHandlerRootView>
   115→  );
   116→}
