import { ErrorBoundary } from "@/components/error-boundary";
import { SyncIndicator } from "@/components/sync-indicator";
import { Stack } from "expo-router";
import * as SplashScreen from "expo-splash-screen";
import React, { useEffect } from "react";
import { Platform, View } from "react-native";
import { GestureHandlerRootView } from "react-native-gesture-handler";
import { SafeAreaProvider, initialWindowMetrics } from "react-native-safe-area-context";
import { useAppTheme } from "../hooks/use-app-theme";
import { StoreProvider, useStore } from "../src/store";

/** Check if device supports Liquid Glass (iOS 26+) */
const isLiquidGlass = Platform.OS === "ios" && (parseInt(String(Platform.Version), 10) || 0) >= 26;

// スプラッシュを自動で隠さず、アプリ準備完了時に手動で隠す
SplashScreen.preventAutoHideAsync();


// モーダル画面のヘッダー・背景を一元管理（theme.modalBackground でメイン画面と区別）
// iOS 26+ uses formSheet for native Liquid Glass effect with swipe gestures
export const getModalHeaderOptions = (theme: any, title: string) => ({
  // formSheet supports native Liquid Glass on iOS 26+ with swipe gestures
  // For non-Liquid Glass, use fullScreenModal to avoid system theme background
  presentation: isLiquidGlass ? "formSheet" as const : "fullScreenModal" as const,
  headerShown: true,
  title,
  headerStyle: {
    backgroundColor: isLiquidGlass ? "transparent" : theme.modalBackground,
  },
  headerTintColor: theme.text,
  headerTitleStyle: {
    fontSize: 20,
    fontWeight: "700" as const,
    color: theme.text,
  },
  // iOS 26+ Liquid Glass settings
  headerBlurEffect: isLiquidGlass ? "systemUltraThinMaterial" as const : undefined,
  headerTransparent: isLiquidGlass,
  // Background color controlled by app theme
  contentStyle: { backgroundColor: isLiquidGlass ? "transparent" : theme.modalBackground },
  // Sheet options for formSheet presentation (iOS 26+)
  ...(isLiquidGlass ? {
    sheetAllowedDetents: [1.0] as number[],
    sheetGrabberVisible: true,
    sheetCornerRadius: 20,
  } : {}),
  // Enable swipe to dismiss
  gestureEnabled: true,
  fullScreenGestureEnabled: true,
});

// ページ画面のヘッダー（通常のpush遷移）
export const getPageHeaderOptions = (theme: any, title: string) => ({
  headerShown: true,
  title,
  headerStyle: {
    backgroundColor: theme.background,
  },
  headerTintColor: theme.text,
  headerTitleStyle: {
    fontSize: 20,
    fontWeight: "700" as const,
    color: theme.text,
  },
  headerBlurEffect: isLiquidGlass ? "systemMaterial" as const : undefined,
  contentStyle: { backgroundColor: theme.background },
});

function Boot() {
  const { loaded } = useStore();
  const theme = useAppTheme();

  useEffect(() => {
    if (loaded) {
      SplashScreen.hideAsync();
      return;
    }
    const fallback = setTimeout(() => SplashScreen.hideAsync(), 5000);
    return () => clearTimeout(fallback);
  }, [loaded]);

  // Memoize modal options so they update when theme changes
  const setupOptions = React.useMemo(() => getModalHeaderOptions(theme, "Setup"), [theme]);
  const createSheetOptions = React.useMemo(() => getModalHeaderOptions(theme, "Create New Sheet"), [theme]);
  const sheetsOptions = React.useMemo(() => getModalHeaderOptions(theme, "Sheets"), [theme]);
  const expenseEntryOptions = React.useMemo(() => getModalHeaderOptions(theme, ""), [theme]);
  const settingsOptions = React.useMemo(() => getModalHeaderOptions(theme, "Settings"), [theme]);

  return (
    <View style={{ flex: 1 }}>
      <Stack screenOptions={{ headerShown: false }}>
        <Stack.Screen name="(tabs)" />
        <Stack.Screen name="setup" options={setupOptions} />
        <Stack.Screen name="create-sheet" options={createSheetOptions} />
        <Stack.Screen name="sheets" options={sheetsOptions} />
        <Stack.Screen name="expense-entry" options={expenseEntryOptions} />
        <Stack.Screen name="settings" options={settingsOptions} />
      </Stack>
      <SyncIndicator />
    </View>
  );
}

export default function RootLayout() {
  return (
    <GestureHandlerRootView style={{ flex: 1 }}>
      <ErrorBoundary>
        <SafeAreaProvider initialMetrics={initialWindowMetrics ?? undefined}>
          <StoreProvider>
            <Boot />
          </StoreProvider>
        </SafeAreaProvider>
      </ErrorBoundary>
    </GestureHandlerRootView>
  );
}

