import { BudgetCard } from "@/components/budget-card";
import { LiquidHeaderOverlay } from "@/components/liquid-header-overlay";
import { FLOATING_TAB_BAR_INSET_BASE } from "@/components/tab-bar-with-fab";
import { IconSymbol } from "@/components/ui/icon-symbol";
import { useAppTheme } from "@/hooks/use-app-theme";
import { useLanguage } from "@/hooks/use-language";
import { useSheetStats } from "@/hooks/use-sheet-stats";
import { useStore } from "@/src/store";
import { formatMoney, itemAmountToBaseForSum, toISODate } from "@/src/utils";
import { useFocusEffect, useRouter } from "expo-router";
import React, { useCallback, useMemo, useState } from "react";
import { Alert, Pressable, RefreshControl, ScrollView, StyleSheet, Text, View } from "react-native";
import { useSafeAreaInsets } from "react-native-safe-area-context";

export default function HomeScreen() {
  const router = useRouter();
  const insets = useSafeAreaInsets();
  const { state, setState, activeSheet, rateCache, fillRateCacheForActiveSheet, syncFromCloud } =
    useStore();
  const [refreshing, setRefreshing] = useState(false);
  const { t } = useLanguage();

  useFocusEffect(
    useCallback(() => {
      if (activeSheet) fillRateCacheForActiveSheet();
      // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [activeSheet?.id, fillRateCacheForActiveSheet])
  );
  const theme = useAppTheme();

  // Use extracted stats hook
  const stats = useSheetStats({
    activeSheet,
    baseCurrency: state.baseCurrency,
    rateCache,
  });

  const formatMoneyFn = useCallback(
    (amount: number) => formatMoney(amount, state.baseCurrency),
    [state.baseCurrency]
  );

  const handleOpenSheets = () => {
    router.push("/sheets");
  };

  // Check for expired sheet on focus (show only once per sheet)
  useFocusEffect(
    useCallback(() => {
      if (!activeSheet) return;

      const todayISO = toISODate(new Date());
      const isExpired = activeSheet.periodEndISO < todayISO;
      const alreadyShown = state.expiredSheetPromptShownForSheetId === activeSheet.id;

      if (isExpired && !alreadyShown) {
        // Mark as shown immediately to prevent re-showing on subsequent focus
        setState((prev) => ({
          ...prev,
          expiredSheetPromptShownForSheetId: activeSheet.id,
        }));

        Alert.alert(
          t("sheetPeriodExpired"),
          t("sheetPeriodExpiredMsg", { start: activeSheet.periodStartISO, end: activeSheet.periodEndISO }),
          [
            { text: t("cancel"), style: "cancel" },
            { text: t("createNewSheet"), onPress: () => router.push("/create-sheet") },
          ]
        );
      }
    }, [activeSheet, state.expiredSheetPromptShownForSheetId, setState, router])
  );

  const base = state.baseCurrency;
  const periodStart = activeSheet?.periodStartISO ?? "";

  const incomeTotal = useMemo(() => {
    if (!activeSheet) return 0;
    const opts = { rateCache, dateISO: periodStart };
    return (activeSheet.incomeItems ?? []).reduce(
      (a, b) => a + itemAmountToBaseForSum(b.amount, base, b, opts),
      0
    );
  }, [activeSheet, base, rateCache, periodStart]);

  const needsSetup =
    state.members.length === 0 ||
    !activeSheet ||
    incomeTotal === 0 ||
    (activeSheet.categories?.length ?? 0) === 0;

  if (needsSetup) {
    return (
      <View style={[styles.setupContainer, { backgroundColor: theme.background }]}>
        {/* Header - absolute positioned to not affect centering */}
        <View style={[styles.setupHeader, { top: insets.top, paddingHorizontal: 18 }]}>
          <View style={styles.headerRow}>
            <View style={styles.menuButton} />
            <Pressable
              onPress={() => router.push("/settings")}
              style={({ pressed }) => [
                styles.menuButton,
                styles.menuButtonRight,
                { backgroundColor: theme.surface, opacity: pressed ? 0.7 : 1 },
              ]}
            >
              <IconSymbol name="gearshape.fill" size={24} color={theme.text} />
            </Pressable>
          </View>
        </View>
        {/* Center content - centered in full screen */}
        <View style={styles.setupContent}>
          <Text style={[styles.title, { color: theme.text }]}>NOKORI</Text>
          <Text style={[styles.sub, { color: theme.subText }]}>Setup is required before you start.</Text>
          <View style={styles.setupButtons}>
            <Pressable
              onPress={() => router.push("/create-sheet")}
              style={({ pressed }) => [
                styles.btn,
                { backgroundColor: theme.buttonDark, opacity: pressed ? 0.7 : 1 },
              ]}
            >
              <Text style={styles.btnText}>Open Setup</Text>
            </Pressable>
            <Pressable
              onPress={() => router.push("/settings?openCloudSync=1")}
              style={({ pressed }) => [
                styles.btn,
                styles.btnSecondary,
                { backgroundColor: theme.surface, borderColor: theme.border, opacity: pressed ? 0.7 : 1 },
              ]}
            >
              <Text style={[styles.btnTextSecondary, { color: theme.text }]}>Import Existing Data</Text>
            </Pressable>
          </View>
          <Text style={[styles.setupHint, { color: theme.subText }]}>
            Import: Select a folder that contains your data (e.g. iCloud, Google Drive, Dropbox, or
            device storage).
          </Text>
        </View>
      </View>
    );
  }

  if (!activeSheet || !stats) return null;

  return (
    <View style={{ flex: 1, backgroundColor: theme.background }}>
      <ScrollView
        style={styles.scrollView}
        contentInsetAdjustmentBehavior="automatic"
        contentContainerStyle={{ paddingBottom: FLOATING_TAB_BAR_INSET_BASE + insets.bottom }}
        refreshControl={
          state.cloudSyncFileUri ? (
            <RefreshControl
              refreshing={refreshing}
              onRefresh={async () => {
                setRefreshing(true);
                try {
                  await syncFromCloud();
                } finally {
                  setRefreshing(false);
                }
              }}
            />
          ) : undefined
        }
      >
        <View style={{ gap: 12, paddingHorizontal: 18 }}>
          {/* Header */}
          <View style={styles.headerRow}>
            <Pressable
              onPress={handleOpenSheets}
              style={({ pressed }) => [
                styles.menuButton,
                { backgroundColor: theme.surface, opacity: pressed ? 0.7 : 1 },
              ]}
            >
              <IconSymbol name="line.3.horizontal" size={24} color={theme.text} />
            </Pressable>
            <View style={[styles.period, { backgroundColor: theme.surface }]}>
              <Text style={[styles.periodText, { color: theme.text }]}>{stats.periodLabel}</Text>
            </View>
            <Pressable
              onPress={() => router.push("/settings")}
              style={({ pressed }) => [
                styles.menuButton,
                styles.menuButtonRight,
                { backgroundColor: theme.surface, opacity: pressed ? 0.7 : 1 },
              ]}
            >
              <IconSymbol name="gearshape.fill" size={24} color={theme.text} />
            </Pressable>
          </View>

          <Pressable
            onPress={() => router.push("/setup")}
            style={({ pressed }) => [
              styles.editSetupBtn,
              { backgroundColor: theme.buttonDark, opacity: pressed ? 0.7 : 1 },
            ]}
          >
            <Text style={styles.editSetupBtnText}>Edit Setup</Text>
          </Pressable>

          {/* Available Today Card */}
          <View style={[styles.card, { backgroundColor: theme.surface }]}>
            <View style={styles.cardHeader}>
              <Text style={[styles.labelCard, { color: theme.subText }]}>Available today</Text>
              <Text style={[styles.cardDate, { color: theme.subText }]}>
                {stats.effectiveTodayLabel}
              </Text>
            </View>
            <Text
              style={[
                styles.big,
                { color: stats.todaySaldo < 0 ? theme.expenseText : theme.text },
              ]}
            >
              {formatMoney(stats.todaySaldo, state.baseCurrency)}
            </Text>
            <Text style={[styles.smallCard, { color: theme.subText }]}>
              Today&apos;s expense: {formatMoney(stats.todayTotalExpense, state.baseCurrency)}
            </Text>
          </View>

          {/* Budget Grid */}
          <View style={styles.grid}>
            <View style={[styles.tile, { backgroundColor: theme.surface }]}>
              <Text style={[styles.label, { color: theme.subText }]}>Budget / Month</Text>
              <Text style={[styles.value, { color: theme.text }]}>
                {formatMoney(stats.discretionary, state.baseCurrency)}
              </Text>
            </View>
            <View style={[styles.tile, { backgroundColor: theme.surface }]}>
              <Text style={[styles.label, { color: theme.subText }]}>Budget / Day</Text>
              <Text style={[styles.value, { color: theme.text }]}>
                {formatMoney(stats.monthBudgetPerDay, state.baseCurrency)}
              </Text>
            </View>
          </View>

          {/* Total Spent */}
          <BudgetCard
            theme={theme}
            label="Total Spent"
            subLabel="Needs + Savings + Wants"
            spent={stats.totalExpense}
            available={stats.income}
            formatMoney={formatMoneyFn}
            amountsLabel="Total / Income:"
            percentLabel="Of income:"
          />

          {/* Wants */}
          <BudgetCard
            theme={theme}
            label="Wants"
            budgetPercent={activeSheet.balanceRule.wantsPct}
            spent={stats.wantsSpent}
            available={stats.wantsTarget}
            formatMoney={formatMoneyFn}
          />

          {/* Wants by Category */}
          <View style={[styles.cardSoft, { backgroundColor: theme.surface }]}>
            <Text style={[styles.label, { color: theme.subText }]}>Wants by Category</Text>
            <Text style={[styles.hintLabel, { color: theme.subText }]}>
              Each % = share of Wants budget
            </Text>
            {stats.categoryBudgets.map((cat) => (
              <View key={cat.id} style={[styles.categoryRow, { borderColor: theme.border }]}>
                <View style={styles.categoryInfo}>
                  <Text style={[styles.categoryName, { color: theme.text }]}>{cat.name}</Text>
                  <Text style={[styles.categoryRatio, { color: theme.subText }]}>
                    {(cat.ratio * 100).toFixed(0)}% of Wants
                  </Text>
                </View>
                <View style={styles.categoryAmounts}>
                  <View style={styles.categorySpentRow}>
                    <Text style={[styles.categorySpentLabel, { color: theme.subText }]}>
                      Remaining:
                    </Text>
                    <Text
                      style={[
                        styles.categorySpentAmount,
                        {
                          color: cat.remaining < 0 ? theme.expenseText : theme.incomeText,
                          fontWeight: "600",
                        },
                      ]}
                    >
                      {formatMoney(cat.remaining, state.baseCurrency)}
                    </Text>
                  </View>
                  <View style={styles.categorySpentRow}>
                    <Text style={[styles.categorySpentLabel, { color: theme.subText }]}>Spent:</Text>
                    <Text style={[styles.categorySpentAmount, { color: theme.text }]}>
                      {formatMoney(cat.spent, state.baseCurrency)}
                    </Text>
                  </View>
                  <View style={[styles.progressBar, { backgroundColor: theme.progressTrack }]}>
                    <View
                      style={[
                        styles.progressFill,
                        {
                          width: `${Math.min(100, cat.percentage)}%`,
                          backgroundColor:
                            cat.percentage > 100
                              ? theme.expenseText
                              : cat.percentage > 80
                                ? theme.warningText
                                : theme.incomeText,
                        },
                      ]}
                    />
                  </View>
                </View>
              </View>
            ))}
          </View>

          {/* Fixed Expenses */}
          <BudgetCard
            theme={theme}
            label="Fixed Expenses (Needs)"
            budgetPercent={activeSheet.balanceRule.needsPct}
            spent={stats.fixedSum}
            available={stats.needsTarget}
            formatMoney={formatMoneyFn}
            onPress={() => {
              setDetailPanel("fixed");
              setSelectedItem(null);
            }}
          />

          {/* Savings */}
          <BudgetCard
            theme={theme}
            label="Savings"
            budgetPercent={activeSheet.balanceRule.savingsPct}
            spent={stats.savingsSum}
            available={stats.savingsTarget}
            formatMoney={formatMoneyFn}
            onPress={() => {
              setDetailPanel("savings");
              setSelectedItem(null);
            }}
          />
        </View>
      </ScrollView>

      <DetailPanelModal
        detailPanel={detailPanel}
        selectedItem={selectedItem}
        setSelectedItem={setSelectedItem}
        onClose={() => {
          setDetailPanel(null);
          setSelectedItem(null);
        }}
        onEdit={handleDetailEdit}
        onDelete={handleDetailDelete}
        activeSheet={activeSheet}
        baseCurrency={state.baseCurrency}
        rateCache={rateCache}
      />
      <LiquidHeaderOverlay />
    </View>
  );
}

