/**
 * Detail panel screen for viewing fixed expenses and savings details.
 * Uses expo-router for native Liquid Glass effect on iOS 26+.
 */
import React, { useState } from "react";
import { Alert, Pressable, ScrollView, StyleSheet, Text, View } from "react-native";
import { useLocalSearchParams, useRouter } from "expo-router";
import { useSafeAreaInsets } from "react-native-safe-area-context";
import { GlassModalContainer } from "@/components/glass-modal-container";
import { useLanguage } from "@/hooks/use-language";
import { useModalTheme } from "@/hooks/use-modal-theme";
import { useStore } from "@/src/store";
import { FixedExpenseItem, SavingItem } from "@/src/types";
import { formatMoneyInBase } from "@/src/utils";

type SelectedItem = { type: "fixed" | "savings"; id: string } | null;

export default function DetailPanelScreen() {
  const router = useRouter();
  const params = useLocalSearchParams<{ type: "fixed" | "savings" }>();
  const panelType = params.type ?? "fixed";
  const { t } = useLanguage();
  const theme = useModalTheme();
  const insets = useSafeAreaInsets();
  const { state, setState, activeSheet, rateCache } = useStore();

  const [selectedItem, setSelectedItem] = useState<SelectedItem>(null);

  const base = state.baseCurrency;
  const periodStart = activeSheet?.periodStartISO ?? "";
  const opts = { rateCache, dateISO: periodStart };

  const handleDelete = (item: FixedExpenseItem | SavingItem, type: "fixed" | "savings") => {
    Alert.alert(t("delete"), t("deleteItemConfirm", { name: item.name }), [
      { text: t("cancel"), style: "cancel" },
      {
        text: t("delete"),
        style: "destructive",
        onPress: () => {
          setState((prev) => ({
            ...prev,
            sheets: prev.sheets.map((sh) =>
              sh.id === activeSheet?.id
                ? {
                    ...sh,
                    ...(type === "fixed"
                      ? { fixedExpenses: (sh.fixedExpenses ?? []).filter((f) => f.id !== item.id) }
                      : { savingsItems: (sh.savingsItems ?? []).filter((s) => s.id !== item.id) }),
                  }
                : sh
            ),
          }));
          setSelectedItem(null);
        },
      },
    ]);
  };

  const handleEdit = () => {
    router.dismiss();
    router.push("/setup");
  };

  const handleBack = () => {
    if (selectedItem) {
      setSelectedItem(null);
    } else {
      router.back();
    }
  };

  return (
    <GlassModalContainer>
      <ScrollView
        style={styles.scroll}
        contentInsetAdjustmentBehavior="automatic"
        contentContainerStyle={[styles.scrollContent, { paddingBottom: 80 + insets.bottom }]}
      >
        {/* List view */}
        {!selectedItem && panelType === "fixed" && (
          <>
            {(activeSheet?.fixedExpenses ?? []).length === 0 ? (
              <Text style={[styles.empty, { color: theme.subText }]}>{t("noFixedExpenses")}</Text>
            ) : (
              (activeSheet?.fixedExpenses ?? []).map((it: FixedExpenseItem) => (
                <Pressable
                  key={it.id}
                  style={[styles.row, { backgroundColor: theme.surface }]}
                  onPress={() => setSelectedItem({ type: "fixed", id: it.id })}
                >
                  <Text style={[styles.rowName, { color: theme.text }]}>{it.name}</Text>
                  <Text style={[styles.rowAmount, { color: theme.text }]}>
                    {formatMoneyInBase(it.amount, base, it, opts)}
                  </Text>
                </Pressable>
              ))
            )}
          </>
        )}
        {!selectedItem && panelType === "savings" && (
          <>
            {(activeSheet?.savingsItems ?? []).length === 0 ? (
              <Text style={[styles.empty, { color: theme.subText }]}>{t("noSavingsItems")}</Text>
            ) : (
              (activeSheet?.savingsItems ?? []).map((it: SavingItem) => (
                <Pressable
                  key={it.id}
                  style={[styles.row, { backgroundColor: theme.surface }]}
                  onPress={() => setSelectedItem({ type: "savings", id: it.id })}
                >
                  <Text style={[styles.rowName, { color: theme.text }]}>{it.name}</Text>
                  <Text style={[styles.rowAmount, { color: theme.text }]}>
                    {formatMoneyInBase(it.amount, base, it, opts)}
                  </Text>
                </Pressable>
              ))
            )}
          </>
        )}

        {/* Detail view */}
        {selectedItem &&
          (() => {
            const item =
              selectedItem.type === "fixed"
                ? (activeSheet?.fixedExpenses ?? []).find(
                    (f: FixedExpenseItem) => f.id === selectedItem.id
                  )
                : (activeSheet?.savingsItems ?? []).find(
                    (s: SavingItem) => s.id === selectedItem.id
                  );
            if (!item)
              return (
                <Text style={[styles.empty, { color: theme.subText }]}>{t("itemNotFound")}</Text>
              );
            return (
              <View style={[styles.card, { backgroundColor: theme.surface }]}>
                <View style={[styles.cardRow, { borderBottomColor: theme.border }]}>
                  <Text style={[styles.cardLabel, { color: theme.subText }]}>{t("name")}</Text>
                  <Text style={[styles.cardValue, { color: theme.text }]}>{item.name}</Text>
                </View>
                <View style={[styles.cardRow, { borderBottomColor: theme.border }]}>
                  <Text style={[styles.cardLabel, { color: theme.subText }]}>{t("amount")}</Text>
                  <Text style={[styles.cardValue, { color: theme.text }]}>
                    {formatMoneyInBase(item.amount, base, item, opts)}
                  </Text>
                </View>
                {item.inputCurrency && item.inputCurrency !== state.baseCurrency && (
                  <View style={[styles.cardRow, { borderBottomWidth: 0 }]}>
                    <Text style={[styles.cardLabel, { color: theme.subText }]}>{t("currency")}</Text>
                    <Text style={[styles.cardValue, { color: theme.text }]}>
                      {item.inputCurrency}
                    </Text>
                  </View>
                )}
              </View>
            );
          })()}
      </ScrollView>

      {/* Floating bottom buttons */}
      <View style={[styles.floatingContainer, { paddingBottom: insets.bottom + 16 }]}>
        <Pressable
          onPress={handleEdit}
          style={[styles.floatingBtn, { backgroundColor: theme.buttonDark }]}
        >
          <Text style={styles.floatingBtnText}>{t("editInSetup")}</Text>
        </Pressable>
        {selectedItem &&
          (() => {
            const item =
              selectedItem.type === "fixed"
                ? (activeSheet?.fixedExpenses ?? []).find(
                    (f: FixedExpenseItem) => f.id === selectedItem.id
                  )
                : (activeSheet?.savingsItems ?? []).find(
                    (s: SavingItem) => s.id === selectedItem.id
                  );
            if (!item) return null;
            return (
              <Pressable
                onPress={() => handleDelete(item, selectedItem.type)}
                style={[
                  styles.floatingBtn,
                  {
                    backgroundColor: theme.modalBackground,
                    borderWidth: 1,
                    borderColor: theme.buttonDanger,
                  },
                ]}
              >
                <Text style={[styles.floatingBtnText, { color: theme.buttonDanger }]}>
                  {t("delete")}
                </Text>
              </Pressable>
            );
          })()}
      </View>
    </GlassModalContainer>
  );
}

const styles = StyleSheet.create({
  scroll: { flex: 1 },
  scrollContent: { paddingHorizontal: 20, paddingTop: 24, gap: 12, flexGrow: 1 },
  empty: { fontSize: 14, paddingVertical: 24, textAlign: "center" },
  row: {
    flexDirection: "row",
    justifyContent: "space-between",
    alignItems: "center",
    padding: 14,
    borderRadius: 12,
    marginBottom: 4,
  },
  rowName: { fontSize: 15, fontWeight: "600", flex: 1 },
  rowAmount: { fontSize: 15, fontWeight: "700" },
  card: { padding: 16, borderRadius: 16, gap: 0 },
  cardRow: {
    flexDirection: "row",
    justifyContent: "space-between",
    alignItems: "center",
    paddingVertical: 12,
    borderBottomWidth: StyleSheet.hairlineWidth,
  },
  cardLabel: { fontSize: 13 },
  cardValue: { fontSize: 15, fontWeight: "600" },
  floatingContainer: {
    position: "absolute",
    bottom: 0,
    left: 0,
    right: 0,
    paddingHorizontal: 20,
    paddingTop: 16,
    gap: 10,
  },
  floatingBtn: {
    paddingVertical: 14,
    borderRadius: 12,
    alignItems: "center",
  },
  floatingBtnText: { color: "#fff", fontWeight: "700", fontSize: 16 },
});
